C.zq=new H.aA(3,{id:1,title:"\u041f\u043e\u0447\u0435\u043c\u0443 \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0431\u0440\u0430\u0442\u044c \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0435 \u043f\u0430\u043a\u0435\u0442\u044b?",text:'\u041c\u043d\u043e\u0433\u0438\u043c \u0438\u0437 \u043d\u0430\u0441 \u0437\u043d\u0430\u043a\u043e\u043c\u0430 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u043a\u0443\u043f\u0438\u0442\u044c \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0435 \u0445\u043b\u0435\u0431 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u043e\u0439\u0442\u0438 \u0434\u043e\u043c\u043e\u0439, \u0430 \u0432 \u0438\u0442\u043e\u0433\u0435 \u0432 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432\u043e\u0439 \u043a\u043e\u0440\u0437\u0438\u043d\u0435 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0435\u0449\u0435 \u0438 \u043c\u043e\u043b\u043e\u043a\u043e, \u043f\u0430\u0440\u0430 \u0442\u043e\u0432\u0430\u0440\u043e\u0432 \u043f\u043e \u0441\u043a\u0438\u0434\u043a\u0435 \u0438 \u044d\u0442\u043e \u043d\u0435 \u043f\u0440\u0435\u0434\u0435\u043b. \u041d\u0435\u0432\u043e\u043b\u044c\u043d\u043e \u0437\u0430\u0433\u043e\u043d\u044f\u0435\u0448\u044c \u0441\u0435\u0431\u044f \u0432 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u044e, \u043a\u043e\u0433\u0434\u0430 \u043d\u0430 \u043a\u0430\u0441\u0441\u0435 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u0440\u043e\u0441\u0438\u0442\u044c \u0448\u0443\u0440\u0448\u0430\u0449\u0438\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0439 \u043f\u0430\u043a\u0435\u0442. \u0418 \u044d\u0442\u043e \u0443\u0436\u0435 \u043d\u0435 \u0433\u043e\u0432\u043e\u0440\u044f \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u0432\u0441\u0435 \u0442\u043e\u0432\u0430\u0440\u044b \u0435\u0449\u0451 \u0434\u043e \u044d\u0442\u043e\u0433\u043e \u043e\u0431\u0435\u0440\u043d\u0443\u0442\u044b \u0432 \u043f\u043b\u0435\u043d\u043a\u0443 \u0438 \u043f\u0430\u043a\u0435\u0442\u044b \u043f\u043e\u043c\u0435\u043d\u044c\u0448\u0435.\n\n\u0418 \u043c\u0430\u043b\u043e \u043a\u0442\u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0437\u0430\u0434\u0443\u043c\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u043e \u0442\u043e\u043c, \u043a\u0443\u0434\u0430 \u043f\u043e\u0442\u043e\u043c \u0434\u0435\u043d\u0435\u0442\u0441\u044f \u044d\u0442\u043e\u0442 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d. \u041e\u043a\u0435\u0430\u043d \u0438 \u043d\u0435\u0441\u0447\u0430\u0441\u0442\u043d\u044b\u0435 \u0447\u0435\u0440\u0435\u043f\u0430\u0445\u0438, \u0441\u044a\u0435\u0434\u0430\u044e\u0449\u0438\u0435 \u043c\u0443\u0441\u043e\u0440 \u0432\u043c\u0435\u0441\u0442\u043e \u043c\u0435\u0434\u0443\u0437, \u043e\u043d\u0438 \u0432\u0441\u0435 \u043e\u0447\u0435\u043d\u044c \u0434\u0430\u043b\u0435\u043a\u043e, \u0434\u0430?\n\n\u041c\u043e\u0436\u0435\u0442 \u0431\u044b\u0442\u044c, \u043d\u043e \u0442\u043e\u0433\u0434\u0430 \u0447\u0442\u043e \u043d\u0430 \u0441\u0447\u0451\u0442 \u0447\u0435\u0433\u043e-\u0442\u043e \u0431\u043e\u043b\u0435\u0435 \u0431\u043b\u0438\u0437\u043a\u043e\u0433\u043e? \u0427\u0442\u043e \u043d\u0430 \u0441\u0447\u0451\u0442 \u0441\u0435\u0431\u044f \u0441\u0430\u043c\u043e\u0433\u043e? \u041f\u0440\u0438\u0432\u044b\u0447\u043d\u044b\u0435 \u043d\u0430\u043c \u043f\u0430\u043a\u0435\u0442\u044b \u0438\u0437 \u043f\u0440\u043e\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0430 \u0434\u0435\u043b\u0430\u044e\u0442 \u0438\u0437 \u0441\u044b\u0440\u043e\u0439 \u043d\u0435\u0444\u0442\u0438, \u0438 \u043a\u043e\u0433\u0434\u0430 \u043e\u043d \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0442\u044c\u0441\u044f \u0441\u0432\u043e\u0438 \u0434\u043e\u043b\u0433\u0438\u0435 \u0441\u043e\u0442\u043d\u0438 \u043b\u0435\u0442, \u043f\u043b\u043e\u0445\u043e \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0432\u0441\u0435\u043c. \u041f\u043e\u0440\u0442\u0438\u0442\u0441\u044f \u043f\u043e\u0447\u0432\u0430, \u0433\u0434\u0435 \u0435\u0449\u0451 \u043a\u043e\u0433\u0434\u0430-\u0442\u043e \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u043b\u043e \u0432\u044b\u0440\u0430\u0441\u0442\u0438\u0442\u044c \u0445\u043e\u0440\u043e\u0448\u0438\u0439 \u0443\u0440\u043e\u0436\u0430\u0439, \u0430 \u0435\u0441\u043b\u0438 \u0447\u0442\u043e-\u0442\u043e \u0432 \u0438\u0442\u043e\u0433\u0435 \u0438 \u0432\u0437\u043e\u0439\u0434\u0451\u0442, \u0442\u043e \u0443\u0436\u0435 \u043d\u0435 \u043e\u0441\u0442\u0430\u043d\u0435\u0442\u0441\u044f \u0431\u044b\u043b\u043e\u0439 \u043f\u043e\u043b\u044c\u0437\u044b \u0438 \u0432\u043a\u0443\u0441\u0430. \u0421\u0442\u043e\u043b\u044c \u0436\u0435 \u0433\u0443\u0431\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0431\u0435\u0437\u0434\u0443\u043c\u043d\u043e \u0432\u044b\u0431\u0440\u043e\u0448\u0435\u043d\u043d\u044b\u0439 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d \u0432\u043b\u0438\u044f\u0435\u0442 \u043d\u0430 \u0432\u043e\u0437\u0434\u0443\u0445. \u041d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0432 \u0441\u0432\u043e\u0439 \u043f\u0440\u043e\u0434\u0443\u043a\u0442 \u0447\u0430\u0441\u0442\u0438\u0446\u044b \u0441\u0432\u0438\u043d\u0446\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u0440\u0438 \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u0438 \u0432\u044b\u0434\u0435\u043b\u044f\u044e\u0449\u0438\u0445 \u043e\u0442\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0435 \u0442\u043e\u043a\u0441\u0438\u043d\u044b.\n\n\u041f\u0435\u0440\u0435\u0447\u0438\u0441\u043b\u044f\u0442\u044c \u0432\u0440\u0435\u0434 \u043c\u043e\u0436\u043d\u043e \u0431\u0435\u0441\u043a\u043e\u043d\u0435\u0447\u043d\u043e, \u043d\u043e \u0432\u044b\u0434\u0435\u043b\u0438\u0442\u044c \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u043d\u0443\u0436\u043d\u043e \u0441\u0430\u043c\u043e\u0435 \u0432\u0430\u0436\u043d\u043e\u0435: \u0432\u0441\u0451 \u044d\u0442\u043e \u0441\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u043d\u0435 \u043d\u0430 \u043a\u043e\u043c-\u0442\u043e \u0434\u0440\u0443\u0433\u043e\u043c, \u0430 \u043d\u0430 \u0441\u0435\u0431\u0435 \u043b\u044e\u0431\u0438\u043c\u043e\u043c. \u041a\u0430\u0436\u0434\u044b\u0439 \u043d\u043e\u0432\u044b\u0439 \u043a\u0443\u043f\u043b\u0435\u043d\u043d\u044b\u0439 \u043f\u0430\u043a\u0435\u0442 \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0442\u044c\u0441\u044f \u043e\u0442 \u0441\u043e\u0442\u043d\u0438 \u0434\u043e \u0442\u044b\u0441\u044f\u0447\u0438 \u043b\u0435\u0442, \u0432\u044b\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u044f \u0432 \u0430\u0442\u043c\u043e\u0441\u0444\u0435\u0440\u0443 \u0442\u043e\u043a\u0441\u0438\u043d\u044b. \u0418 \u043e\u043d \u043d\u0435 \u043e\u0434\u0438\u043d, \u0438\u0445 \u0441\u043e\u0442\u043d\u0438. \u041b\u044e\u0434\u0438 \u043a\u0430\u0436\u0434\u044b\u0439 \u0434\u0435\u043d\u044c, \u043d\u0435 \u043f\u043e\u0434\u0443\u043c\u0430\u0432, \u0431\u0435\u0440\u0443\u0442 \u0432\u0441\u0451 \u043d\u043e\u0432\u044b\u0435, \u0430 \u0444\u0430\u0431\u0440\u0438\u043a\u0438 \u0441 \u0440\u0430\u0434\u043e\u0441\u0442\u044c\u044e \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u044e\u0442 \u0448\u0442\u0430\u043c\u043f\u043e\u0432\u0430\u0442\u044c "\u043c\u0430\u0435\u0447\u043a\u0438", \u0441\u043a\u0440\u0435\u043f\u043b\u044f\u044f \u043d\u0438\u0437 \u043d\u0435 \u043c\u0435\u043d\u0435\u0435 \u0432\u0440\u0435\u0434\u043d\u044b\u043c \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u043a\u043b\u0435\u0435\u043c.\n\n\u041a\u0430\u043a \u0436\u0435 \u0442\u043e\u0433\u0434\u0430 \u0431\u044b\u0442\u044c? \u0412 \u043f\u0435\u0440\u0432\u0443\u044e \u043e\u0447\u0435\u0440\u0435\u0434\u044c, \u043d\u0430\u0447\u0430\u0442\u044c \u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u043e\u0432\u044b\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0438 \u043f\u0440\u0438 \u043f\u043e\u0445\u043e\u0434\u0435 \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d. \u0421\u0442\u043e\u0438\u0442 \u0441\u043c\u0435\u043d\u0438\u0442\u044c \u043d\u0435\u043d\u0430\u0434\u0435\u0436\u043d\u044b\u0439 \u0438 \u0432\u0440\u0435\u0434\u043d\u044b\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0439 \u043f\u0430\u043a\u0435\u0442 \u043d\u0430 \u0448\u043e\u043f\u043f\u0435\u0440 \u0438\u043b\u0438 \u0440\u044e\u043a\u0437\u0430\u043a \u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043d\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0441\u0435\u0431\u0435 \u0432\u044b\u0445\u043e\u0434\u0438\u0442\u044c \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d \u0438\u043c\u0435\u043d\u043d\u043e \u0441 \u043d\u0438\u043c\u0438. \u041c\u043e\u0436\u043d\u043e \u0442\u0430\u043a\u0436\u0435 \u043f\u0440\u0438\u043e\u0431\u0440\u0435\u0441\u0442\u0438 \u0441\u043a\u043b\u0430\u0434\u043d\u044b\u0435 \u0442\u043a\u0430\u043d\u0435\u0432\u044b\u0435 \u0441\u0443\u043c\u043a\u0438, \u0432 \u0441\u043b\u043e\u0436\u0435\u043d\u043d\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \u043d\u0435 \u0437\u0430\u043d\u0438\u043c\u0430\u044e\u0449\u0438\u0435 \u043c\u0435\u0441\u0442\u0430 \u0431\u043e\u043b\u044c\u0448\u0435, \u0447\u0435\u043c \u043b\u0430\u0434\u043e\u043d\u044c \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430. \u0418\u0445 \u0431\u0443\u0434\u0435\u0442 \u0443\u0434\u043e\u0431\u043d\u043e \u043d\u043e\u0441\u0438\u0442\u044c \u043d\u0430 \u0443\u0447\u0435\u0431\u0443 \u0438 \u0440\u0430\u0431\u043e\u0442\u0443, \u0430 \u043d\u0430 \u043a\u0430\u0441\u0441\u0435 \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0435 \u0443\u0436\u0435 \u043d\u0435 \u0432\u043e\u0437\u043d\u0438\u043a\u043d\u0435\u0442 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u043a\u043e\u0433\u0434\u0430 \u043c\u043d\u043e\u0433\u043e \u043f\u043e\u043a\u0443\u043f\u043e\u043a \u043d\u0435\u043a\u0443\u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043b\u043e\u0436\u0438\u0442\u044c.\n'},C.aj,t.c)
C.zt=new H.aA(3,{id:2,title:"\u0427\u0442\u043e \u0431\u0443\u0434\u0435\u0442, \u0435\u0441\u043b\u0438 \u0431\u0440\u0430\u0442\u044c \u0432 \u043a\u043e\u0444\u0435\u0439\u043d\u0435 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0435 \u0442\u0440\u0443\u0431\u043e\u0447\u043a\u0438",text:'\u0422\u0440\u0443\u0431\u043e\u0447\u043a\u0430 \u0441\u043e\u0432\u0441\u0435\u043c \u043d\u0435 \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u043e\u043f\u0430\u0441\u043d\u043e\u0439. \u0421\u043a\u043e\u043b\u044c\u043a\u043e \u0432 \u043d\u0435\u0439 \u0432\u043e\u043e\u0431\u0449\u0435 \u044d\u0442\u043e\u0433\u043e \u0441\u0430\u043c\u043e\u0433\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430? \u041f\u0430\u0440\u0443 \u0433\u0440\u0430\u043c\u043c \u0438 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u043a\u0440\u0430\u0441\u043a\u0438? \u041a\u0430\u0436\u0435\u0442\u0441\u044f, \u0447\u0442\u043e \u043f\u043e\u0434\u043e\u0431\u043d\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u043d\u0435 \u043c\u043e\u0436\u0435\u0442 \u0441\u0442\u0430\u0442\u044c \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u043e\u0439, \u043d\u043e \u044d\u0442\u043e \u0442\u0430\u043a. \u041e\u0434\u043d\u0443 \u043f\u044f\u0442\u0443\u044e \u0447\u0430\u0441\u0442\u044c \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0445 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u0439 \u043c\u0438\u0440\u0430 \u0438 \u043e\u043a\u0435\u0430\u043d\u0430 \u0437\u0430\u043d\u0438\u043c\u0430\u044e\u0442 \u0438\u043c\u0435\u043d\u043d\u043e \u043e\u043d\u0438. \u0422\u0430\u043a\u0438\u043c \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u043c \u0432\u0435\u0449\u0430\u043c \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u043f\u0440\u043e\u0449\u0435 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u044f\u0442\u044c\u0441\u044f \u043f\u043e \u0432\u043e\u0434\u0435, \u043e\u0442\u0447\u0435\u0433\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u0434\u0430\u0436\u0435 \u043d\u0430 \u0421\u0435\u0432\u0435\u0440\u043d\u043e\u043c \u043f\u043e\u043b\u044e\u0441\u0435, \u0432\u043e \u043b\u044c\u0434\u0430\u0445. \n\n\u0411\u043e\u043b\u044c\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0432 \u043c\u0438\u0440\u0435 \u043e\u0442 \u0442\u0440\u0443\u0431\u043e\u0447\u0435\u043a \u0441\u0442\u0440\u0430\u0434\u0430\u044e\u0442 \u043c\u043e\u0440\u0441\u043a\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0435. \u041f\u043e\u043c\u0438\u043c\u043e \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u043e\u043d\u0438 \u043d\u0435\u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0441\u044a\u0435\u0434\u0430\u044e\u0442 \u0438\u0445 \u0438\u043b\u0438 \u0437\u0430\u0433\u043b\u0430\u0442\u044b\u0432\u0430\u044e\u0442 \u043f\u0440\u0438 \u0434\u044b\u0445\u0430\u043d\u0438\u0438, \u0447\u0442\u043e \u0432\u0440\u0435\u0434\u0438\u0442 \u043f\u0438\u0449\u0435\u0432\u043e\u0434\u0443 \u0438 \u0434\u044b\u0445\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0441\u0438\u0441\u0442\u0435\u043c\u0435, \u0442\u0430\u043a \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0435\u0449\u0435 \u0438 \u043e\u0442\u0440\u0430\u0432\u043b\u044f\u0435\u0442 \u0432\u043e\u0434\u0443 \u043f\u0440\u0438 \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u0438. \u0410 \u0432 \u0442\u0430\u043a\u043e\u0439 \u0441\u0440\u0435\u0434\u0435 \u044d\u0442\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442 \u0432 \u0434\u0432\u0430 \u0440\u0430\u0437\u0430 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u0447\u0435\u043c \u043d\u0430 \u0441\u0443\u0448\u0435, \u0438 \u043e\u0434\u043d\u0430 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0430\u044f \u0442\u0440\u0443\u0431\u043e\u0447\u043a\u0430 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u0440\u0442\u0438\u0442\u044c \u0432\u043e\u0434\u0443 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u0435\u0441\u044f\u0442\u0438\u043b\u0435\u0442\u0438\u0439. \n\n\u0423\u0447\u0435\u043d\u044b\u0435 \u0433\u043e\u0432\u043e\u0440\u044f\u0442 \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u0435\u0441\u043b\u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0441\u0434\u0435\u043b\u0430\u0442\u044c, \u0442\u043e \u0442\u0430\u043a\u0438\u043c\u0438 \u0442\u0435\u043c\u043f\u0430\u043c\u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u0430 \u0432\u043e\u043a\u0440\u0443\u0433 \u043d\u0430\u0441 \u0443\u043c\u0440\u0435\u0442 \u0432 \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0438\u0435 \u0441\u0442\u043e\u043b\u0435\u0442\u0438\u044f. \u0412\u0441\u0451 \u043d\u0430\u0447\u043d\u0451\u0442\u0441\u044f \u0441 \u043e\u043a\u0435\u0430\u043d\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0441\u0442\u0440\u0430\u0434\u0430\u0435\u0442 \u0441\u0435\u0439\u0447\u0430\u0441 \u0431\u043e\u043b\u044c\u0448\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445, \u043d\u043e \u0435\u0441\u043b\u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0434\u0435\u043b\u0430\u0442\u044c, \u0442\u043e \u0443\u0436\u0435 \u0441\u043a\u043e\u0440\u043e \u043c\u0443\u0441\u043e\u0440\u043d\u044b\u0435 \u043e\u0441\u0442\u0440\u043e\u0432\u0430 \u043d\u0430\u0447\u043d\u0443\u0442 \u0437\u0430\u043f\u043e\u043b\u043d\u044f\u0442\u044c \u0432\u0441\u0435 \u0432\u043e\u0434\u043d\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u043e. \u0427\u0435\u043b\u043e\u0432\u0435\u043a \u0440\u0438\u0441\u043a\u0443\u0435\u0442 \u0431\u0443\u043a\u0432\u0430\u043b\u044c\u043d\u043e \u043b\u0438\u0448\u0438\u0442\u044c\u0441\u044f \u0432\u043e\u0434\u044b, \u043d\u0435 \u0433\u043e\u0432\u043e\u0440\u044f \u0443\u0436\u0435 \u043e \u0442\u043e\u043c, \u043a\u0430\u043a \u043f\u043e\u0441\u0442\u0440\u0430\u0434\u0430\u044e\u0442 \u043b\u0435\u0441\u0430.\n\n\u0418 \u0432\u0441\u0451 \u044d\u0442\u043e \u0438\u0437-\u0437\u0430 \u043e\u0434\u043d\u043e\u0439 \u0442\u0440\u0443\u0431\u043e\u0447\u043a\u0438, \u0441\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442\u0441\u044f? \u0414\u0430 \u0438\u043c\u0435\u043d\u043d\u043e \u0438\u0437-\u0437\u0430 \u043d\u0435\u0451, \u0438\u0437-\u0437\u0430 \u043e\u0434\u043d\u043e\u0439 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u043e\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u043e\u0439 \u043f\u0430\u043b\u043e\u0447\u043a\u0438 \u0434\u043b\u044f \u043d\u0430\u043f\u0438\u0442\u043a\u043e\u0432, \u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u043d\u043e\u0439 \u0432 \u043d\u0435\u0438\u0437\u043c\u0435\u0440\u0438\u043c\u044b\u0445 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0430\u0445 \u0444\u0430\u0431\u0440\u0438\u043a\u0430\u043c\u0438 \u0438 \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u043e \u0432\u044b\u043a\u0438\u043d\u0443\u0442\u043e\u0439 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u043e\u043c. \u0412\u0435\u0434\u044c \u043e\u043d \u043d\u0435 \u043e\u0434\u0438\u043d, \u0442\u0430\u043a\u0438\u0445, \u043d\u0435 \u0437\u0430\u0434\u0443\u043c\u044b\u0432\u0430\u044e\u0449\u0438\u0445\u0441\u044f \u043e \u043f\u043e\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u044f\u0445, \u043c\u0438\u043b\u043b\u0438\u043e\u043d\u044b \u043f\u043e \u0432\u0441\u0435\u0439 \u043f\u043b\u0430\u043d\u0435\u0442\u0435. \n\n\u0423\u0436\u0435 \u0432 2018 \u0433\u043e\u0434\u0443 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u0430\u044f \u0441\u0435\u0442\u044c \u043a\u043e\u0444\u0435\u0435\u043d "\u0421\u0442\u0430\u0440\u0431\u0430\u043a\u0441" \u0441\u043e\u043e\u0431\u0449\u0438\u043b\u0430, \u0447\u0442\u043e \u043e\u043d\u0438 \u043e\u0442\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442\u0441\u044f \u043e\u0442 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0445 \u0442\u0440\u0443\u0431\u043e\u0447\u0435\u043a, \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u044f \u043d\u0430 \u0441\u043e\u043b\u043e\u043c\u0438\u043d\u043a\u0438 \u0438\u0437 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u043c\u043e\u0433\u043e \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430. \u0418 \u0434\u0430\u0436\u0435 \u043e\u043d\u0438 \u0431\u0443\u0434\u0443\u0442 \u0432\u044b\u0434\u0430\u0432\u0430\u0442\u044c\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u0442\u043e\u043c \u0441\u043b\u0443\u0447\u0430\u0435, \u0435\u0441\u043b\u0438 \u043a\u043b\u0438\u0435\u043d\u0442 \u0441\u0430\u043c \u043f\u043e\u043f\u0440\u043e\u0441\u0438\u0442. \u0418\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432\u0443 "\u0421\u0442\u0430\u0440\u0431\u0430\u043a\u0441" \u043f\u043e\u0434\u0445\u0432\u0430\u0442\u0438\u043b\u0430 \u0438 \u0434\u0440\u0443\u0433\u0430\u044f \u043a\u0440\u0443\u043f\u043d\u0430\u044f \u0441\u0435\u0442\u044c - \u041c\u0430\u043a\u0434\u043e\u043d\u0430\u043b\u044c\u0434\u0441, \u0430 \u0437\u0430 \u043d\u0438\u043c, \u043a\u0441\u0442\u0430\u0442\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0440\u0435\u0441\u0442\u043e\u0440\u0430\u043d\u0447\u0438\u043a\u0438 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443.\n\n\u0422\u0430\u043a \u0447\u0442\u043e \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u043b\u0438\u0448\u043d\u0438\u0439 \u0440\u0430\u0437 \u0431\u0440\u0430\u0442\u044c \u0442\u0440\u0443\u0431\u043e\u0447\u043a\u0438  \u0438 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0435 \u043a\u0440\u044b\u0448\u043a\u0438, \u0442\u0435\u043c \u0431\u043e\u043b\u0435\u0435, \u043b\u044e\u0431\u043e\u0439 \u0431\u0430\u0440\u0438\u0441\u0442\u0430 \u0441\u043a\u0430\u0436\u0435\u0442 \u0432\u0430\u043c, \u0447\u0442\u043e \u0431\u0435\u0437 \u0441\u043e\u043b\u043e\u043c\u0438\u043d\u043a\u0438 \u043a\u043e\u0444\u0435 \u0432\u043a\u0443\u0441\u043d\u0435\u0435.\n'},C.aj,t.c)
C.zx=new H.aA(3,{id:3,title:"\u0421\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043c\u0443\u0441\u043e\u0440\u0430: \u043d\u0435\u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0438\u043b\u0438 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e?",text:'\u0415\u0449\u0451 \u0434\u0435\u0441\u044f\u0442\u0438\u043b\u0435\u0442\u0438\u0435 \u043d\u0430\u0437\u0430\u0434 \u0432\u043e\u043f\u0440\u043e\u0441 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u0443\u0441\u043e\u0440\u0430 \u0432\u043e\u043b\u043d\u043e\u0432\u0430\u043b \u043b\u0438\u0448\u044c \u0443\u0447\u0435\u043d\u044b\u0445. \u041f\u0440\u043e\u0441\u0442\u044b\u0435 \u043e\u0431\u044b\u0432\u0430\u0442\u0435\u043b\u0438 \u0438 \u043d\u0435 \u0434\u0443\u043c\u0430\u043b\u0438 \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0435 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0438 \u0438 \u0441\u0442\u0435\u043a\u043b\u044f\u043d\u043d\u044b\u0435 \u0431\u0443\u0442\u044b\u043b\u043a\u0438 \u0441\u0442\u043e\u0438\u043b\u043e \u0431\u044b \u0431\u0440\u043e\u0441\u0430\u0442\u044c \u0432 \u0440\u0430\u0437\u043d\u044b\u0435 \u043a\u043e\u043d\u0442\u0435\u0439\u043d\u0435\u0440\u044b, \u043f\u043e\u043a\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438 \u043d\u0435 \u0437\u0430\u0431\u0438\u043b\u0438 \u0442\u0440\u0435\u0432\u043e\u0433\u0443.\n\n\u041d\u043e, \u0435\u0441\u043b\u0438 \u0447\u0435\u0441\u0442\u043d\u043e, \u043d\u043e\u0432\u043e\u0441\u0442\u0438 \u043e\u0431 \u0443\u0445\u0443\u0434\u0448\u0435\u043d\u0438\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u043b\u0438\u0448\u044c \u043d\u0430\u0432\u0435\u043b\u0438 \u0438\u0437\u043b\u0438\u0448\u043d\u044e\u044e \u043f\u0430\u043d\u0438\u043a\u0443, \u0438 \u043b\u044e\u0434\u0438 \u043f\u043e \u0441\u0435\u0439 \u0434\u0435\u043d\u044c \u043d\u0435 \u0437\u043d\u0430\u044e\u0442 \u043d\u0438\u0447\u0435\u0433\u043e \u043e \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u0439 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0435. \u0420\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u0435 \u043c\u0443\u0441\u043e\u0440\u0430 \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u0447\u0435\u043c-\u0442\u043e \u043d\u0435\u0440\u0435\u0430\u043b\u044c\u043d\u044b\u043c, \u0441\u0442\u043e\u0438\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u0441\u043f\u043e\u043c\u043d\u0438\u0442\u044c \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0431\u044b\u0432\u0430\u0435\u0442 \u0440\u0430\u0437\u043d\u044b\u0445 \u0432\u0438\u0434\u043e\u0432, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440. \u0418\u043b\u0438 \u0447\u0442\u043e \u0434\u0435\u043b\u0430\u0442\u044c \u0441\u043e \u0441\u0442\u0435\u043a\u043b\u044f\u043d\u043d\u044b\u043c\u0438 \u0431\u0443\u0442\u044b\u043b\u043a\u0430\u043c\u0438 \u0441 \u0431\u0443\u043c\u0430\u0436\u043d\u043e\u0439 \u044d\u0442\u0438\u043a\u0435\u0442\u043a\u043e\u0439? \u0421\u0430\u043c\u043e\u0441\u0442\u043e\u044f\u0442\u0435\u043b\u044c\u043d\u0430 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u043d\u0435\u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0439.\n\n\u041d\u043e \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0434\u0435\u043b\u0430\u0442\u044c \u043f\u043e\u0441\u043f\u0435\u0448\u043d\u044b\u0435 \u0432\u044b\u0432\u043e\u0434\u044b, \u043a\u0430\u043a \u0438 \u043d\u0435 \u043d\u0443\u0436\u043d\u043e \u043f\u044b\u0442\u0430\u0442\u044c\u0441\u044f \u0441\u0440\u0430\u0437\u0443 \u0440\u0430\u0441\u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0432\u0435\u0441\u044c \u043c\u0443\u0441\u043e\u0440 \u0432 \u0434\u043e\u043c\u0435. \u0412\u044b \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430\u043f\u0443\u0442\u0430\u0435\u0442\u0435\u0441\u044c, \u0440\u0430\u0437\u043e\u0437\u043b\u0438\u0442\u0435\u0441\u044c \u0438 \u0432\u043e\u043e\u0431\u0449\u0435 \u0437\u0430\u0445\u043e\u0442\u0438\u0442\u0435 \u043e\u0442\u0431\u0440\u043e\u0441\u0438\u0442\u044c \u044d\u0442\u0443 \u0437\u0430\u0442\u0435\u044e. \u041d\u0430\u0447\u0438\u043d\u0430\u0442\u044c \u0441\u0442\u043e\u0438\u0442 \u0441 \u043c\u0430\u043b\u043e\u0433\u043e, \u0430 \u0438\u043c\u0435\u043d\u043d\u043e \u0441 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u043f\u0435\u0440\u0435\u0434 \u0432\u0430\u043c\u0438 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f. \u042d\u043a\u043e\u043b\u043e\u0433\u0438 \u0432\u044b\u0434\u0435\u043b\u044f\u044e\u0442 \u0442\u0440\u0438 \u0442\u0438\u043f\u0430 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430:\n\n- \u041c\u0443\u0441\u043e\u0440 - \u043d\u0435\u0447\u0442\u043e \u0441\u043e\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u043e \u043d\u0438\u043a\u043e\u043c\u0443 \u043d\u0435 \u043d\u0443\u0436\u043d\u043e, \u043f\u0440\u043e\u0441\u0442\u043e \u0432\u044b\u0431\u0440\u043e\u0448\u0435\u043d\u043d\u043e\u0435 \u0433\u0434\u0435-\u0442\u043e \u043d\u0430 \u0437\u0435\u043c\u043b\u0435. \n- \u041e\u0442\u0445\u043e\u0434\u044b - \u044d\u0442\u043e \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u043e\u0432\u0430\u043d\u043e \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u0439 \u043c\u0443\u0441\u043e\u0440\n- \u0412\u0442\u043e\u0440\u0441\u044b\u0440\u044c\u0435 - \u043e\u0442\u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u043e\u0442\u0445\u043e\u0434\u044b, \u0446\u0435\u043b\u0435\u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u043d\u043e \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u0435 \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443.\n\n\u041d\u0443\u0436\u043d\u043e \u0440\u0430\u0437\u0433\u0440\u0430\u043d\u0438\u0447\u0438\u0432\u0430\u0442\u044c \u043f\u0435\u0440\u0432\u044b\u0435 \u0434\u0432\u0430 \u043f\u043e\u043d\u044f\u0442\u0438\u044f \u0438 \u0437\u0430\u043d\u0438\u043c\u0430\u0442\u044c\u0441\u044f \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u0442\u043e\u0440\u043e\u0433\u043e. \u041d\u0430\u0447\u0430\u0442\u044c \u0441\u0442\u043e\u0438\u0442 \u0441 \u0441\u0430\u043c\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u043e\u0433\u043e, \u043d\u0435 \u0431\u0440\u043e\u0441\u0430\u0442\u044c\u0441\u044f \u0432 \u043e\u043c\u0443\u0442 \u0440\u0430\u0437\u0434\u0435\u043b\u0435\u043d\u0438\u044f \u0438 \u043f\u043e\u043f\u044b\u0442\u043a\u0438 \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u0442\u044c \u0432\u0438\u0434\u044b \u0431\u0443\u043c\u0430\u0433\u0438. \u0421\u0430\u043c\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0435 \u0434\u043b\u044f \u0440\u0430\u0437\u0433\u043e\u043d\u0430 - \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u0431\u0430\u0442\u0430\u0440\u0435\u0435\u043a \u043e\u0442 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043c\u0443\u0441\u043e\u0440\u0430. \u042d\u0442\u043e \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0439, \u043d\u043e \u043e\u0447\u0435\u043d\u044c \u0432\u0430\u0436\u043d\u044b\u0439 \u0448\u0430\u0433, \u0432\u0435\u0434\u044c \u0431\u0430\u0442\u0430\u0440\u0435\u0438 \u0438 \u0430\u043a\u043a\u0443\u043c\u0443\u043b\u044f\u0442\u043e\u0440\u044b \u043e\u0442\u043d\u043e\u0441\u044f\u0442\u0441\u044f \u043a \u043e\u0442\u0445\u043e\u0434\u0430\u043c \u043e\u043f\u0430\u0441\u043d\u043e\u0433\u043e \u0442\u0438\u043f\u0430. \u041a\u043e\u0433\u0434\u0430 \u0434\u043e\u043c\u0430 \u043d\u0430\u043a\u043e\u043f\u0438\u0442\u0441\u044f \u0443\u0436\u0435 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0430\u044f \u0433\u043e\u0440\u0430 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u0431\u0430\u0442\u0430\u0440\u0435\u0435\u043a \u0438\u0445 \u043c\u043e\u0436\u043d\u043e \u0431\u0443\u0434\u0435\u0442 \u0441\u0434\u0430\u0442\u044c \u0432 \u043f\u0443\u043d\u043a\u0442 \u043f\u0440\u0438\u0435\u043c\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0441\u0435\u0439\u0447\u0430\u0441 \u0443\u0436\u0435 \u043d\u0435 \u043c\u0430\u043b\u043e. \u0412 \u041e\u043c\u0441\u043a\u0435 \u043f\u0440\u0438\u0435\u043c \u043e\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432 \u0442\u0430\u043a\u043e\u0439 \u0441\u0435\u0442\u0438 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u043e\u0432, \u043a\u0430\u043a "\u041b\u0435\u043d\u0442\u0430", \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440.\n\n\u041a\u043e\u0433\u0434\u0430 \u043f\u0435\u0440\u0432\u044b\u0435 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0435 \u0448\u0430\u0433\u0438 \u0432\u043e\u0439\u0434\u0443\u0442 \u0432 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443, \u043c\u043e\u0436\u043d\u043e \u0431\u0443\u0434\u0435\u0442 \u043d\u0430\u0447\u0430\u0442\u044c \u043e\u0442\u0434\u0435\u043b\u044f\u0442\u044c \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044b, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0438\u0437\u0443\u0447\u0430\u0442\u044c \u0438 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0440\u0430\u0441\u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0435\u043c\u043d\u044b\u0445 \u043f\u0443\u043d\u043a\u0442\u043e\u0432 \u0432 \u0433\u043e\u0440\u043e\u0434\u0435. \u042d\u0442\u043e \u043e\u0447\u0435\u043d\u044c \u0432\u0430\u0436\u043d\u043e \u0432\u043e \u0438\u0437\u0431\u0435\u0436\u0430\u043d\u0438\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0439, \u043a\u043e\u0433\u0434\u0430 \u0432 \u0446\u0435\u043d\u0442\u0440 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0431\u0443\u043c\u0430\u0433\u0438 \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u0437\u0430\u044f\u0432\u0438\u0442\u044c\u0441\u044f \u0441\u043e \u0441\u0442\u0435\u043a\u043b\u043e\u0442\u0430\u0440\u043e\u0439.\n\n\u0418, \u043d\u0430\u043f\u043e\u0441\u043b\u0435\u0434\u043e\u043a, \u043f\u043e\u043c\u043d\u0438\u0442\u0435, \u0447\u0442\u043e \u0432\u0441\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044b \u0442\u0440\u0435\u0431\u0443\u044e\u0442 \u0440\u0430\u0437\u043d\u043e\u0433\u043e \u043e\u0431\u0440\u0430\u0449\u0435\u043d\u0438\u044f \u0438 \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f. \u0411\u0443\u043c\u0430\u0436\u043d\u044b\u0435 \u043e\u0442\u0445\u043e\u0434\u044b \u043d\u0435\u043f\u0440\u0438\u0445\u043e\u0442\u043b\u0438\u0432\u044b, \u0430 \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0438 \u0441\u0442\u0435\u043a\u043b\u043e \u043d\u0443\u0436\u043d\u043e \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u0440\u043e\u043c\u044b\u0432\u0430\u0442\u044c \u043e\u0442 \u043e\u0441\u0442\u0430\u0442\u043a\u043e\u0432 \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u043c\u043e\u0433\u043e. \u0421\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0435 \u0441\u0442\u0430\u043d\u0435\u0442 \u0434\u043b\u044f \u0432\u0430\u0441 \u0441\u043b\u043e\u0436\u043d\u043e\u0439, \u0435\u0441\u043b\u0438 \u0432\u043d\u0438\u043a\u0430\u0442\u044c \u0432 \u043d\u0435\u0451 \u043f\u043e\u0441\u0442\u0435\u043f\u0435\u043d\u043d\u043e.\n'},C.aj,t.c)
C.zy=new H.aA(3,{id:4,title:"\u0423\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u0443\u0435\u043c \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e",text:"\u0412\u043e\u043f\u0440\u043e\u0441 \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430, \u043a\u0430\u043a \u043d\u0430\u043c \u043a\u0430\u0436\u0435\u0442\u0441\u044f, \u043d\u0438\u043a\u043e\u0433\u0434\u0430 \u043d\u0435 \u0443\u0442\u0438\u0445\u043d\u0435\u0442. \u0412\u0440\u043e\u0434\u0435 \u0431\u044b, \u043a\u0430\u0436\u0434\u044b\u0439 \u0437\u043d\u0430\u0435\u0442, \u043a\u0430\u043a \u043c\u0438\u043d\u0438\u043c\u0443\u043c \u043d\u0430 \u0431\u0430\u0437\u043e\u0432\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435, \u0447\u0442\u043e \u043d\u0443\u0436\u043d\u043e \u0438 \u043d\u0435 \u043d\u0443\u0436\u043d\u043e \u0434\u0435\u043b\u0430\u0442\u044c, \u043e\u0434\u043d\u0430\u043a\u043e \u0432 \u0438\u043d\u0442\u0435\u0440\u043d\u0435\u0442\u0435 \u0442\u043e \u0438 \u0434\u0435\u043b\u043e \u0432\u0441\u043f\u043b\u044b\u0432\u0430\u044e\u0442 \u0441\u043e\u0432\u0441\u0435\u043c \u043d\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0435 \u043f\u043e\u0441\u0442\u044b \u043e\u0442 \u0431\u043b\u043e\u0433\u0433\u0435\u0440\u043e\u0432 \u0441 \u0431\u043e\u043b\u044c\u0448\u043e\u0439 \u0430\u0443\u0434\u0438\u0442\u043e\u0440\u0438\u0435\u0439, \u0433\u0434\u0435 \u043e\u0431 \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u0433\u043e\u0432\u043e\u0440\u044f\u0442\u0441\u044f \u0436\u0443\u0442\u043a\u0438\u0435, \u0441\u043e\u0432\u0441\u0435\u043c \u043d\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0435 \u0432\u0435\u0449\u0438.\t  \n\u0422\u0430\u043a \u0447\u0442\u043e \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u043c\u044b \u0440\u0430\u0441\u0441\u043a\u0430\u0436\u0435\u043c \u043e \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0442\u043e\u043d\u043a\u043e\u0441\u0442\u044f\u0445 \u044d\u0442\u043e\u0433\u043e \u0432\u043e\u043f\u0440\u043e\u0441\u0430, \u0438 \u043a\u0430\u043a \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u0442\u043e\u0438\u0442 \u043f\u043e\u0441\u0442\u0443\u043f\u0430\u0442\u044c, \u0435\u0441\u043b\u0438 \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0432\u0441\u0451-\u0442\u0430\u043a\u0438 \u043e\u043a\u0430\u0437\u0430\u043b\u0441\u044f \u0443 \u0432\u0430\u0441 \u0432 \u0440\u0443\u043a\u0430\u0445.\n\u0414\u043b\u044f \u043d\u0430\u0447\u0430\u043b\u0430 \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043c\u0435\u0442\u0438\u0442\u044c, \u0447\u0442\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u2013 \u0441\u043e\u0432\u0441\u0435\u043c \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \xab\u0437\u0432\u0435\u0440\u044c\xbb. \u0411\u0443\u0442\u044b\u043b\u043a\u0430 \u043e\u0442 \u0433\u0430\u0437\u0438\u0440\u043e\u0432\u043a\u0438 \u0438 \u044d\u0442\u0438\u043a\u0435\u0442\u043a\u0430 \u043d\u0430 \u043d\u0435\u0439, \u043a\u0430\u043a \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f, \u0445\u043e\u0442\u044c \u0438 \u0438\u043c\u0435\u044e\u0442 \u043e\u0434\u043d\u043e\u0433\u043e \u0440\u043e\u0434\u0438\u0442\u0435\u043b\u044f, \u043d\u043e \u0434\u0430\u0436\u0435 \u043e\u043d\u0438 \u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u0440\u0430\u0437\u043d\u044b\u043c\u0438. \u0427\u0442\u043e \u0443\u0436 \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c \u043e \u0440\u0430\u0437\u043d\u0438\u0446\u0435 \u0443\u043f\u0430\u043a\u043e\u0432\u043e\u043a \u0438 \u043f\u0430\u043a\u0435\u0442\u043e\u0432, \u0442\u0440\u0443\u0431\u043e\u0447\u0435\u043a \u0438 \u043a\u043e\u043d\u0442\u0435\u0439\u043d\u0435\u0440\u043e\u0432 \u0434\u043b\u044f \u0435\u0434\u044b.\t   \n\u0412\u043e\u0442 \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u043a\u0430, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0441\u0442\u043e\u0438\u0442 \u043d\u0430\u0447\u0430\u0442\u044c \u043f\u043e\u0441\u0442\u0435\u043f\u0435\u043d\u043d\u043e \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c:\n 1.  (PET, PETE, \u041f\u042d\u0422, \u041f\u0415\u0422\u0415) \u2013 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d\u0442\u0435\u0440\u0435\u0444\u0442\u0430\u043b\u0430\u0442. \u0425\u043e\u0440\u043e\u0448\u043e \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f, \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442\u0441\u044f \u043f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0432\u0435\u0437\u0434\u0435, \u0433\u0434\u0435 \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442 \u043f\u043b\u0430\u0441\u0442\u0438\u043a. \u041e\u0431\u044b\u0447\u043d\u043e \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u0432\u0438\u0434\u0430 \u0441\u043e\u0437\u0434\u0430\u044e\u0442\u0441\u044f \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u0435 \u0431\u0443\u0442\u044b\u043b\u043a\u0438.\n2. (PEHD, HDPE, PE-HD, HD-PE, \u041f\u041d\u0414) \u2013 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d \u0432\u044b\u0441\u043e\u043a\u043e\u0439 \u043f\u043b\u043e\u0442\u043d\u043e\u0441\u0442\u0438. \u0427\u0430\u0441\u0442\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443. \u042d\u0442\u043e \u0442\u0432\u0451\u0440\u0434\u044b\u0439 \u0442\u0438\u043f \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430, \u0438\u0437 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u043e\u0431\u044b\u0447\u043d\u043e \u0434\u0435\u043b\u0430\u044e\u0442 \u0444\u043b\u0430\u043a\u043e\u043d\u044b. \n3. (PVC, V, \u041f\u0412\u0425) \u2013 \u0418\u0437 \u043f\u043e\u043b\u0438\u0432\u0438\u043d\u0438\u043b\u0445\u043b\u043e\u0440\u0438\u0434 \u0434\u0435\u043b\u0430\u044e\u0442 \u0432\u0438\u043d\u0438\u043f\u043b\u0430\u0441\u0442 \u0438 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430\u0442, \u043f\u0430\u0441\u0442\u044b-\u043f\u043b\u0430\u0441\u0442\u0438\u0437\u043e\u043b\u0438 \u041f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f.\n4. (PELD, LDPE, PE-LD, LD-PE, \u041f\u0412\u0414) \u2013 \u0442\u043e\u0442 \u0436\u0435 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d, \u0447\u0442\u043e \u0438 \u0432 2, \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0438\u0437\u043a\u043e\u0439 \u043f\u043b\u043e\u0442\u043d\u043e\u0441\u0442\u0438. \u0421\u0434\u0430\u0442\u044c \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443 \u0443\u0436\u0435 \u0441\u043b\u043e\u0436\u043d\u0435\u0435, \u043d\u043e \u0432\u0441\u0451 \u0436\u0435 \u043c\u043e\u0436\u043d\u043e. \u0418\u043c\u0435\u043d\u043d\u043e \u0438\u0437 \u044d\u0442\u043e\u0433\u043e \u0442\u0438\u043f\u0430 \u0441\u043e\u0437\u0434\u0430\u044e\u0442\u0441\u044f  \u043b\u0438\u043d\u043e\u043b\u0435\u0443\u043c, \u043c\u0443\u0441\u043e\u0440\u043d\u044b\u0435 \u043f\u0430\u043a\u0435\u0442\u044b \u0438 \u043f\u0438\u0449\u0435\u0432\u0430\u044f \u043f\u043b\u0435\u043d\u043a\u0430.\n 5. (PP, \u041f\u041f) \u2013 \u043f\u043e\u043b\u0438\u043f\u0440\u043e\u043f\u0438\u043b\u0435\u043d \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043f\u043e\u0447\u0442\u0438 \u0432\u0435\u0437\u0434\u0435 \u0432 \u043d\u0430\u0448\u0435\u0439 \u0436\u0438\u0437\u043d\u0438. \u0418\u0437 \u043d\u0435\u0433\u043e \u0441\u043e\u0437\u0434\u0430\u044e\u0442 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0438, \u0442\u0435\u043a\u0441\u0442\u0438\u043b\u044c, \u043a\u0430\u043d\u0446\u0435\u043b\u044f\u0440\u0438\u044e, \u043a\u043e\u043d\u0442\u0435\u0439\u043d\u0435\u0440\u044b \u0438 \u0434\u0430\u0436\u0435 \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0435 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439 \u041f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0435\u043d\u0430, \u043d\u043e \u043d\u0435 \u0442\u0430\u043a \u0445\u043e\u0440\u043e\u0448\u043e \u043a\u0430\u043a \u0443 \u041f\u042d\u0422.\n6.  (PS, \u041f\u0421) \u2013 \u043f\u043e\u043b\u0438\u0441\u0442\u0438\u0440\u043e\u043b \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0432 \u043f\u0440\u043e\u043c\u044b\u0448\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u0438: \u0438\u0437 \u043d\u0435\u0433\u043e \u0438\u0437\u0433\u043e\u0442\u0430\u0432\u043b\u0438\u0432\u0430\u044e\u0442 \u043e\u0434\u043d\u043e\u0440\u0430\u0437\u043e\u0432\u0443\u044e \u043f\u043e\u0441\u0443\u0434\u0443, \u0440\u0430\u0437\u043b\u0438\u0447\u043d\u044b\u0435 \u0443\u043f\u0430\u043a\u043e\u0432\u043e\u0447\u043d\u044b\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044b, \u0434\u0435\u0442\u0441\u043a\u0438\u0435 \u0438\u0433\u0440\u0443\u0448\u043a\u0438 \u0438 \u043c\u043d\u043e\u0433\u043e\u0435 \u0434\u0440\u0443\u0433\u043e\u0435. \u0415\u0433\u043e \u0440\u0435\u0434\u043a\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443.\n7. (O, \u041ether) \u2013 \u0434\u0440\u0443\u0433\u0438\u0435 \u0432\u0438\u0434\u044b \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430 \u0438\u043b\u0438 \u0441\u043c\u0435\u0441\u044c \u0438\u0437 \u0432\u044b\u0448\u0435\u043f\u0435\u0440\u0435\u0447\u0438\u0441\u043b\u0435\u043d\u043d\u044b\u0445. \u041f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f.\n \u0422\u0435\u043f\u0435\u0440\u044c, \u043a\u043e\u0433\u0434\u0430 \u043c\u044b \u0437\u043d\u0430\u0435\u043c \u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0435 \u0431\u043e\u043b\u044c\u0448\u0435, \u0441\u0442\u0430\u043d\u0435\u0442 \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u043f\u0440\u043e\u0449\u0435 \u0437\u0430\u043d\u0438\u043c\u0430\u0442\u044c\u0441\u044f \u0434\u043e\u043c\u0430\u0448\u043d\u0435\u0439 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u043e\u0439. \u0410 \u0442\u0430\u043a\u0436\u0435 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442 \u043f\u043e\u043b\u043d\u043e\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0442\u043e\u0433\u043e, \u043f\u043e\u0447\u0435\u043c\u0443 \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0437\u0430\u043d\u0438\u043c\u0430\u0442\u044c\u0441\u044f \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u0435\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430 \u0441\u0430\u043c\u043e\u0441\u0442\u043e\u044f\u0442\u0435\u043b\u044c\u043d\u043e. \u0412\u043e\u043b\u0435\u0439-\u043d\u0435\u0432\u043e\u043b\u0435\u0439, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u0441\u0440\u0435\u0434\u0438 \u0434\u0430\u0447\u043d\u0438\u043a\u043e\u0432, \u0441\u0435\u0439\u0447\u0430\u0441 \u0447\u0430\u0441\u0442\u043e \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044e\u0442\u0441\u044f \u0441\u043e\u0432\u0435\u0442\u044b \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u0441\u0436\u0438\u0433\u0430\u0442\u044c \u0431\u0443\u0442\u044b\u043b\u043a\u0438  \u043c\u043e\u0436\u043d\u043e \u0438 \u0432\u043e\u043e\u0431\u0449\u0435, \u044d\u0442\u043e \u0432\u0441\u044f\u043a\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u043f\u0440\u043e\u0441\u0442\u043e \u0432\u044b\u0431\u0440\u043e\u0441\u0438\u0442\u044c \u0438\u0445 \u0432 \u043e\u0447\u0435\u0440\u0435\u0434\u043d\u043e\u0439 \u0440\u0430\u0437 \u0434\u043e\u043b\u0433\u043e \u0440\u0430\u0437\u043e\u043b\u0433\u0430\u0442\u044c\u0441\u044f.\n \u041e\u0434\u043d\u0430\u043a\u043e, \u0441\u043f\u0435\u0448\u0438\u043c \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u0430\u0442\u044c, \u043f\u043e\u0447\u0435\u043c\u0443 \u0432\u0441\u0451 \u043d\u0435 \u0442\u0430\u043a \u043f\u0440\u043e\u0441\u0442\u043e!\n1. \u0412 \u0442\u0435\u043e\u0440\u0438\u0438, PET \u0438\u0437 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0434\u0435\u043b\u0430\u043d\u044b \u0431\u0443\u0442\u044b\u043b\u043a\u0438, \u043d\u0435 \u0434\u043e\u043b\u0436\u0435\u043d \u0432\u044b\u0434\u0435\u043b\u044f\u0442\u044c \u043e\u043f\u0430\u0441\u043d\u044b\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432 \u043f\u0440\u0438 \u0441\u0433\u043e\u0440\u0430\u043d\u0438\u0438, \u043d\u043e \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u043e\u043d\u0438 \u043c\u043e\u0433\u0443\u0442 \u0438 \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0442 \u0432\u0440\u0435\u0434\u043d\u044b\u0435 \u0434\u043e\u0431\u0430\u0432\u043a\u0438, \u043e \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u043d\u0438\u043a\u0442\u043e \u043d\u0435 \u0440\u0430\u0441\u0441\u043a\u0430\u0436\u0435\u0442. \u041a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u0438, \u0441\u0442\u0430\u0431\u0438\u043b\u0438\u0437\u0430\u0442\u043e\u0440\u044b \u0438 \u0442\u043e\u043c\u0443 \u043f\u043e\u0434\u043e\u0431\u043d\u043e\u0435 \u0431\u0443\u0434\u0443\u0442 \u0432\u0440\u0435\u0434\u043d\u044b \u0434\u0430\u0436\u0435 \u0432 \u043c\u0430\u043b\u044b\u0445 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0430\u0445, \u0430 \u0447\u0442\u043e \u0432 \u0438\u0442\u043e\u0433\u0435 \u0432\u044b\u0434\u0435\u043b\u0438\u0442\u0441\u044f \u043f\u0440\u0438 \u0438\u0445 \u0441\u0433\u043e\u0440\u0430\u043d\u0438\u0438 \u2013 \u043d\u0438\u043a\u043e\u043c\u0443 \u043d\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u043e. \u0410 \u0432\u043e\u0442 \u0435\u0441\u043b\u0438 \u0432 \u043a\u043e\u0441\u0442\u0451\u0440 \u043f\u043e\u043f\u0430\u0434\u0451\u0442 \u043a\u043e\u043d\u0442\u0435\u0439\u043d\u0435\u0440 \u0438\u0437 \u043f\u043e\u043b\u0438\u0432\u0438\u043d\u0438\u043b\u0445\u043b\u043e\u0440\u0438\u0434\u0430, \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u0435 \u0432\u043e\u0437\u0434\u0443\u0445\u0430 \u0442\u043e\u043a\u0441\u0438\u0447\u043d\u044b\u043c\u0438 \u0434\u0438\u043e\u043a\u0441\u0438\u043d\u0430\u043c\u0438 \u0438 \u0444\u0443\u0440\u0430\u043d\u0430\u043c\u0438 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043e. \u0414\u044b\u0448\u0430\u0442\u044c \u044d\u0442\u0438\u043c \u043e\u0447\u0435\u043d\u044c \u043e\u043f\u0430\u0441\u043d\u043e!\n2. \u041d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0432\u0435\u0440\u0438\u0442\u044c \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0441\u0436\u0438\u0433\u0430\u043d\u0438\u0435 \u2013 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0441\u043f\u043e\u0441\u043e\u0431 \u0441\u043f\u0430\u0441\u0435\u043d\u0438\u044f \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b \u043e\u0442 \u0431\u0443\u0442\u044b\u043b\u043e\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0431\u0435\u0437 \u044d\u0442\u043e\u0433\u043e \u0431\u0443\u0434\u0443\u0442 \u0441\u043e\u0442\u043d\u0438 \u043b\u0435\u0442 \u043e\u0442\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u0437\u0435\u043c\u043b\u044e \u0441\u0432\u043e\u0438\u043c \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u0435. \u041f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0442\u0430\u043a, \u043d\u043e \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u043b\u0443\u0447\u0448\u0438\u043c \u0440\u0435\u0448\u0435\u043d\u0438\u0435\u043c \u0432\u0441\u0451 \u0435\u0449\u0451 \u043e\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0430. \u0418\u0437 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043d\u043e\u0433\u043e \u0432\u0442\u043e\u0440\u0441\u044b\u0440\u044c\u044f \u043f\u043e\u0437\u0436\u0435 \u0441\u0434\u0435\u043b\u0430\u044e\u0442 \u043f\u0430\u043a\u0435\u0442\u044b, \u043e\u0442\u0434\u0435\u043b\u043e\u0447\u043d\u044b\u0435 \u043f\u043b\u0438\u0442\u043a\u0438 \u0438 \u043b\u0430\u0434\u0435 \u043d\u043e\u0432\u044b\u0435 \u0431\u0443\u0442\u044b\u043b\u043a\u0438! \u041d\u0435 \u043b\u0438\u0448\u0430\u0439\u0442\u0435 \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u0438 \u043f\u0435\u0440\u0435\u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f.\n3. \u0421\u0430\u043c\u044b\u0439 \u043b\u0443\u0447\u0448\u0438\u0439 \u0441\u043e\u0432\u0435\u0442 \u0432 \u0440\u0430\u0431\u043e\u0442\u0435 \u0441 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u043c \u2013 \u043e\u0442\u043a\u0430\u0437 \u043e\u0442 \u043d\u0435\u0433\u043e. \u0414\u0430-\u0434\u0430, \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u044f \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u0431\u0443\u0442\u044b\u043b\u043e\u043a \u0438 \u043f\u0430\u043a\u0435\u0442\u043e\u0432 \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u043b\u0443\u0447\u0448\u0435 \u0434\u0430\u0436\u0435 \u0438\u0445 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438. \u0415\u0441\u043b\u0438 \u0441\u0434\u0430\u0442\u044c \u0420\u042d\u0422 \u0418 \u041f\u042d\u0422 \u043b\u0435\u0433\u043a\u043e, \u0442\u043e \u043d\u0430\u0439\u0442\u0438 \u043f\u0443\u043d\u043a\u0442 \u043f\u0440\u0438\u0435\u043c\u0430 \u0434\u043b\u044f \u0431\u043e\u043b\u0435\u0435 \u0441\u043b\u043e\u0436\u043d\u044b\u0445 \u0432\u0438\u0434\u043e\u0432, \u0432\u0440\u043e\u0434\u0435 \u0437\u0443\u0431\u043d\u044b\u0445 \u0449\u0435\u0442\u043e\u043a - \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0440\u0435\u0430\u043b\u044c\u043d\u043e. \u0422\u0430\u043a \u0447\u0442\u043e \u0435\u0441\u043b\u0438 \u0434\u0430\u0436\u0435 \u043d\u0435 \u0437\u0430\u0432\u043e\u0434\u0438\u0442\u044c \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0432 \u0441\u0432\u043e\u0435\u0439 \u0436\u0438\u0437\u043d\u0438, \u043f\u043e\u0437\u0436\u0435 \u043d\u0435 \u043f\u0440\u0438\u0434\u0451\u0442\u0441\u044f \u0434\u0443\u043c\u0430\u0442\u044c, \u043a\u0430\u043a \u0435\u0433\u043e \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0432\u043e\u0432\u0441\u0435.\n \u041f\u043e\u043c\u043d\u0438 \u044d\u0442\u0438 \u043f\u0440\u043e\u0441\u0442\u044b\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0438 \u0441\u043e\u0432\u0435\u0442\u044b, \u0438 \u0441\u0442\u0440\u043e\u0438\u0442\u044c \u0441\u0432\u043e\u0439 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043e\u0431\u0440\u0430\u0437 \u0436\u0438\u0437\u043d\u0438 \u0431\u0443\u0434\u0435\u0442 \u043b\u0435\u0433\u0447\u0435!"},C.aj,t.c)
C.zm=new H.aA(3,{id:5,title:"\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u0448\u043e\u043f\u043f\u0435\u0440?",text:"\u042d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0435 \u0441\u0443\u043c\u043a\u0438 \u0434\u0430\u0432\u043d\u043e \u0432 \u0442\u0440\u0435\u043d\u0434\u0435 \u0437\u0430 \u0440\u0443\u0431\u0435\u0436\u043e\u043c \u0438 \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u0432\u0441\u0435 \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u044b\u043c\u0438. \u0412\u0441\u0435 \u0431\u043e\u043b\u044c\u0448\u0435 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u0439 \u043e\u0442\u0434\u0430\u044e\u0442 \u043f\u0440\u0435\u0434\u043f\u043e\u0447\u0442\u0435\u043d\u0438\u0435 \u0430\u043a\u0441\u0435\u0441\u0441\u0443\u0430\u0440\u0430\u043c \u0438\u0437 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432. \u0412 \u044d\u0442\u043e\u043c \u043f\u0440\u043e\u0435\u043a\u0442\u0435 \u044f \u043f\u043e\u0441\u0442\u0430\u0440\u0430\u044e\u0441\u044c \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u044c \u043a\u0430\u043a \u044d\u043a\u043e\u0441\u0443\u043c\u043a\u0438, \u043f\u0440\u0438 \u0438\u0445 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0438 \u043b\u044e\u0434\u044c\u043c\u0438, \u0441\u043c\u043e\u0433\u0443\u0442 \u043f\u043e\u043c\u043e\u0447\u044c \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435. \u041d\u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f\u0448\u043d\u0438\u0439 \u0434\u0435\u043d\u044c \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0432\u0430\u0436\u043d\u0435\u0439\u0448\u0438\u0445 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043f\u0440\u043e\u0431\u043b\u0435\u043c \u043d\u0430 \u0417\u0435\u043c\u043b\u0435 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044f \u043c\u0443\u0441\u043e\u0440\u0430, \u0432 \u0447\u0430\u0441\u0442\u043d\u043e\u0441\u0442\u0438 \u043d\u0435\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u044e\u0449\u0438\u0435\u0441\u044f \u043e\u0442\u0445\u043e\u0434\u044b \u0438\u0437 \u043f\u043b\u0430\u0441\u0442\u043c\u0430\u0441\u0441, \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d\u0430 \u0438 \u0440\u0435\u0437\u0438\u043d\u044b, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u0432\u0430\u0436\u0435\u043d \u0432\u043e\u043f\u0440\u043e\u0441 \u043e\u0431 \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u0438 \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d\u043e\u0432\u044b\u0445 \u043f\u0430\u043a\u0435\u0442\u043e\u0432 \u043e\u0434\u043d\u043e\u0440\u0430\u0437\u043e\u0432\u043e\u0433\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u044f. \u0415\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0430\u0445 \u0432\u043e \u0432\u0441\u0435\u043c \u043c\u0438\u0440\u0435 \u043f\u0440\u043e\u0434\u0430\u044e\u0442\u0441\u044f \u0442\u044b\u0441\u044f\u0447\u0438 \u0442\u043e\u043d\u043d \u0442\u0430\u043a\u0438\u0445 \u043f\u0430\u043a\u0435\u0442\u043e\u0432, \u0431\u043e\u043b\u044c\u0448\u0430\u044f \u0447\u0430\u0441\u0442\u044c \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u043d\u0435 \u043f\u043e\u0434\u0432\u0435\u0440\u0433\u0430\u0435\u0442\u0441\u044f \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0435 \u0438 \u0434\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u043c\u0443 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044e, \u0430 \u043f\u0440\u043e\u0441\u0442\u043e \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043d\u0430 \u0441\u0432\u0430\u043b\u043a\u0438. \u0421\u0440\u043e\u043a \u043f\u043e\u043b\u043d\u043e\u0433\u043e \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u043f\u043e\u043b\u0438\u044d\u0442\u0438\u043b\u0435\u043d\u043e\u0432\u043e\u0433\u043e \u043f\u0430\u043a\u0435\u0442\u0430 \u0432 \u0441\u0440\u0435\u0434\u043d\u0435\u043c \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 500 \u043b\u0435\u0442, \u043f\u0440\u0438 \u044d\u0442\u043e\u043c \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442 \u043e\u0442\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0437\u0435\u043c\u043b\u0438 \u0438 \u0433\u0440\u0443\u043d\u0442\u043e\u0432\u044b\u0445 \u0432\u043e\u0434 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u043d\u044b\u043c\u0438 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u0430 \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0438 \u043a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u044f\u043c\u0438 \u043d\u0430 \u043c\u043d\u043e\u0433\u0438\u0435 \u0433\u043e\u0434\u044b \u0432\u043f\u0435\u0440\u0435\u0434. \u041c\u043d\u043e\u0433\u043e\u0440\u0430\u0437\u043e\u0432\u044b\u0435 \u0442\u0440\u044f\u043f\u0438\u0447\u043d\u044b\u0435 \u0441\u0443\u043c\u043a\u0438 \u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u0445\u043e\u0440\u043e\u0448\u0435\u0439 \u0430\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u043e\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u044b\u043c \u043f\u0430\u043a\u0435\u0442\u0430\u043c ,\u0438\u0445 \u043c\u043e\u0436\u043d\u043e \u0434\u043e\u043b\u0433\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c ,\u043f\u043e\u0441\u043b\u0435 \u0438\u0437\u043d\u043e\u0441\u0430 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0435 \u0442\u043a\u0430\u043d\u0438 \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u043f\u0443\u0442\u0435\u043c.\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://dobro.ru/projects/FXQMJRlKFZ-\u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u0430\u044f-\u0441\u0443\u043c\u043a\u0430-\u0448\u043e\u043f\u043f\u0435\u0440"},C.aj,t.c)
C.zu=new H.aA(3,{id:6,title:"\u0412\u0441\u0451 \u043e\u0431 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0445 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430\u0445",text:"\u0417\u0430\u0431\u043e\u0442\u0438\u0442\u044c\u0441\u044f \u043e\u0431 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435 \u043d\u0443\u0436\u043d\u043e \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0434\u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f \u043d\u0430\u0448\u0435\u0439 \u043f\u043b\u0430\u043d\u0435\u0442\u044b \u0434\u043b\u044f \u0431\u0443\u0434\u0443\u0449\u0438\u0445 \u043f\u043e\u043a\u043e\u043b\u0435\u043d\u0438\u0439. \u0414\u0430\u0436\u0435 \u0435\u0441\u043b\u0438 \u0432\u0430\u0441 \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u0443\u0435\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0438\u0431\u044b\u043b\u044c, \u0441\u043b\u0435\u0434\u0443\u0439\u0442\u0435 \u044d\u043a\u043e-\u0442\u0440\u0435\u043d\u0434\u0430\u043c. \u0412 \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044c \u043f\u0435\u0440\u0432\u043e\u043c \u0432\u0435\u043a\u0435 \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u043e \u043b\u044e\u0434\u0435\u0439 \u0441\u0442\u0440\u0435\u043c\u044f\u0442\u0441\u044f \u0432\u0435\u0441\u0442\u0438 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0439 \u043e\u0431\u0440\u0430\u0437 \u0436\u0438\u0437\u043d\u0438. \u041f\u043e\u043a\u0430\u0436\u0438\u0442\u0435, \u0447\u0442\u043e \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u044f \u0432\u0430\u043c \u043d\u0435 \u0431\u0435\u0437\u0440\u0430\u0437\u043b\u0438\u0447\u043d\u0430, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u0432\u043e\u0435\u0432\u0430\u0442\u044c \u0434\u043e\u0432\u0435\u0440\u0438\u0435 \u043f\u043e\u043a\u0443\u043f\u0430\u0442\u0435\u043b\u0435\u0439 \u0438 \u0443\u043b\u0443\u0447\u0448\u0438\u0442\u044c \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u044e \u0431\u0440\u0435\u043d\u0434\u0430. \n\u041a\u0440\u0438\u0442\u0435\u0440\u0438\u0438 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0441\u0442\u0438\n\u041f\u043e\u043b\u043d\u044b\u0439 \u043f\u0435\u0440\u0435\u0445\u043e\u0434 \u043d\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u0443\u044e \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442 \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u0438\u0435 \u043c\u0443\u0441\u043e\u0440\u0430 \u043d\u0430 \u043f\u043b\u0430\u043d\u0435\u0442\u0435. \u042d\u043a\u043e-\u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u043d\u0435 \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u043c\u0443\u0441\u043e\u0440\u043e\u043c. \u041e\u043d\u0430 \u043f\u043e\u0434\u043b\u0435\u0436\u0438\u0442 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0435 \u0438\u043b\u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0440\u0438\u0440\u043e\u0434\u0435. \u0421\u0430\u043c\u043e\u0439 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0439 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0442\u0430\u0440\u0430, \u0441\u0434\u0435\u043b\u0430\u043d\u043d\u0430\u044f \u0438\u0437 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438. \u041d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0438\u0437 \u0433\u043e\u0444\u0440\u043e\u043a\u0430\u0440\u0442\u043e\u043d\u0430 \u0438 \u0431\u0443\u043c\u0430\u0433\u0438.\n\u041f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e\n\u0418\u0437\u0433\u043e\u0442\u043e\u0432\u043b\u0435\u043d\u0438\u0435 \u044d\u043a\u043e-\u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0438 \u043d\u0435 \u0434\u043e\u043b\u0436\u043d\u043e \u0432\u0440\u0435\u0434\u0438\u0442\u044c \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435. \u0420\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u0443\u0435\u0442\u0441\u044f \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u0434\u043b\u044f \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0432\u043e\u0437\u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u043c\u044b\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044b. \u0415\u0441\u043b\u0438 \u0432 \u0445\u043e\u0434\u0435 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0432 \u0430\u0442\u043c\u043e\u0441\u0444\u0435\u0440\u0443 \u0432\u044b\u0434\u0435\u043b\u044f\u044e\u0442\u0441\u044f \u043e\u043f\u0430\u0441\u043d\u044b\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430, \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044f \u043d\u0435 \u0434\u043e\u043b\u0436\u043d\u0430 \u043f\u0440\u0435\u0432\u044b\u0448\u0430\u0442\u044c \u043f\u0440\u0435\u0434\u0435\u043b\u044c\u043d\u043e \u0434\u043e\u043f\u0443\u0441\u0442\u0438\u043c\u044b\u0435 \u043d\u043e\u0440\u043c\u044b.\n\u041f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435\n\u041f\u043e\u0447\u0442\u0438 \u0443 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0443\u043f\u0430\u043a\u043e\u0432\u043e\u0447\u043d\u043e\u0433\u043e \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u0435\u0441\u0442\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438 \u0447\u0438\u0441\u0442\u0430\u044f \u0430\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u0430. \u042d\u043a\u043e-\u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u043c\u043e\u0436\u0435\u0442 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0442\u044c\u0441\u044f \u0434\u043b\u044f \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f, \u043f\u0435\u0440\u0435\u0432\u043e\u0437\u043a\u0438, \u0434\u043e\u0441\u0442\u0430\u0432\u043a\u0438 \u0442\u043e\u0432\u0430\u0440\u043e\u0432. \u041f\u043e \u043f\u0440\u043e\u0447\u043d\u043e\u0441\u0442\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u043c \u0441\u0432\u043e\u0439\u0441\u0442\u0432\u0430\u043c \u043e\u043d\u0430 \u043d\u0435 \u0443\u0441\u0442\u0443\u043f\u0430\u0435\u0442 \u043d\u0435\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u043c \u0430\u043d\u0430\u043b\u043e\u0433\u0430\u043c.\n\u0423\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044f\n\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u043d\u0430\u044f \u0442\u0430\u0440\u0430 \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043c\u0435\u0442\u043e\u0434\u043e\u043c \u043a\u043e\u043c\u043f\u043e\u0441\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u0438 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u044f. \u041e\u043d\u0430 \u043d\u0435 \u043d\u0430\u043d\u043e\u0441\u0438\u0442 \u0432\u0440\u0435\u0434\u0430 \u043b\u044e\u0434\u044f\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0441 \u043d\u0435\u0439 \u0441\u043e\u043f\u0440\u0438\u043a\u0430\u0441\u0430\u044e\u0442\u0441\u044f, \u0438 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435. \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u044b\u0435 \u0432\u0438\u0434\u044b \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430 \u0440\u0430\u0437\u043b\u0430\u0433\u0430\u044e\u0442\u0441\u044f \u043e\u0442 100 \u0434\u043e 1000 \u043b\u0435\u0442. \u0411\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0430\u044f \u0442\u0430\u0440\u0430 \u043c\u043e\u0436\u0435\u0442 \u0440\u0430\u0441\u043f\u0430\u0434\u0430\u0442\u044c\u0441\u044f \u043d\u0430 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b \u0437\u0430 2-3 \u043c\u0435\u0441\u044f\u0446\u0430.\n\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u0432\u043e\u0437\u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u043c\u0430\u044f \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430?\n\u042d\u0442\u043e \u0442\u0430\u0440\u0430, \u0438\u0437\u0433\u043e\u0442\u043e\u0432\u043b\u0435\u043d\u043d\u0430\u044f \u0438\u0437 \u0432\u043e\u0437\u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u043c\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432. \u041d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0431\u0443\u043c\u0430\u0433\u0443 \u0438 \u043a\u0430\u0440\u0442\u043e\u043d \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442 \u0438\u0437 \u0434\u0440\u0435\u0432\u0435\u0441\u0438\u043d\u044b. \u0427\u0442\u043e\u0431\u044b \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u0431\u044b\u043b\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0439, \u043d\u0443\u0436\u043d\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0440\u0435\u0436\u0438\u043c \u0432\u044b\u0440\u0443\u0431\u043a\u0438 \u0434\u0435\u0440\u0435\u0432\u044c\u0435\u0432. \u0412\u043c\u0435\u0441\u0442\u043e \u0432\u044b\u0440\u0443\u0431\u043b\u0435\u043d\u043d\u044b\u0445 \u043b\u0435\u0441\u043e\u0432 \u043d\u0443\u0436\u043d\u043e \u0432\u044b\u0441\u0430\u0436\u0438\u0432\u0430\u0442\u044c \u043d\u043e\u0432\u044b\u0435, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u044e \u043f\u043b\u0430\u043d\u0435\u0442\u044b.\n\u0412\u043e\u0437\u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u043c\u0430\u044f \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u043f\u043e\u0434\u043b\u0435\u0436\u0438\u0442 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0435. \u041f\u043e\u0441\u043b\u0435 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u043c\u043e\u0433\u0443\u0442 \u0438\u0437\u043c\u0435\u043d\u044f\u0442\u044c\u0441\u044f \u0441\u0432\u043e\u0439\u0441\u0442\u0432\u0430 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430. \u041d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0438\u0437 \u043d\u043e\u0432\u043e\u0439 \u0431\u0443\u043c\u0430\u0433\u0438 \u0434\u043b\u044f \u043f\u0438\u0441\u044c\u043c\u0430 \u043f\u043e\u043b\u0443\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0431\u0435\u0440\u0442\u043e\u0447\u043d\u0430\u044f \u0431\u0443\u043c\u0430\u0433\u0430 \u0434\u043b\u044f \u043f\u0438\u0449\u0435\u0432\u044b\u0445 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432. \u0427\u0435\u043c \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e \u0446\u0438\u043a\u043b\u043e\u0432 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438, \u0442\u0435\u043c \u0432\u044b\u0448\u0435 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0441\u0442\u0438 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430.\n\u041f\u0440\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0438\n\u041e\u043a\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044c \u0432 \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u043e\u0439 \u0441\u0440\u0435\u0434\u0435, \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0430\u044f \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u0440\u0430\u0441\u043f\u0430\u0434\u0430\u0435\u0442\u0441\u044f \u0437\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0435\u0441\u044f\u0446\u0435\u0432. \u0412 \u0445\u043e\u0434\u0435 \u0440\u0430\u0441\u043f\u0430\u0434\u0430 \u0432 \u0430\u0442\u043c\u043e\u0441\u0444\u0435\u0440\u0443 \u043d\u0435 \u0432\u044b\u0434\u0435\u043b\u044f\u044e\u0442\u0441\u044f \u0432\u0440\u0435\u0434\u043d\u044b\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430, \u0430 \u043f\u043e\u0447\u0432\u0430 \u043d\u0435 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u044f\u0435\u0442\u0441\u044f. \u0411\u0443\u043c\u0430\u0433\u0430 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u043c \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u043e\u043c. \u0410\u043d\u0430\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0435 \u0441\u0432\u043e\u0439\u0441\u0442\u0432\u0430 \u043c\u043e\u0436\u043d\u043e \u043f\u0440\u0438\u0434\u0430\u0442\u044c \u0438 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0443, \u0435\u0441\u043b\u0438 \u0438\u0437\u043c\u0435\u043d\u0438\u0442\u044c \u0441\u043e\u0441\u0442\u0430\u0432 \u0438\u0441\u0445\u043e\u0434\u043d\u043e\u0433\u043e \u0441\u044b\u0440\u044c\u044f \u0438 \u0442\u0435\u0445\u043d\u043e\u043b\u043e\u0433\u0438\u044e \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0430.\n\u041f\u043e \u043f\u0440\u043e\u0447\u043d\u043e\u0441\u0442\u0438 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0430\u044f \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u043d\u0435 \u0443\u0441\u0442\u0443\u043f\u0430\u0435\u0442 \u043d\u0435\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u043e\u0439. \u041f\u0435\u0440\u0435\u0445\u043e\u0434 \u043d\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u0443\u044e \u0442\u0430\u0440\u0443 \u043d\u0435 \u043f\u0440\u0438\u0432\u0435\u0434\u0435\u0442 \u043a \u0443\u0432\u0435\u043b\u0438\u0447\u0435\u043d\u043d\u044b\u043c \u043f\u043e\u0442\u0435\u0440\u044f\u043c. \u041c\u043d\u0435\u043d\u0438\u0435 \u043e \u0445\u0440\u0443\u043f\u043a\u043e\u0441\u0442\u0438 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u0445 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u043e\u0432 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043c\u0438\u0444\u043e\u043c. \u0414\u043b\u044f \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430 \u0441 \u043f\u043e\u043c\u043e\u0449\u044c\u044e \u043c\u0438\u043a\u0440\u043e\u043e\u0440\u0433\u0430\u043d\u0438\u0437\u043c\u043e\u0432 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044f \u0432\u0440\u0435\u043c\u044f. \u0423\u043f\u0430\u043a\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0442\u043e\u0432\u0430\u0440 \u043d\u0435 \u0431\u0443\u0434\u0435\u0442 \u043f\u043e\u0432\u0440\u0435\u0436\u0434\u0435\u043d \u0432 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u0435 \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438.\n\u0417\u0430\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435\n\u0421\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u043f\u043b\u0430\u043d\u0435\u0442\u0443 \u0447\u0438\u0441\u0442\u043e\u0439 \u0434\u043b\u044f \u0431\u0443\u0434\u0443\u0449\u0438\u0445 \u043f\u043e\u043a\u043e\u043b\u0435\u043d\u0438\u0439 \u043f\u043e\u043c\u043e\u0436\u0435\u0442 \u043f\u0435\u0440\u0435\u0445\u043e\u0434 \u043d\u0430 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0443\u044e \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443. \u0425\u043e\u0442\u044f \u0441\u0435\u0439\u0447\u0430\u0441 \u043d\u0435 \u0443 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430 \u0435\u0441\u0442\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438 \u0447\u0438\u0441\u0442\u044b\u0439 \u0430\u043d\u0430\u043b\u043e\u0433, \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u043e \u043c\u043d\u043e\u0433\u043e \u0432\u0438\u0434\u043e\u0432 \u0441\u044b\u0440\u044c\u044f, \u043f\u043e\u0434\u043b\u0435\u0436\u0430\u0449\u0438\u0445 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0435.\n\u041d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u0438\u0434\u044b \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u043e\u0432\u043e\u0439 \u0442\u0430\u0440\u044b \u043c\u043e\u0436\u043d\u043e \u0437\u0430\u043c\u0435\u043d\u0438\u0442\u044c \u0438\u0437\u0434\u0435\u043b\u0438\u044f\u043c\u0438 \u0438\u0437 \u043a\u0430\u0440\u0442\u043e\u043d\u0430 \u0438 \u0431\u0443\u043c\u0430\u0433\u0438. \u0422\u0430\u043c, \u0433\u0434\u0435 \u044d\u0442\u043e \u043d\u0435\u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0439\u0442\u0435 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0438\u043b\u0438 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b, \u043f\u043e\u0434\u043b\u0435\u0436\u0430\u0449\u0438\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0435. \u0412\u044b \u043f\u043e\u0437\u0430\u0431\u043e\u0442\u0438\u0442\u0435\u0441\u044c \u043e\u0431 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438, \u0441\u043d\u0438\u0437\u0438\u0442\u0435 \u0437\u0430\u0442\u0440\u0430\u0442\u044b \u043d\u0430 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443 \u0442\u043e\u0432\u0430\u0440\u043e\u0432, \u0443\u043b\u0443\u0447\u0448\u0438\u0442\u0435 \u0440\u0435\u043f\u0443\u0442\u0430\u0446\u0438\u044e \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438.\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://www.utupack.ru/other/eco_upack/chto-takoe-ekologichnaja-upakovka/"},C.aj,t.c)
C.zs=new H.aA(3,{id:7,title:"\u041f\u0440\u0438\u0448\u043b\u043e \u0432\u0440\u0435\u043c\u044f \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a\u0438!",text:"\u041a\u0430\u043a \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a?\n\u0412\u0441\u0435 \u043c\u044b \u0441 \u0434\u0435\u0442\u0441\u0442\u0432\u0430 \u0437\u043d\u0430\u0435\u043c, \u0447\u0442\u043e \u0441 \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a\u043e\u043c \u043d\u0443\u0436\u043d\u043e \u0431\u044b\u0442\u044c \u043f\u0440\u0435\u0434\u0435\u043b\u044c\u043d\u043e \u0430\u043a\u043a\u0443\u0440\u0430\u0442\u043d\u044b\u043c, \u0447\u0442\u043e \u0440\u0442\u0443\u0442\u044c - \u043e\u0447\u0435\u043d\u044c \u043e\u043f\u0430\u0441\u043d\u043e\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043d\u0430\u0448\u0435\u0433\u043e \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f. \u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043c\u043d\u043e\u0433\u0438\u0435 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u044f\u0442 \u043d\u0430 \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u044b\u0435 \u0438\u043b\u0438 \u0438\u043d\u0444\u0440\u0430\u043a\u0440\u0430\u0441\u043d\u044b\u0435 \u0442\u0435\u0440\u043c\u043e\u043c\u0435\u0442\u0440\u044b \u0438 \u043e\u0442 \u0433\u0440\u0435\u0445\u0430 \u043f\u043e\u0434\u0430\u043b\u044c\u0448\u0435 \u0445\u043e\u0442\u044f\u0442 \u0438\u0437\u0431\u0430\u0432\u0438\u0442\u044c\u0441\u044f \u043e\u0442 \u0440\u0442\u0443\u0442\u043d\u044b\u0445 \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a\u043e\u0432.\n \n\u0421\u0435\u0438\u0306\u0447\u0430\u0441 \u0440\u0435\u0447\u044c \u043f\u043e\u0438\u0306\u0434\u0435\u0442 \u0438\u043c\u0435\u043d\u043d\u043e \u043e \u0446\u0435\u043b\u043e\u043c, \u043d\u0435\u0440\u0430\u0437\u0431\u0438\u0442\u043e\u043c \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a\u0435.\n\u0420\u0442\u0443\u0442\u044c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043a \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430\u043c 1 \u043a\u043b\u0430\u0441\u0441\u0430 \u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u0438, \u043f\u0440\u043e\u0441\u0442\u043e \u0432\u044b\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u0442\u044c \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a \u0441 \u043e\u0431\u044b\u0447\u043d\u044b\u043c \u043c\u0443\u0441\u043e\u0440\u043e\u043c \u043d\u0435\u043b\u044c\u0437\u044f.\n \n\u0415\u0441\u0442\u044c \u043f\u043e\u043b\u0435\u0437\u043d\u044b\u0438\u0306 \u0441\u0430\u0438\u0306\u0442 www.kudagradusnik.ru \u0441 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0435\u0438\u0306 \u043e \u0442\u043e\u043c, \u043a\u043e\u043c\u0443 \u043c\u043e\u0436\u043d\u043e \u0441\u0434\u0430\u0442\u044c \u043d\u0430 \u0443\u0442\u0438\u043b\u0438\u0437\u0430\u0446\u0438\u044e \u0440\u0442\u0443\u0442\u043d\u044b\u0438\u0306 \u0433\u0440\u0430\u0434\u0443\u0441\u043d\u0438\u043a \u0432 \u0441\u0432\u043e\u0435\u0308\u043c \u0433\u043e\u0440\u043e\u0434\u0435.\n\u041d\u043e \u0434\u0430\u043d\u043d\u044b\u0435 \u043b\u0443\u0447\u0448\u0435 \u043f\u0440\u0435\u0434\u0432\u0430\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u043d\u0430 \u0430\u043a\u0442\u0443\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c: \u044f \u043e\u0431\u0437\u0432\u043e\u043d\u0438\u043b\u0430 \u0443\u043a\u0430\u0437\u0430\u043d\u043d\u044b\u0435 \u043f\u043e \u043d\u0430\u0448\u0435\u043c\u0443 \u0433\u043e\u0440\u043e\u0434\u0443 \u041e\u043c\u0441\u043a\u0443 \u0442\u0440\u0438 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0438, \u0438\u0437 \u043d\u0438\u0445 \u043f\u043e \u0444\u0430\u043a\u0442\u0443 \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0434\u043d\u0430:\n\u041e\u041e\u041e \xab\u041c\u0435\u0440\u043a\xbb\n\u0410\u0434\u0440\u0435\u0441: \u0433. \u041e\u043c\u0441\u043a, \u041a\u043e\u043c\u0431\u0438\u043d\u0430\u0442\u0441\u043a\u0430\u044f 50/2,\n\u0422\u0435\u043b\u0435\u0444\u043e\u043d: 24-68-35, 24-67-38\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://www.instagram.com/p/CFYbR1_Bepe/?igshid=6khyf6vvqvgy\n"},C.aj,t.c)
C.zr=new H.aA(3,{id:8,title:"15 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u0434\u043b\u044f \u0443\u0431\u043e\u0440\u043a\u0438",text:"\u0421\u043e\u0432\u0441\u0435\u043c \u043d\u0435\u043c\u043d\u043e\u0433\u0438\u0435 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u044d\u043a\u043e\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043d\u0430 \u0441\u0430\u043c\u043e\u043c \u0434\u0435\u043b\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u044b. \u041b\u0438\u0448\u044c \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043c\u0430\u0440\u043a\u0438\u0440\u043e\u0432\u043a\u0438 \u2013 \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, Ecocert \u0438\u043b\u0438 \u043d\u0435\u043c\u0435\u0446\u043a\u0430\u044f BDHI \u2013 \u0433\u043e\u0432\u043e\u0440\u044f\u0442 \u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u043e\u043c \u0438 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u043c \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0435. \u0412 \u044d\u0442\u043e\u0442 \u0440\u0430\u0437 \u0440\u0435\u0434\u0430\u043a\u0446\u0438\u044f Recycle \u0432\u044b\u0431\u0440\u0430\u043b\u0430 \u043d\u0430\u0438\u0431\u043e\u043b\u0435\u0435 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0434\u043b\u044f \u0443\u0431\u043e\u0440\u043a\u0438 \u0434\u043e\u043c\u0430.\n\n1.\u0416\u0438\u0434\u043a\u0438\u0439 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0442 \u0441 \u043c\u0430\u0441\u043b\u043e\u043c \u043b\u044c\u043d\u0430 \u0434\u043b\u044f \u043f\u043e\u043b\u0430 Ecover\n\u041e\u0441\u043e\u0431\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u2013 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0445\u043b\u043e\u0440\u0430 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0435\u0434\u043a\u0438\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432. \u0421\u0440\u0435\u0434\u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432, \u043f\u0440\u0435\u0434\u043d\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043d\u044b\u0445 \u0434\u043b\u044f \u043c\u044b\u0442\u044c\u044f \u043f\u043e\u043b\u043e\u0432, \u044d\u0442\u043e \u0440\u0435\u0434\u043a\u043e\u0441\u0442\u044c. \u0416\u0438\u0434\u043a\u0438\u0439 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0442 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u043c \u044d\u0444\u0438\u0440\u043d\u044b\u043c \u043c\u0430\u0441\u043b\u043e\u043c \u0446\u0438\u0442\u0440\u0443\u0441\u043e\u0432\u044b\u0445 \u0438 \u0432 \u0435\u0433\u043e \u0441\u043e\u0441\u0442\u0430\u0432\u0435, \u043f\u043e\u043c\u0438\u043c\u043e \u043c\u044b\u043b\u0430 \u043d\u0430 \u0440\u0430\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u043e\u0441\u043d\u043e\u0432\u0435, \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043c\u0430\u0441\u043b\u043e \u0441\u0435\u043c\u044f\u043d \u043b\u044c\u043d\u0430, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0443\u0445\u0430\u0436\u0438\u0432\u0430\u0435\u0442 \u0437\u0430 \u043d\u0430\u043f\u043e\u043b\u044c\u043d\u044b\u043c \u043f\u043e\u043a\u0440\u044b\u0442\u0438\u0435\u043c \u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u0435\u0433\u043e \u043e\u0442 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u0439. \u0421 \u043f\u043e\u043c\u043e\u0449\u044c\u044e \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0442\u0430 \u043c\u043e\u0436\u043d\u043e \u043c\u044b\u0442\u044c \u0434\u0435\u0440\u0435\u0432\u044f\u043d\u043d\u044b\u0435, \u043a\u0435\u0440\u0430\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0435, \u043c\u0440\u0430\u043c\u043e\u0440\u043d\u044b\u0435, \u0431\u0435\u0442\u043e\u043d\u043d\u044b\u0435 \u043f\u043e\u043b\u044b, \u0430 \u0442\u0430\u043a\u0436\u0435 \u043f\u043e\u043b\u044b, \u043f\u043e\u043a\u0440\u044b\u0442\u044b\u0435 \u043b\u0438\u043d\u043e\u043b\u0435\u0443\u043c\u043e\u043c.\n\u0426\u0435\u043d\u0430: 310 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 1 \u043b\n2. \u041e\u0447\u0438\u0441\u0442\u0438\u0442\u0435\u043b\u044c \u0434\u043b\u044f \u0441\u0442\u0435\u043a\u043e\u043b \u0438 \u0437\u0435\u0440\u043a\u0430\u043b Attitude \n\n\u0412 \u043e\u0442\u043b\u0438\u0447\u0438\u0435 \u043e\u0442 \u043c\u043d\u043e\u0433\u0438\u0445 \u0440\u0430\u0441\u043f\u044b\u043b\u044f\u0435\u043c\u044b\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432, \u043e\u043d \u043d\u0435 \u043d\u0430\u043d\u043e\u0441\u0438\u0442 \u0432\u0440\u0435\u0434\u0430 \u043e\u0437\u043e\u043d\u043e\u0432\u043e\u043c\u0443 \u0441\u043b\u043e\u044e, \u043f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u043d\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u0430\u043c\u043c\u0438\u0430\u043a. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430 \u043a\u043e\u043a\u043e \u0438 \u043b\u0430\u0443\u0440\u0438\u043b \u0433\u043b\u044e\u043a\u043e\u0437\u0438\u0434\u044b, \u0441\u043f\u0438\u0440\u0442, \u0430 \u0432 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440\u043e\u0432 \u2013 \u044d\u0444\u0438\u0440\u043d\u044b\u0435 \u043c\u0430\u0441\u043b\u0430 \u043b\u0430\u0432\u0430\u043d\u0434\u044b \u0438 \u043b\u0430\u0439\u043c\u0430. \u041f\u0440\u043e\u0434\u0443\u043a\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u0446\u0438\u0440\u043e\u0432\u0430\u043d \u043f\u043e \u043a\u0430\u043d\u0430\u0434\u0441\u043a\u043e\u043c\u0443 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0443 EcoLogo \u0438 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0443 \u043e\u0445\u0440\u0430\u043d\u044b \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b \u041a\u0430\u043d\u0430\u0434\u044b. \u041a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b \u044d\u043a\u043e\u043e\u0447\u0438\u0441\u0442\u0438\u0442\u0435\u043b\u044f \u043d\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445, \u0438 \u0438\u043c \u043c\u043e\u0433\u0443\u0442 \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u0432\u0435\u0433\u0430\u043d\u044b. \n\n\u0426\u0435\u043d\u0430: 395 \u0440\u0443\u0431. \n\n\u041e\u0431\u044a\u0435\u043c: 800 \u043c\u043b\n\n3. \u0427\u0438\u0441\u0442\u044f\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043c\u0435\u0442\u0430\u043b\u043b\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0435\u0439 Amway \n\n\u0412 \u0441\u043e\u0441\u0442\u0430\u0432 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0432\u0445\u043e\u0434\u044f\u0442 \u0434\u0432\u0430 \u0432\u0438\u0434\u0430 \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 \u0447\u0438\u0441\u0442\u044f\u0449\u0438\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432: \u0445\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0435 (\u0430\u043d\u0438\u043e\u043d\u043d\u044b\u0435 \u041f\u0410\u0412) \u0438 \u0430\u0431\u0440\u0430\u0437\u0438\u0432\u043d\u044b\u0435. \u041e\u043d\u0438 \u043f\u043e\u043c\u043e\u0433\u0430\u044e\u0442 \u0443\u0441\u0442\u0440\u0430\u043d\u044f\u0442\u044c \u043f\u044f\u0442\u043d\u0430 \u0441 \u0438\u0437\u0434\u0435\u043b\u0438\u0439 \u0438\u0437 \u043c\u0435\u0434\u0438, \u043b\u0430\u0442\u0443\u043d\u0438 \u0438 \u043d\u0435\u0440\u0436\u0430\u0432\u0435\u044e\u0449\u0435\u0439 \u0441\u0442\u0430\u043b\u0438, \u0438 \u043f\u0440\u0438\u0434\u0430\u044e\u0442 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u044f\u043c \u0441\u0438\u044f\u043d\u0438\u0435. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043d\u0435\u0442\u043e\u043a\u0441\u0438\u0447\u043d\u043e, \u043e\u043d\u043e \u043d\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u0435\u0434\u043a\u0438\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432 \u0438 \u0431\u0435\u0440\u0435\u0436\u043d\u043e \u0432\u0437\u0430\u0438\u043c\u043e\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0441 \u043a\u043e\u0436\u0435\u0439 \u0440\u0443\u043a. \u041f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044f Amway \u043d\u0435 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043e\u0440\u0433\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439, \u043d\u043e \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 \u0430\u043a\u0442\u0438\u0432\u043d\u043e \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u044b WWF. \n\n\u0426\u0435\u043d\u0430: 269 \u0440\u0443\u0431. \n\n\u041e\u0431\u044a\u0435\u043c: 200 \u043c\u043b \n \n4. \u0427\u0438\u0441\u0442\u044f\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0442\u0443\u0430\u043b\u0435\u0442\u0430 Klar \n\u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0431\u0435\u0437 \u0443\u0441\u0438\u043b\u0438\u0439 \u0443\u0434\u0430\u043b\u044f\u0435\u0442 \u0441\u0442\u043e\u0439\u043a\u0438\u0435 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u044f, \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0440\u0436\u0430\u0432\u0447\u0438\u043d\u0443 \u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u044c. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432 \u0432\u0445\u043e\u0434\u044f\u0442 \u043c\u043e\u043b\u043e\u0447\u043d\u0430\u044f \u0438 \u043b\u0438\u043c\u043e\u043d\u043d\u0430\u044f \u043a\u0438\u0441\u043b\u043e\u0442\u044b \u0438 \u043c\u044f\u0433\u043a\u0438\u0439 \u041f\u0410\u0412 (\u043a\u0430\u043f\u0440\u0438\u043b \u0433\u043b\u044e\u043a\u043e\u0437\u0438\u0434). \u041f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u043c \u043b\u0438\u043d\u0438\u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 Klar \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043d\u0435\u043c\u0435\u0446\u043a\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f AlmaWin, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0438\u043c\u0435\u0435\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 Ecogarantie. \u042d\u0442\u043e\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430 \u043a\u0430\u043a \u0434\u043b\u044f \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f, \u0442\u0430\u043a \u0438 \u0434\u043b\u044f \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u043c \u0438 \u043d\u0435 \u043d\u0430\u043d\u043e\u0441\u0438\u0442 \u0432\u0440\u0435\u0434 \u0432\u043e\u0434\u043d\u044b\u043c \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u0430\u043c. \n\u0426\u0435\u043d\u0430: 305 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b\n\n5. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0447\u0438\u0441\u0442\u043a\u0438 \u0432\u0430\u043d\u043d\u044b \u0438 \u0434\u0443\u0448\u0430 Sodasan\n\n\u042d\u0442\u043e \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u043e \u043e\u0447\u0438\u0449\u0430\u0435\u0442 \u0440\u0430\u043a\u043e\u0432\u0438\u043d\u044b, \u0432\u0430\u043d\u043d\u044b, \u0434\u0443\u0448\u0435\u0432\u044b\u0435 \u043a\u0430\u0431\u0438\u043d\u044b \u0438 \u043a\u0435\u0440\u0430\u043c\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043f\u043b\u0438\u0442\u043a\u0443. \u041d\u0435 \u043f\u043e\u0432\u0440\u0435\u0436\u0434\u0430\u0435\u0442 \u0438 \u043d\u0435 \u0440\u0430\u0437\u044a\u0435\u0434\u0430\u0435\u0442 \u043f\u0440\u0435\u0434\u043c\u0435\u0442\u044b \u0438\u0437 \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430 \u0438 \u0430\u043a\u0440\u0438\u043b\u0430. \u0423\u0434\u0430\u043b\u044f\u0435\u0442 \u0438\u0437\u0432\u0435\u0441\u0442\u043a\u043e\u0432\u044b\u0439 \u043d\u0430\u043b\u0435\u0442, \u043c\u044b\u043b\u044c\u043d\u044b\u0435 \u0440\u0430\u0437\u0432\u043e\u0434\u044b, \u0434\u0435\u0437\u0438\u043d\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u043d\u0435\u0442 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0413\u041c\u041e, \u0438\u0441\u043a\u0443\u0441\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440\u043e\u0432 \u0438 \u043a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u0435\u0439. \u041b\u0438\u043c\u043e\u043d\u043d\u0430\u044f \u043a\u0438\u0441\u043b\u043e\u0442\u0430 \u0438 \u043e\u0440\u0433\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0443\u043a\u0441\u0443\u0441 \u043f\u0440\u0438\u0434\u0430\u044e\u0442 \u043a\u0435\u0440\u0430\u043c\u0438\u043a\u0435 \u0431\u043b\u0435\u0441\u043a, \u0442\u0435\u043d\u0437\u0438\u0434\u044b \u0441\u0430\u0445\u0430\u0440\u0430 \u043f\u043e\u043c\u043e\u0433\u0430\u044e\u0442 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c\u0441\u044f \u0441 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u044f\u043c\u0438, \u0430 \u0441\u043f\u0438\u0440\u0442 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0434\u0435\u0437\u0438\u043d\u0444\u0438\u0446\u0438\u0440\u0443\u044e\u0449\u0438\u0439 \u044d\u0444\u0444\u0435\u043a\u0442. \u0412 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440\u0430 \u0432 \u043f\u0440\u043e\u0434\u0443\u043a\u0442 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u044b \u044d\u0444\u0438\u0440\u043d\u044b\u0435 \u043c\u0430\u0441\u043b\u0430 \u0446\u0438\u0442\u0440\u0443\u0441\u043e\u0432\u044b\u0445.\n\u0426\u0435\u043d\u0430: 330 \u0440\u0443\u0431.\n\u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b\n\n6. \u041d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u043e\u0435 \u043c\u043e\u044e\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \xab\u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u0439 \u043a\u0430\u043c\u0435\u043d\u044c\xbb \n\n\u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u043e\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043e\u0447\u0438\u0449\u0435\u043d\u0438\u044f \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u0430 \u0442\u0432\u0435\u0440\u0434\u044b\u0445 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0435\u0439. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u043f\u044f\u0442\u044c \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u0432: \u043c\u044b\u043b\u044c\u043d\u044b\u0435 \u0445\u043b\u043e\u043f\u044c\u044f \u0438\u0437 \u043a\u043e\u043a\u043e\u0441\u043e\u0432\u043e\u0433\u043e \u043c\u0430\u0441\u043b\u0430 \u0445\u043e\u043b\u043e\u0434\u043d\u043e\u0433\u043e \u043e\u0442\u0436\u0438\u043c\u0430, \u044d\u0444\u0438\u0440\u043d\u043e\u0435 \u043c\u0430\u0441\u043b\u043e \u0446\u0438\u0442\u0440\u043e\u043d\u0435\u043b\u043b\u044b, \u0440\u0430\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0433\u043b\u0438\u0446\u0435\u0440\u0438\u043d, \u0431\u0435\u043b\u0430\u044f \u0433\u043b\u0438\u043d\u0430 \u0438 \u043c\u0430\u0440\u0441\u0435\u043b\u044c\u0441\u043a\u043e\u0435 \u0437\u0435\u043b\u0435\u043d\u043e\u0435 \u043c\u044b\u043b\u043e \u0438\u0437 \u043e\u043b\u0438\u0432\u043a\u043e\u0432\u043e\u0433\u043e \u043c\u0430\u0441\u043b\u0430. \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u0439 \u043a\u0430\u043c\u0435\u043d\u044c \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u0435\u043d \u0434\u043b\u044f \u0434\u0435\u0442\u0435\u0439, \u043e\u043d \u0431\u0435\u0440\u0435\u0436\u043d\u043e \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043a \u043a\u043e\u0436\u0435 \u0440\u0443\u043a \u0438 \u0445\u043e\u0440\u043e\u0448\u043e \u043e\u0447\u0438\u0449\u0430\u0435\u0442 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u044f \u0441 \u043c\u0435\u0442\u0430\u043b\u043b\u0430, \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0438, \u0434\u0435\u0440\u0435\u0432\u0430, \u043a\u0435\u0440\u0430\u043c\u0438\u043a\u0438, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0441 \u043e\u0434\u0435\u0436\u0434\u044b \u0438 \u043e\u0431\u0443\u0432\u0438. \u041d\u0435\u043c\u0435\u0446\u043a\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f Zelinsky Universal-Stein, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442 \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u0439 \u043a\u0430\u043c\u0435\u043d\u044c, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 20 \u043b\u0435\u0442, \u0438 \u0438\u043c\u0435\u0435\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u044b EMAS \u0438 EMPA. \n\u0426\u0435\u043d\u0430: 1370 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u0433\n7. \u042d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043a\u0440\u0435\u043c\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u043e\u0435 \u0447\u0438\u0441\u0442\u044f\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e Ecover \n\u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0438\u043c\u0435\u0435\u0442 \u0442\u0435\u043a\u0441\u0442\u0443\u0440\u0443 \u043f\u043e\u043b\u0443\u0436\u0438\u0434\u043a\u043e\u0433\u043e \u043a\u0440\u0435\u043c\u0430. \u041e\u043d\u043e \u0445\u043e\u0440\u043e\u0448\u043e \u0443\u0434\u0430\u043b\u044f\u0435\u0442 \u043d\u0430\u043a\u0438\u043f\u044c, \u0440\u0430\u0437\u043b\u0438\u0447\u043d\u044b\u0435 \u043f\u044f\u0442\u043d\u0430, \u043d\u0430\u043b\u0435\u0442, \u0436\u0438\u0440 \u0438 \u0438\u0437\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043e\u0442 \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u043d\u044b\u0445 \u0437\u0430\u043f\u0430\u0445\u043e\u0432, \u0445\u043e\u0442\u044f \u0441\u0430\u043c\u043e, \u043f\u0440\u0438 \u044d\u0442\u043e\u043c, \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043f\u0430\u0445\u043d\u0435\u0442. \u041a\u0440\u0435\u043c\u043e\u043c \u043c\u043e\u0436\u043d\u043e \u0447\u0438\u0441\u0442\u0438\u0442\u044c \u0432\u0430\u043d\u043d\u044b, \u0440\u0430\u043a\u043e\u0432\u0438\u043d\u044b, \u043a\u0435\u0440\u0430\u043c\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043f\u043b\u0438\u0442\u043a\u0443, \u043a\u0443\u0445\u043e\u043d\u043d\u044b\u0435 \u043f\u043b\u0438\u0442\u044b, \u0445\u043e\u043b\u043e\u0434\u0438\u043b\u044c\u043d\u0438\u043a\u0438, \u043a\u0430\u0441\u0442\u0440\u044e\u043b\u0438, \u0441\u043a\u043e\u0432\u043e\u0440\u043e\u0434\u043a\u0438 \u0438 \u043f\u0440. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u0434\u043b\u044f \u0434\u0435\u0442\u0435\u0439, \u043e\u043d\u043e \u043e\u0442\u043b\u0438\u0447\u043d\u043e \u0441\u043c\u044b\u0432\u0430\u0435\u0442\u0441\u044f, \u043d\u0435 \u0432\u0440\u0435\u0434\u0438\u0442 \u043a\u043e\u0436\u0435 \u0438 \u043d\u0435 \u0432\u044b\u0437\u044b\u0432\u0430\u0435\u0442 \u0430\u043b\u043b\u0435\u0440\u0433\u0438\u0438. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u2013 \u043f\u043e\u0440\u043e\u0448\u043e\u043a \u043c\u0435\u043b\u0430, \u043d\u0435\u0438\u043e\u043d\u043d\u044b\u0435 \u041f\u0410\u0412, \u0433\u043b\u0438\u0446\u0435\u0440\u0438\u043d, \u0433\u043b\u0438\u043d\u0430 \u0438 \u0432\u043e\u0434\u0430. \n\u0426\u0435\u043d\u0430: 225 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b\n8. \u042d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0447\u0438\u0441\u0442\u044f\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043a\u0443\u0445\u043d\u0438 \u0438 \u0434\u0443\u0445\u043e\u0432\u043e\u043a Orange House \n\u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043f\u043e\u0434\u0445\u043e\u0434\u0438\u0442 \u0434\u043b\u044f \u043c\u044b\u0442\u044c\u044f \u0433\u0430\u0437\u043e\u0432\u044b\u0445 \u043f\u043b\u0438\u0442, \u0434\u0443\u0445\u043e\u0432\u043e\u043a, \u0433\u0440\u0438\u043b\u0435\u0439, \u043c\u0438\u043a\u0440\u043e\u0432\u043e\u043b\u043d\u043e\u0432\u044b\u0445 \u043f\u0435\u0447\u0435\u0439, \u043f\u043e\u0441\u0443\u0434\u044b \u0438\u0437 \u043d\u0435\u0440\u0436\u0430\u0432\u0435\u044e\u0449\u0435\u0439 \u0441\u0442\u0430\u043b\u0438, \u0444\u0430\u0440\u0444\u043e\u0440\u0430 \u0438 \u043a\u0435\u0440\u0430\u043c\u0438\u043a\u0438. \u041e\u0442\u043b\u0438\u0447\u043d\u043e \u0443\u0434\u0430\u043b\u044f\u0435\u0442 \u0436\u0438\u0440 \u0438 \u043f\u044f\u0442\u043d\u0430 \u043e\u0440\u0433\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f. \u041d\u0435 \u043e\u0431\u0440\u0430\u0437\u0443\u0435\u0442 \u0440\u0430\u0437\u0432\u043e\u0434\u043e\u0432 \u0438 \u043f\u0440\u0438\u0434\u0430\u0435\u0442 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u044f\u043c \u0431\u043b\u0435\u0441\u043a \u0438 \u043f\u0440\u0438\u044f\u0442\u043d\u044b\u0439 \u0430\u0440\u043e\u043c\u0430\u0442. \u041e\u0431\u043b\u0430\u0434\u0430\u0435\u0442 \u0430\u043d\u0442\u0438\u0431\u0430\u043a\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u043c \u044d\u0444\u0444\u0435\u043a\u0442\u043e\u043c. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430 \u0432\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u043e\u0435 \u0430\u043f\u0435\u043b\u044c\u0441\u0438\u043d\u043e\u0432\u043e\u0435 \u043c\u0430\u0441\u043b\u043e \u0445\u043e\u043b\u043e\u0434\u043d\u043e\u0433\u043e \u043e\u0442\u0436\u0438\u043c\u0430, \u0441\u043f\u0438\u0440\u0442, \u0441\u043e\u0434\u0430 \u0438 \u041f\u0410\u0412 \u0438\u0437 \u043a\u043e\u043a\u043e\u0441\u043e\u0432\u043e\u0433\u043e \u043c\u0430\u0441\u043b\u0430. \u0422\u0430\u0439\u0432\u0430\u043d\u044c\u0441\u043a\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f Orange House \u0432\u044b\u043f\u0443\u0441\u043a\u0430\u0435\u0442 \u043d\u0435\u0442\u043e\u043a\u0441\u0438\u0447\u043d\u0443\u044e \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438 \u0447\u0438\u0441\u0442\u0443\u044e \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044e, \u0441\u043e\u0441\u0442\u0430\u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0440\u0438\u0440\u043e\u0434\u0435. \u0413\u043b\u0430\u0432\u043d\u044b\u0439 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u0430 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u2013 \u0430\u043f\u0435\u043b\u044c\u0441\u0438\u043d\u043e\u0432\u043e\u0435 \u043c\u0430\u0441\u043b\u043e, \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0449\u0435\u0435 \u0432\u0441\u0435 \u0430\u043d\u0442\u0438\u0431\u0430\u043a\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0438 \u0445\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430. \n\u0426\u0435\u043d\u0430: 490 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 450 \u043c\u043b \n9. \u041e\u0431\u0435\u0437\u0436\u0438\u0440\u0438\u0432\u0430\u044e\u0449\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043f\u043b\u0438\u0442\u044b \u0441 \u044d\u0444\u0438\u0440\u043d\u044b\u043c \u043c\u0430\u0441\u043b\u043e\u043c \u043b\u0438\u043c\u043e\u043d\u0430 Ecodoo \n\u042d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u043e \u0443\u0441\u0442\u0440\u0430\u043d\u044f\u0435\u0442 \u0436\u0438\u0440 \u0438 \u043a\u043e\u043f\u043e\u0442\u044c \u0441 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u043a\u0443\u0445\u043e\u043d\u043d\u044b\u0445 \u043f\u043b\u0438\u0442, \u0434\u0443\u0445\u043e\u0432\u044b\u0445 \u0448\u043a\u0430\u0444\u043e\u0432, \u043c\u0438\u043a\u0440\u043e\u0432\u043e\u043b\u043d\u043e\u0432\u044b\u0445 \u043f\u0435\u0447\u0435\u0439 \u0438 \u0433\u0440\u0438\u043b\u0435\u0439. \u0424\u043e\u0440\u043c\u0443\u043b\u0430 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043d\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u0441\u0438\u043b\u044c\u043d\u044b\u0445 \u043a\u0438\u0441\u043b\u043e\u0442, \u0430\u043c\u043c\u0438\u0430\u043a\u0430, \u043a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u0435\u0439 \u0438 \u0445\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440\u043e\u0432. \u041a\u0440\u043e\u043c\u0435 \u0442\u043e\u0433\u043e, \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0430 \u0438\u043c\u0435\u0435\u0442 \u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u043a\u0443 \u043e\u0442 \u0434\u0435\u0442\u0435\u0439. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u2013 \u0440\u0430\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u041f\u0410\u0412, \u043a\u0430\u043c\u0435\u0434\u044c \u0440\u043e\u0436\u043a\u043e\u0432\u043e\u0433\u043e \u0434\u0435\u0440\u0435\u0432\u0430, \u0432\u043e\u0434\u0430 \u0438 \u044d\u0444\u0438\u0440\u043d\u044b\u0435 \u043c\u0430\u0441\u043b\u0430 \u043b\u0438\u043c\u043e\u043d\u044b, \u0430\u043f\u0435\u043b\u044c\u0441\u0438\u043d\u0430 \u0438 \u043f\u0435\u0442\u0438\u0442\u0433\u0440\u0435\u0439\u043d\u0430. \u0412\u0441\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 Ecodoo \u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u043c\u0438 \u0438 \u0438\u043c\u0435\u044e\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 ECOCERT. \n\u0426\u0435\u043d\u0430: 375 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b\n10. \u0416\u0438\u0434\u043a\u043e\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u043d\u0430\u043a\u0438\u043f\u0438 \u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043a\u043e\u0432\u044b\u0445 \u043e\u0442\u043b\u043e\u0436\u0435\u043d\u0438\u0439 Klar \n\u0421\u043e\u0437\u0434\u0430\u043d\u043e \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u043d\u0430\u043a\u0438\u043f\u0438 \u0441 \u043f\u043e\u0441\u0443\u0434\u044b, \u0441\u0442\u0438\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u0438 \u043f\u043e\u0441\u0443\u0434\u043e\u043c\u043e\u0435\u0447\u043d\u044b\u0445 \u043c\u0430\u0448\u0438\u043d. \u0422\u0430\u043a\u0436\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0445\u043e\u0440\u043e\u0448\u043e \u0443\u0434\u0430\u043b\u044f\u0435\u0442 \u0438\u0437\u0432\u0435\u0441\u0442\u043a\u043e\u0432\u044b\u0439 \u043d\u0430\u043b\u0435\u0442 \u0441 \u043a\u0430\u0444\u0435\u043b\u044f, \u0440\u0430\u043a\u043e\u0432\u0438\u043d \u0438 \u043a\u0430\u0444\u0435\u043b\u044c\u043d\u043e\u0439 \u043f\u043b\u0438\u0442\u043a\u0438. \u041e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u0431\u043b\u0435\u0441\u0442\u044f\u0449\u0438\u043c\u0438 \u0438 \u0433\u043b\u0430\u0434\u043a\u0438\u043c\u0438. \u0412 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0440\u0430\u0441\u0442\u0432\u043e\u0440\u0438\u0442\u0435\u043b\u044f \u043d\u0430\u043a\u0438\u043f\u0438 \u0432 \u0436\u0438\u0434\u043a\u043e\u0441\u0442\u044c \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u0430 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u0430\u044f \u043b\u0438\u043c\u043e\u043d\u043d\u0430\u044f \u043a\u0438\u0441\u043b\u043e\u0442\u0430, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0441\u043c\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0432\u043e\u0434\u043e\u0439 \u0438 \u043d\u0435 \u0432\u044b\u0437\u044b\u0432\u0430\u0435\u0442 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u044f. \u0412 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435 \u043d\u0435\u0442 \u043e\u0442\u0434\u0443\u0448\u0435\u043a, \u043a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u0435\u0439, \u0445\u043b\u043e\u0440\u0430 \u0438 \u0441\u0438\u043d\u0442\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043a\u0438\u0441\u043b\u043e\u0442. \u041e\u043d\u043e \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u0434\u043b\u044f \u0432\u0441\u0435\u0445 \u0447\u043b\u0435\u043d\u043e\u0432 \u0441\u0435\u043c\u044c\u0438 \u0438 \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u043e. \n\u0426\u0435\u043d\u0430: 285 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b \n11. \u041f\u0435\u043d\u0430 \u0434\u043b\u044f \u0447\u0438\u0441\u0442\u043a\u0438 \u043a\u043e\u0432\u0440\u043e\u0432 Nordland \n\u041f\u0435\u043d\u0430 \u043e\u0431\u043b\u0430\u0434\u0430\u0435\u0442 \u043c\u0438\u043a\u0440\u043e\u0430\u043a\u0442\u0438\u0432\u043d\u044b\u043c\u0438 \u0441\u0432\u043e\u0439\u0441\u0442\u0432\u0430\u043c\u0438. \u041e\u043d\u0430 \u043f\u0440\u043e\u043d\u0438\u043a\u0430\u0435\u0442 \u0432\u0433\u043b\u0443\u0431\u044c \u0432\u043e\u043b\u043e\u043a\u043e\u043d \u0442\u043a\u0430\u043d\u0435\u0439 \u0438 \u043e\u0447\u0438\u0449\u0430\u0435\u0442 \u0438\u0445 \u0434\u043e \u043e\u0441\u043d\u043e\u0432\u0430\u043d\u0438\u044f \u043e\u0442 \u043f\u044b\u043b\u0438, \u0433\u0440\u044f\u0437\u0438, \u0436\u0438\u0440\u0430 \u0438 \u0441\u043b\u0435\u0434\u043e\u0432 \u043d\u0438\u043a\u043e\u0442\u0438\u043d\u0430. \u041f\u0440\u0435\u0434\u043d\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u0430 \u0434\u043b\u044f \u0447\u0438\u0441\u0442\u043a\u0438 \u043a\u043e\u0432\u0440\u043e\u0432, \u043a\u043e\u0432\u0440\u043e\u0432\u044b\u0445 \u043f\u043e\u043a\u0440\u044b\u0442\u0438\u0439, \u043c\u044f\u0433\u043a\u043e\u0439 \u043c\u0435\u0431\u0435\u043b\u0438 \u0438 \u0441\u0430\u043b\u043e\u043d\u043e\u0432 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043d\u0435 \u0432\u043b\u0438\u044f\u0435\u0442 \u043d\u0430 \u043e\u043a\u0440\u0430\u0441\u043a\u0443 \u0442\u043a\u0430\u043d\u0435\u0439 \u0438 \u043f\u0440\u0438\u0434\u0430\u0435\u0442 \u0442\u043a\u0430\u043d\u044f\u043c \u0441\u0432\u0435\u0436\u0435\u0441\u0442\u044c, \u0430 \u0431\u043e\u043b\u0435\u0435 90% \u0435\u0433\u043e \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u0432 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b. \n\u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044e\u0442 \u0430\u043d\u0438\u043e\u043d\u043d\u044b\u0435 \u0438 \u043d\u0435\u0438\u043e\u043d\u043d\u044b\u0435 \u041f\u0410\u0412, \u0441\u043e\u043b\u044c \u0438 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440. \u0418\u0442\u0430\u043b\u044c\u044f\u043d\u0441\u043a\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f Nordland \u0441\u043e\u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u0442\u0440\u0435\u0431\u043e\u0432\u0430\u043d\u0438\u044f\u043c \u0415\u0432\u0440\u043e\u0441\u043e\u044e\u0437\u0430. \u0415\u0435 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044f \u043d\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0438 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0439 \u0434\u043b\u044f \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 \u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u044b. \n\u0426\u0435\u043d\u0430: 262 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 600 \u043c\u043b\n12. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u043f\u043b\u0435\u0441\u0435\u043d\u0438 Naturally its clean \n\u0411\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u043e\u0447\u0438\u0449\u0430\u0435\u0442 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0435\u0439 (\u0431\u0435\u0442\u043e\u043d, \u043f\u043b\u0430\u0441\u0442\u0438\u043a, \u0442\u043a\u0430\u043d\u0438, \u0433\u0438\u043f\u0441\u043e\u043a\u0430\u0440\u0442\u043e\u043d, \u0434\u0435\u0440\u0435\u0432\u043e), \u0443\u0431\u0438\u0440\u0430\u044f \u0441 \u043d\u0438\u0445 \u043f\u043b\u0435\u0441\u0435\u043d\u044c \u0438 \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u043d\u044b\u0439 \u0437\u0430\u043f\u0430\u0445. \u0417\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u043e\u0442 \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u043e\u0433\u043e \u0432\u043e\u0437\u043d\u0438\u043a\u043d\u043e\u0432\u0435\u043d\u0438\u044f \u043f\u043b\u0435\u0441\u0435\u043d\u0438. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044e\u0442 \u0440\u0430\u0441\u0442\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0444\u0435\u0440\u043c\u0435\u043d\u0442\u044b, \u0440\u0430\u0441\u0449\u0435\u043f\u043b\u044f\u044e\u0449\u0438\u0435 \u043f\u043b\u0435\u0441\u043d\u0435\u0432\u044b\u0435 \u0433\u0440\u0438\u0431\u043a\u0438, \u043c\u044f\u0433\u043a\u0438\u0439 \u041f\u0410\u0412 \u0438\u0437 \u043c\u0430\u0441\u043b\u0430 \u043a\u043e\u043a\u043e\u0441\u0430 \u0438 \u043e\u0442\u0434\u0443\u0448\u043a\u0430 \u0438\u0437 \u044d\u0444\u0438\u0440\u043d\u043e\u0433\u043e \u043c\u0430\u0441\u043b\u0430 \u0446\u0438\u0442\u0440\u0443\u0441\u043e\u0432\u044b\u0445. \n\u0410\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f ChemFree Solutions \u043c\u043d\u043e\u0433\u043e \u043b\u0435\u0442 \u0441\u043b\u0435\u0434\u0443\u0435\u0442 \u0437\u0435\u043b\u0435\u043d\u043e\u043c\u0443 \u043e\u0431\u0440\u0430\u0437\u0443 \u0436\u0438\u0437\u043d\u0438. \u041e\u043d\u0430 \u0443\u0434\u0435\u043b\u044f\u0435\u0442 \u0431\u043e\u043b\u044c\u0448\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0435 \u043e\u0442\u0445\u043e\u0434\u043e\u0432, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0435\u0435 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0438\u043c\u0435\u044e\u0442 \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443 \u0438\u0437 \u043b\u0435\u0433\u043a\u043e \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u043c\u043e\u0433\u043e \u043f\u043b\u0430\u0441\u0442\u0438\u043a\u0430. \u0412\u0441\u0435 \u043e\u043d\u0438 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b \u0434\u043b\u044f \u043b\u044e\u0434\u0435\u0439 \u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u044b. \n\u0426\u0435\u043d\u0430: 441 \u0440\u0443\u0431.  \u041e\u0431\u044a\u0435\u043c: 473 \u043c\u043b\n13. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u043f\u044b\u043b\u0438 Etamine \n\u041e\u0447\u0438\u0449\u0430\u0435\u0442 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0442\u0432\u0435\u0440\u0434\u044b\u0445 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0435\u0439 \u043e\u0442 \u0433\u0440\u044f\u0437\u0438 \u0438 \u043f\u044b\u043b\u0438, \u0438\u043c\u0435\u0435\u0442 \u0430\u043d\u0442\u0438\u0441\u0442\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u044d\u0444\u0444\u0435\u043a\u0442. \u0424\u043e\u0440\u043c\u0443\u043b\u0430 \xab\u0441\u0432\u044f\u0437\u044b\u0432\u0430\u043d\u0438\u044f \u0433\u0440\u044f\u0437\u0438\xbb \u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0435\u0442 \u043f\u044b\u043b\u044c \u043d\u0430 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u0441\u0430\u043b\u0444\u0435\u0442\u043a\u0438 \u0438 \u0441\u043f\u043e\u0441\u043e\u0431\u0441\u0442\u0432\u0443\u0435\u0442 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043e\u0447\u0438\u0449\u0435\u043d\u0438\u044e \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0435\u0439. \u041f\u0440\u0435\u0434\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442 \u043c\u0435\u0431\u0435\u043b\u044c \u043e\u0442 \u043e\u0441\u0435\u0434\u0430\u043d\u0438\u044f \u043f\u044b\u043b\u0438. \u041f\u0440\u043e\u0434\u0443\u043a\u0442 \u043d\u0435 \u043d\u0443\u0436\u043d\u043e \u0441\u043c\u044b\u0432\u0430\u0442\u044c. \u0412 \u0435\u0433\u043e \u0441\u043e\u0441\u0442\u0430\u0432\u0435 \u041f\u0410\u0412 \u0438\u0437 \u043f\u0430\u043b\u044c\u043c\u043e\u0432\u043e\u0433\u043e \u043c\u0430\u0441\u043b\u0430 \u0438 \u0441\u0430\u0445\u0430\u0440\u0430, \u044d\u0444\u0438\u0440\u043d\u044b\u0435 \u043e\u0440\u0433\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043c\u0430\u0441\u043b\u0430 \u044d\u0432\u043a\u0430\u043b\u0438\u043f\u0442\u0430 \u0438 \u043c\u044f\u0442\u044b, \u043f\u0447\u0435\u043b\u0438\u043d\u044b\u0439 \u0432\u043e\u0441\u043a \u0438 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u043a\u043e\u043d\u0441\u0435\u0440\u0432\u0430\u043d\u0442 \u0441\u043e\u0440\u0431\u0430\u0442 \u043a\u0430\u043b\u0438\u044f. \u0418\u043c\u0435\u0435\u0442 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 ECOCERT \u0438 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u0435\u043d \u0434\u043b\u044f \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f \u0438 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b. \n\u0426\u0435\u043d\u0430: 703 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 1 \u043b\n14. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0447\u0438\u0441\u0442\u043a\u0438 \u043c\u0435\u0431\u0435\u043b\u0438 \u0441 \u0441\u043e\u0441\u043d\u043e\u0432\u044b\u043c \u043c\u0430\u0441\u043b\u043e\u043c Etamine \n\u041f\u043e\u0434\u0445\u043e\u0434\u0438\u0442 \u0434\u043b\u044f \u043e\u0447\u0438\u0449\u0435\u043d\u0438\u044f \u043c\u0435\u0431\u0435\u043b\u0438 \u0438\u0437 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0434\u0435\u0440\u0435\u0432\u0430. \u0421\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441 \u0440\u0430\u0437\u043b\u0438\u0447\u043d\u044b\u043c\u0438 \u043f\u044f\u0442\u043d\u0430\u043c\u0438, \u0430 \u0442\u0430\u043a\u0436\u0435 \u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u0442 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u0438\u0445 \u043e\u0442 \u0432\u043e\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u0432\u0440\u0435\u043c\u0435\u043d\u0438. \u041f\u043e\u0434\u0433\u043e\u0442\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u043c\u0435\u0431\u0435\u043b\u044c \u043a \u043d\u0430\u043d\u0435\u0441\u0435\u043d\u0438\u044e \u0432\u043e\u0441\u043a\u0430. \u041d\u0435 \u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u043f\u043e\u0441\u043b\u0435 \u0441\u0435\u0431\u044f \u043b\u0438\u043f\u043a\u043e\u0439 \u043f\u043b\u0435\u043d\u043a\u0438, \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u0438 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u043e. \u0412 \u0441\u043e\u0441\u0442\u0430\u0432 \u0432\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u043a\u0438\u043f\u0438\u0434\u0430\u0440, \u044d\u0444\u0438\u0440\u043d\u044b\u0435 \u043c\u0430\u0441\u043b\u0430 \u0430\u043f\u0435\u043b\u044c\u0441\u0438\u043d\u0430 \u0438 \u0441\u043e\u0441\u043d\u044b. \n\u0426\u0435\u043d\u0430: 886 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 500 \u043c\u043b\n15.\u042d\u043a\u043e\u0433\u0435\u043b\u044c \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u0437\u0430\u0441\u043e\u0440\u043e\u0432 \u0432 \u043a\u0430\u043d\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u043e\u043d\u043d\u044b\u0445 \u0442\u0440\u0443\u0431\u0430\u0445 Nature clean \n\u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u0434\u043b\u044f \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f \u0437\u0430\u0441\u043e\u0440\u043e\u0432 \u0438\u0437 \u0442\u0440\u0443\u0431 \u0441\u043e\u0441\u0442\u043e\u044f\u0442 \u0438\u0437 \u0445\u043b\u043e\u0440\u043e\u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0445 \u043e\u0442\u0431\u0435\u043b\u0438\u0432\u0430\u0442\u0435\u043b\u0435\u0439 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043d\u044b\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432, \u043e\u043d\u0438 \u043e\u0447\u0435\u043d\u044c \u043e\u043f\u0430\u0441\u043d\u044b \u0434\u043b\u044f \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f \u0438 \u0432\u044b\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u0438\u043b\u044c\u043d\u044b\u0435 \u0430\u043b\u043b\u0435\u0440\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438. \u041d\u043e \u0432 \u044d\u0442\u043e\u043c \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435 \u0432\u043c\u0435\u0441\u0442\u043e \u0445\u043b\u043e\u0440\u0430 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0442\u0441\u044f \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0435 \u044d\u043d\u0437\u0438\u043c\u044b, \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043d\u044b\u0435 \u0438\u0437 \u0431\u0430\u043a\u0442\u0435\u0440\u0438\u0439, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u0434\u043b\u044f \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u043e\u0440\u0433\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043c\u0443\u0441\u043e\u0440\u0430. \u0421\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043d\u0435 \u0442\u043e\u043a\u0441\u0438\u0447\u043d\u043e, \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e \u0434\u043b\u044f \u0434\u0435\u0442\u0435\u0439, \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u043e. \u041e\u043d\u043e \u043d\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445, \u043d\u0435 \u0438\u043c\u0435\u0435\u0442 \u0437\u0430\u043f\u0430\u0445\u0430 \u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0438\u0442 \u0434\u043b\u044f \u043b\u044e\u0431\u044b\u0445 \u0432\u0438\u0434\u043e\u0432 \u0442\u0440\u0443\u0431. \n\u0426\u0435\u043d\u0430: 375 \u0440\u0443\u0431. \u041e\u0431\u044a\u0435\u043c: 1 \u043b\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a:  https://recyclemag.ru/article/15-ekologichnyh-sredstv-dlja-uborki"},C.aj,t.c)
C.zo=new H.aA(3,{id:9,title:"\u041e\u0442\u0441\u0442\u0438\u0440\u0430\u0442\u044c \u0432\u0441\u0451 \u043f\u0440\u0438 30 \u0433\u0440\u0430\u0434\u0443\u0441\u0430\u0445? \u0412\u043e\u0437\u043c\u043e\u0436\u043d\u043e!",text:"\u041b\u0430\u0439\u0444\u0445\u0430\u043a: \u043a\u0430\u043a \u043e\u0442\u0441\u0442\u0438\u0440\u0430\u0442\u044c \u043b\u044e\u0431\u044b\u0435 \u043f\u044f\u0442\u043d\u0430 \u043f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435 \n\u041c\u043d\u043e\u0433\u0438\u0435 \u043e\u043f\u0430\u0441\u0430\u044e\u0442\u0441\u044f \u0441\u0442\u0438\u0440\u0430\u0442\u044c \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u043a \u0432\u044b\u0441\u043e\u043a\u0438\u043c \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0430\u043c \u0442\u043a\u0430\u043d\u0438. \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e, \u043e\u0434\u043d\u0430 \u0432\u0435\u0434\u044c \u043c\u043e\u0436\u0435\u0442 \xab\u0441\u0435\u0441\u0442\u044c\xbb, \u0434\u0440\u0443\u0433\u0430\u044f \u2014 \u0432\u044b\u0446\u0432\u0435\u0441\u0442\u0438, \u0432 \u043e\u0431\u0449\u0435\u043c, \u0438\u043d\u043e\u0433\u0434\u0430 \u0431\u0435\u0437 \u0440\u0443\u0447\u043d\u043e\u0439 \u0441\u0442\u0438\u0440\u043a\u0438 \u043d\u0435 \u043e\u0431\u043e\u0439\u0442\u0438\u0441\u044c. \u0412\u043f\u0440\u043e\u0447\u0435\u043c, \u0435\u0441\u0442\u044c \u0441\u043f\u043e\u0441\u043e\u0431 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e \u043f\u043e\u0441\u0442\u0438\u0440\u0430\u0442\u044c \u0432\u0435\u0449\u044c \u043f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435. \u041a\u0430\u043a\u043e\u0439? \u041d\u0430\u0443\u043a\u0430 \u0437\u043d\u0430\u0435\u0442 \u043e\u0442\u0432\u0435\u0442!\n\u0415\u0441\u0442\u044c \u0434\u0432\u0435 \u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u0438, \u043f\u043e\u0434\u0441\u0442\u0435\u0440\u0435\u0433\u0430\u044e\u0449\u0438\u0445 \u0431\u0435\u043b\u044c\u0451 \u043f\u0440\u0438 \u0441\u0442\u0438\u0440\u043a\u0435 \u0432 \u0433\u043e\u0440\u044f\u0447\u0435\u0439 \u0432\u043e\u0434\u0435. \u0412\u043e\u2011\u043f\u0435\u0440\u0432\u044b\u0445, \u043e\u0434\u0435\u0436\u0434\u0430 \u043c\u043e\u0436\u0435\u0442 \xab\u0441\u0435\u0441\u0442\u044c\xbb, \u0442\u043e \u0435\u0441\u0442\u044c \u0443\u043c\u0435\u043d\u044c\u0448\u0438\u0442\u044c\u0441\u044f \u0432 \u0440\u0430\u0437\u043c\u0435\u0440\u0430\u0445 (\u044d\u0442\u043e \u043a\u0430\u0441\u0430\u0435\u0442\u0441\u044f, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0448\u0435\u0440\u0441\u0442\u044f\u043d\u044b\u0445 \u0438\u0437\u0434\u0435\u043b\u0438\u0439), \u0430 \u0432\u043e-\u0432\u0442\u043e\u0440\u044b\u0445, \u043e\u043d\u0430 \u043c\u043e\u0436\u0435\u0442 \u043e\u043a\u0440\u0430\u0441\u0438\u0442\u044c \u0434\u0440\u0443\u0433\u0443\u044e \u043e\u0434\u0435\u0436\u0434\u0443, \u0442\u0430\u043a\u0438\u043c \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u043f\u043e\u0442\u0435\u0440\u044f\u0432 \u0447\u0430\u0441\u0442\u044c \u043a\u0440\u0430\u0441\u043a\u0438 \u0438 \u043f\u043e\u043b\u0438\u043d\u044f\u0432. \u041d\u0438 \u0442\u043e, \u043d\u0438 \u0434\u0440\u0443\u0433\u043e\u0435, \u043e\u0434\u0435\u0436\u0434\u0443 \u043d\u0435 \u043a\u0440\u0430\u0441\u0438\u0442. \n\u0412\u043e\u0442, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u043a\u0430\u043a \u0432\u044b\u0433\u043b\u044f\u0434\u0438\u0442 \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0430 \u0448\u0435\u0440\u0441\u0442\u0438 \u043f\u043e\u0441\u043b\u0435 \u0441\u0442\u0438\u0440\u043a\u0438 \u0432 \u043e\u0434\u043d\u043e\u0439 \xab\u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438\xbb \u0441 \u043e\u043a\u0440\u0430\u0448\u0438\u0432\u0430\u044e\u0449\u0435\u0439 \u0444\u0443\u0442\u0431\u043e\u043b\u043a\u043e\u0439 \u043f\u0440\u0438 \u0432\u044b\u0441\u043e\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435. \u041c\u0430\u043b\u043e \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0448\u0435\u0440\u0441\u0442\u044c \u043f\u043e\u0442\u0435\u0440\u044f\u043b\u0430 \u0433\u043b\u0430\u0434\u043a\u043e\u0441\u0442\u044c \u0438 \u0440\u0430\u0432\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u044c (\u0435\u0435 \u0432\u043e\u043e\u0431\u0449\u0435 \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0441\u0442\u0438\u0440\u0430\u0442\u044c \u0432 \u0433\u043e\u0440\u044f\u0447\u0435\u0439 \u0432\u043e\u0434\u0435), \u0442\u0430\u043a \u043e\u043d\u0430 \u0435\u0449\u0451 \u0438 \u043e\u043a\u0440\u0430\u0441\u0438\u043b\u0430\u0441\u044c \u0440\u043e\u0437\u043e\u0432\u044b\u043c\u0438 \xab\u043f\u044f\u0442\u043d\u0430\u043c\u0438\xbb. \u0418 \u0441\u0430\u043c\u043e\u0435 \u043e\u0431\u0438\u0434\u043d\u043e\u0435, \u0447\u0442\u043e \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u0430\u044f \u0441\u0442\u0438\u0440\u043a\u0430 \u0441 \u0432\u044b\u0441\u043e\u043a\u043e\u0439 \u0434\u043e\u043b\u0435\u0439 \u0432\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0441\u0442\u0438 \u043a \u0438\u0441\u0445\u043e\u0434\u043d\u043e\u043c\u0443 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044e \u0441\u0432\u0438\u0442\u0435\u0440 \u043d\u0435 \u0432\u0435\u0440\u043d\u0451\u0442.\n\u041f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435 \u0442\u0430\u043a\u043e\u0433\u043e \u043d\u0435 \u043f\u0440\u043e\u0438\u0437\u043e\u0439\u0434\u0451\u0442 \u2014 \u0446\u0432\u0435\u0442\u043d\u043e\u0435 \u043c\u043e\u0436\u043d\u043e \u0441\u043c\u0435\u043b\u043e \u0441\u043c\u0435\u0448\u0438\u0432\u0430\u0442\u044c \u0441 \u0431\u0435\u043b\u044b\u043c. \u041d\u043e \u043a\u0430\u043a\u043e\u0432\u043e \u0431\u0443\u0434\u0435\u0442 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u0441\u0442\u0438\u0440\u043a\u0438? \u0412\u0435\u0434\u044c \u043e\u0441\u043d\u043e\u0432\u043d\u0430\u044f \u0438\u0434\u0435\u044f \u043d\u0430\u0433\u0440\u0435\u0432\u0430 \u0441\u043e\u0441\u0442\u043e\u0438\u0442 \u043a\u0430\u043a \u0440\u0430\u0437 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e \u0442\u043a\u0430\u043d\u044c \u043c\u043e\u0436\u0435\u0442 \u0441\u043e\u043f\u0440\u043e\u0442\u0438\u0432\u043b\u044f\u0442\u044c\u0441\u044f \u0432\u044b\u0441\u043e\u043a\u0438\u043c \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0430\u043c, \u0430 \u0433\u0440\u044f\u0437\u044c \u2014 \u043d\u0435 \u043c\u043e\u0436\u0435\u0442. \n\u0417\u0430\u0434\u0443\u043c\u0430\u0442\u044c\u0441\u044f \u043d\u0430 \u0442\u0435\u043c\u0443 \xab\u043c\u043e\u0436\u043d\u043e \u043b\u0438 \u043f\u043e\u0441\u0442\u0438\u0440\u0430\u0442\u044c \u043e\u0434\u0435\u0436\u0434\u0443 \u043f\u0440\u0438 \u043d\u0438\u0437\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435 \u0438 \u0438\u0437\u0431\u0430\u0432\u0438\u0442\u044c\u0441\u044f \u043e\u0442 \u043f\u044f\u0442\u0435\u043d\xbb \u043d\u0430\u0441 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u043b\u0438 \u0438\u043d\u0436\u0435\u043d\u0435\u0440\u044b \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 Hotpoint. \u0411\u0440\u0435\u043d\u0434 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u043b \u043d\u043e\u0432\u0443\u044e \u043b\u0438\u043d\u0435\u0439\u043a\u0443 \u0441\u0442\u0438\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u043c\u0430\u0448\u0438\u043d, \u043e\u0442\u043b\u0438\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0447\u0435\u0440\u0442\u043e\u0439 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0442\u0441\u0442\u0438\u0440\u044b\u0432\u0430\u0442\u044c \u0431\u043e\u043b\u0435\u0435 100 \u0432\u0438\u0434\u043e\u0432 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u0439 \u043f\u0440\u0438 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0435 20 \xb0C. \u042d\u0442\u043e \u043d\u0430 \u0441\u0430\u043c\u043e\u043c \u0434\u0435\u043b\u0435 \u043e\u0447\u0435\u043d\u044c \u043d\u0438\u0437\u043a\u0430\u044f \u0434\u043b\u044f \u0441\u0442\u0438\u0440\u043a\u0438 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0430. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435, \u0445\u043e\u043b\u043e\u0434\u043d\u0430\u044f \u0432\u043e\u0434\u0430.\n\u0420\u0435\u0434\u0430\u043a\u0446\u0438\u044f \u0443\u0441\u043e\u043c\u043d\u0438\u043b\u0430\u0441\u044c \u0438 \u0441\u043f\u0438\u0441\u0430\u043b\u0430 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u0435 Hotpoint \u043d\u0430 PR-\u0430\u043a\u0446\u0438\u044e, \u043d\u043e \u0437\u0430\u0442\u0435\u043c \u043c\u044b \u043f\u043e\u0434\u0443\u043c\u0430\u043b\u0438: \u0432 \u0442\u0435\u0447\u0435\u043d\u0438\u0435 \u043c\u043d\u043e\u0433\u0438\u0445 \u043b\u0435\u0442 \u043d\u0430\u0448\u0438 \u043f\u0440\u0435\u0434\u043a\u0438 \u0441\u0442\u0438\u0440\u0430\u043b\u0438 \u043e\u0434\u0435\u0436\u0434\u0443 \u0432 \u043f\u0440\u043e\u0442\u043e\u0447\u043d\u043e\u0439 \u0440\u0435\u0447\u043d\u043e\u0439 \u0432\u043e\u0434\u0435, \u043f\u043e\u0440\u043e\u0439 \u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0431\u043e\u043b\u0435\u0435 \u043d\u0438\u0437\u043a\u043e\u0439 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u044b. \u0414\u0430 \u0438 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0435 \u0442\u0443\u0440\u0438\u0441\u0442\u044b \u043d\u0435\u0440\u0435\u0434\u043a\u043e \u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u0443\u0441\u043b\u0443\u0433\u0430\u043c\u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u044b\u0445 \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a\u043e\u0432. \u0418 \u0431\u0435\u043b\u044c\u0451 \u043a\u0430\u043a\u0438\u043c-\u0442\u043e \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0447\u0438\u0441\u0442\u044b\u043c \u2014 \u0438 \u043f\u0430\u0445\u043d\u0435\u0442 \u0441\u0432\u0435\u0436\u0435\u0441\u0442\u044c\u044e \u043d\u0435 \u0445\u0443\u0436\u0435, \u0447\u0435\u043c \u043f\u043e\u0441\u043b\u0435 \u0441\u0442\u0438\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u043c\u0430\u0448\u0438\u043d\u044b! \n\u0417\u043d\u0430\u0447\u0438\u0442, \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u0430 \u2014 \u044d\u0442\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0434\u0438\u043d \u0438\u0437 \u0444\u0430\u043a\u0442\u043e\u0440\u043e\u0432, \u0430 \u0434\u0440\u0443\u0433\u043e\u0439, \u043d\u0435 \u043c\u0435\u043d\u0435\u0435 \u0432\u0430\u0436\u043d\u044b\u0439 \u0444\u0430\u043a\u0442\u043e\u0440, \u2014 \u044d\u0442\u043e \u043c\u0435\u0442\u043e\u0434, \u043a\u043e\u0442\u043e\u0440\u044b\u043c \u0431\u0435\u043b\u044c\u0451 \u0432\u0437\u0430\u0438\u043c\u043e\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0441 \u0432\u043e\u0434\u043e\u0439. \u0418\u043d\u0430\u0447\u0435 \u0433\u043e\u0432\u043e\u0440\u044f \u2014 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435. \u0415\u0441\u043b\u0438 \u0432 \u0443\u043c\u0435\u043b\u044b\u0445 \u0447\u0435\u043b\u043e\u0432\u0435\u0447\u0435\u0441\u043a\u0438\u0445 \u0440\u0443\u043a\u0430\u0445 \u0442\u043a\u0430\u043d\u044c \u043c\u043e\u0436\u0435\u0442 \u043e\u0447\u0438\u0441\u0442\u0438\u0442\u044c\u0441\u044f \u0434\u0430\u0436\u0435 \u0432 \u0445\u043e\u043b\u043e\u0434\u043d\u043e\u0439 \u0432\u043e\u0434\u0435, \u043f\u043e\u0447\u0435\u043c\u0443 \u0442\u043e \u0436\u0435 \u0441\u0430\u043c\u043e\u0435 \u043d\u0435 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u043c\u0435\u0445\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0431\u0430\u0440\u0430\u0431\u0430\u043d?\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://www.popmech.ru/gadgets/232598-layfkhak-kak-otstirat-lyubye-pyatna-pri-nizkoy-temperature/"},C.aj,t.c)
C.zp=new H.aA(3,{id:10,title:"\u041f\u043e\u0447\u0435\u043c\u0443 \u0438 \u043a\u0430\u043a \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0432\u0440\u0435\u0434\u0438\u0442 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438?",text:"\u0421\u043e\u0437\u0434\u0430\u0432\u0430\u044f \u0441\u0430\u0439\u0442, \u043f\u043e\u0441\u0432\u044f\u0449\u0451\u043d\u043d\u044b\u0439 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438, \u043c\u044b \u043d\u0435 \u043c\u043e\u0433\u043b\u0438 \u0437\u0430\u043a\u0440\u044b\u0442\u044c \u0433\u043b\u0430\u0437\u0430 \u043d\u0430 \u0434\u0440\u0443\u0433\u0443\u044e \u0432\u0430\u0436\u043d\u0443\u044e \u0442\u0435\u043c\u0443 \u2014 \u0432\u0435\u0433\u0435\u0442\u0430\u0440\u0438\u0430\u043d\u0441\u0442\u0432\u043e. \u0414\u043b\u044f \u043d\u0430\u0441 \u0441\u0430\u043c\u043e \u0441\u043e\u0431\u043e\u0439 \u0441\u0442\u0430\u043b\u043e \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u044b\u043c, \u0447\u0442\u043e \u0432\u0435\u0433\u0435\u0442\u0430\u0440\u0438\u0430\u043d\u0441\u043a\u043e\u0435 \u043f\u0438\u0442\u0430\u043d\u0438\u0435 \u2014 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u0437\u0430\u0431\u043e\u0442\u044b \u043e\u0431 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u043c \u043c\u0438\u0440\u0435. \u0418 \u0435\u0441\u043b\u0438 \u0441\u0432\u044f\u0437\u044c \u0432\u0435\u0433\u0430\u043d\u0441\u0442\u0432\u0430/\u0432\u0435\u0433\u0435\u0442\u0430\u0440\u0438\u0430\u043d\u0441\u0442\u0432\u0430 \u0441 \u044d\u0442\u0438\u0447\u043d\u044b\u043c \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435\u043c \u043a \u0436\u0438\u0432\u044b\u043c \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043c \u043b\u0435\u0436\u0438\u0442 \u0432 \u0441\u0430\u043c\u043e\u0439 \u043e\u0441\u043d\u043e\u0432\u0435 \u044d\u0442\u043e\u0433\u043e \u0432\u044b\u0431\u043e\u0440\u0430, \u0442\u043e \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043d\u0430\u0448\u0435\u0433\u043e \u0440\u0430\u0446\u0438\u043e\u043d\u0430 \u043d\u0430 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432, \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b \u0438 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u044e \u0432 \u0431\u043e\u043b\u0435\u0435 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0438 \u0443\u0436\u0435 \u043e\u0442\u043d\u044e\u0434\u044c \u043d\u0435 \u0441\u0442\u043e\u043b\u044c \u043f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u043e. \n\u041e\u0434\u043d\u0430\u043a\u043e \u0442\u0430\u043a\u0430\u044f \u0441\u0432\u044f\u0437\u044c \u0442\u043e\u0436\u0435 \u0435\u0441\u0442\u044c \u0438 \u043e\u043d\u0430 \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u0430. \u0414\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u043f\u0440\u043e\u0446\u0438\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430 \u0441 \u0441\u0430\u0439\u0442\u0430 \u041f\u0440\u043e\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438 \u0441\u0435\u043b\u044c\u0441\u043a\u043e\u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0438 \u043f\u0440\u0438 \u041e\u041e\u041d (UN Food and Agriculture Organization, FAO): \xab\u0421\u0435\u043a\u0442\u043e\u0440 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0438 \u043f\u0443\u0442\u044c, \u043a\u043e\u0442\u043e\u0440\u044b\u043c \u0431\u0443\u0434\u0435\u0442 \u043e\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043b\u044f\u0442\u044c\u0441\u044f \u0435\u0433\u043e \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435, \u0432\u044b\u0437\u044b\u0432\u0430\u0435\u0442 \u0433\u043b\u0443\u0431\u043e\u043a\u0438\u0435 \u0438 \u0448\u0438\u0440\u043e\u043a\u043e\u043c\u0430\u0441\u0448\u0442\u0430\u0431\u043d\u044b\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u044f, \u043f\u043e\u0434\u043b\u0435\u0436\u0430\u0449\u0438\u0435 \u043d\u0435\u0437\u0430\u043c\u0435\u0434\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u043c\u0443 \u0443\u0441\u0442\u0440\u0430\u043d\u0435\u043d\u0438\u044e\xbb. \n\u041a\u0430\u043a \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0432\u043b\u0438\u044f\u0435\u0442 \u043d\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u044e? \n\u041d\u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f\u0448\u043d\u0438\u0439 \u0434\u0435\u043d\u044c \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043c\u044f\u0441\u0430, \u0440\u044b\u0431\u044b, \u043c\u043e\u0440\u0435\u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0438 \u043c\u043e\u043b\u043e\u043a\u0430 \u2014 \u044d\u0442\u043e \u043e\u0433\u0440\u043e\u043c\u043d\u0430\u044f \u0438\u043d\u0434\u0443\u0441\u0442\u0440\u0438\u044f, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0440\u0430\u0434\u0438 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0432\u044b\u0433\u043e\u0434\u044b \u0433\u043e\u0442\u043e\u0432\u0430 \u043d\u0430 \u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0436\u0435\u0440\u0442\u0432\u044b, \u043e\u0431\u044a\u044f\u0441\u043d\u044f\u044f \u0438\u0445 \u043c\u0430\u0441\u0441\u043e\u0432\u043e\u0439 \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u044c\u044e \u043b\u044e\u0434\u0435\u0439 \u0432 \u0442\u0430\u043a\u043e\u0439 \u043f\u0438\u0449\u0435. \u041a \u0441\u043e\u0436\u0430\u043b\u0435\u043d\u0438\u044e, \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u043e\u0433\u043b\u0430\u0448\u0430\u0435\u0442\u0441\u044f \u0441 \u043d\u0430\u0434\u0443\u043c\u0430\u043d\u043d\u043e\u0439 \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u044c\u044e \u0432 \u0442\u0430\u043a\u043e\u0439 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u0438. \u0412\u0434\u043e\u0431\u0430\u0432\u043e\u043a, \u043a\u0430\u043a \u0438 \u0432 \u043b\u044e\u0431\u043e\u043c \u0434\u0440\u0443\u0433\u043e\u043c \u0431\u0438\u0437\u043d\u0435\u0441\u0435, \u043a\u043b\u044e\u0447\u0435\u0432\u0443\u044e \u0440\u043e\u043b\u044c \u0437\u0434\u0435\u0441\u044c \u0438\u0433\u0440\u0430\u0435\u0442 \u0444\u0430\u043a\u0442\u043e\u0440 \u0434\u0435\u043d\u0435\u0433, \u0441 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e\u043c \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0443 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u0439 (\u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u043c\u0430\u0441\u0448\u0442\u0430\u0431\u0430\u043c \u0438 \u0441\u043f\u0440\u043e\u0441\u0443) \u043f\u0440\u043e\u0431\u043b\u0435\u043c \u043d\u0435\u0442. \u041a\u0430\u043a \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442, \u0438\u043d\u0434\u0443\u0441\u0442\u0440\u0438\u044f \u043f\u043e\u043b\u0443\u0447\u0430\u0435\u0442 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u043a\u0443 \u043d\u0430 \u0432\u0441\u0435\u0445 \u0443\u0440\u043e\u0432\u043d\u044f\u0445 (\u043e\u0442 \u043d\u0430\u0441\u0435\u043b\u0435\u043d\u0438\u044f \u0434\u043e \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u043e\u0432) \u0438 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0435\u0442 \u043f\u0440\u043e\u0446\u0432\u0435\u0442\u0430\u0442\u044c. \u0427\u0442\u043e \u0436\u0435 \u0432 \u044d\u0442\u043e\u043c \u043f\u043b\u043e\u0445\u043e\u0433\u043e \u0434\u043b\u044f \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438? \n\u0410\u0432\u0442\u043e\u0440\u044b \u0437\u0430\u043c\u0435\u0447\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0444\u0438\u043b\u044c\u043c\u0430 Cowspiracy (\u0432 \u0440\u0443\u0441\u0441\u043a\u043e\u043c \u043f\u0440\u043e\u043a\u0430\u0442\u0435 \u0432\u044b\u0448\u0435\u043b \u043f\u043e\u0434 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435\u043c \xab\u0421\u043a\u043e\u0442\u043e\u0437\u0430\u0433\u043e\u0432\u043e\u0440\xbb) \u0441\u043e\u0431\u0440\u0430\u043b\u0438 \u0431\u043e\u043b\u044c\u0448\u0443\u044e \u043f\u043e\u0434\u0431\u043e\u0440\u043a\u0443 \u0444\u0430\u043a\u0442\u043e\u0432 \u0438\u0437 \u043f\u0443\u0431\u043b\u0438\u0447\u043d\u043e \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u044b\u0445 \u043d\u0430\u0443\u0447\u043d\u043e-\u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0445 \u0440\u0430\u0431\u043e\u0442/\u0437\u0430\u043c\u0435\u0442\u043e\u043a \u043e \u0442\u043e\u043c, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u0438 \u043f\u0430\u0433\u0443\u0431\u043d\u044b\u043c \u0434\u043b\u044f \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e. \u041e\u0431\u0449\u0438\u0439 \u044d\u0444\u0444\u0435\u043a\u0442 \u0441\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0438\u0437 \u0440\u044f\u0434\u0430 \u0444\u0430\u043a\u0442\u043e\u0440\u043e\u0432. \u041e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u0438\u0437 \u043d\u0438\u0445 \u043f\u0435\u0440\u0435\u0447\u0438\u0441\u043b\u0435\u043d\u044b \u043d\u0438\u0436\u0435 \u0438 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u0442 \u0441\u0441\u044b\u043b\u043a\u0438 \u043d\u0430 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430, \u0437\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0443\u0447\u0451\u043d\u044b\u043c\u0438. \n\n1. \u041f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0435 \u0433\u0430\u0437\u044b\n\n\u0416\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043f\u0440\u0438\u0432\u043e\u0434\u0438\u0442 \u043a \u0443\u0432\u0435\u043b\u0438\u0447\u0435\u043d\u0438\u044e \u0432\u044b\u0431\u0440\u043e\u0441\u043e\u0432 \u043f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0445 \u0433\u0430\u0437\u043e\u0432 \u043f\u043e \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u043f\u0440\u0438\u0447\u0438\u043d\u0430\u043c: \u0443\u0433\u043b\u0435\u043a\u0438\u0441\u043b\u043e\u0433\u043e \u0433\u0430\u0437\u0430 \u2014 \u0438\u0437-\u0437\u0430 \u0434\u044b\u0445\u0430\u043d\u0438\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445, \u0430 \u043c\u0435\u0442\u0430\u043d\u0430 (CH4)* \u2014 \u0438\u0437-\u0437\u0430 \u043f\u0438\u0449\u0435\u0432\u0430\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0436\u0432\u0430\u0447\u043d\u044b\u0445 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 (\u043f\u043e \u043f\u043e\u0434\u0441\u0447\u0451\u0442\u0430\u043c \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0446\u0435\u0432, \u043e\u0434\u043d\u0430 \u043a\u043e\u0440\u043e\u0432\u0430 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442 \u043e\u0442 250 \u0434\u043e 500 \u043b\u0438\u0442\u0440\u043e\u0432 \u043c\u0435\u0442\u0430\u043d\u0430 \u0432 \u0434\u0435\u043d\u044c). \u042d\u0442\u043e\u0442 \u0441\u0430\u043c\u044b\u0439 \u043c\u0435\u0442\u0430\u043d \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043d\u0430\u043c\u043d\u043e\u0433\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0435 \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043d\u0430 \u043f\u043e\u0432\u044b\u0448\u0435\u043d\u0438\u0435 \u0442\u0435\u043c\u043f\u0435\u0440\u0430\u0442\u0443\u0440\u044b \u043d\u0430 \u0417\u0435\u043c\u043b\u0435, \u0447\u0435\u043c CO2, \u043d\u043e \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432 \u0430\u0442\u043c\u043e\u0441\u0444\u0435\u0440\u0435 \u043c\u0435\u043d\u044c\u0448\u0435\u0435 \u0432\u0440\u0435\u043c\u044f. \n\n\u0415\u0441\u0442\u044c \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u043f\u0440\u0438\u0447\u0438\u043d\u044b, \u0432\u044b\u0437\u0432\u0430\u043d\u043d\u044b\u0435 \u043d\u0435\u043f\u043e\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c\u044e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 \u0434\u043b\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u0441\u0442\u0432\u0443\u044e\u0442 \u0440\u043e\u0441\u0442\u0443 \u043f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0445 \u0433\u0430\u0437\u043e\u0432, \u0442\u0430\u043a\u0438\u0435 \u043a\u0430\u043a: \n\n\u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0445\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0444\u0442\u043e\u0440\u0443\u0433\u043b\u0435\u0440\u043e\u0434\u044b \u0434\u043b\u044f \u043e\u0445\u043b\u0430\u0436\u0434\u0435\u043d\u0438\u044f \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043d\u044b\u0445 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432); \n\u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u044f \u043b\u0435\u0447\u0435\u043d\u0438\u044f \u0437\u043e\u043e\u043d\u043e\u0437\u043d\u044b\u0445 \u0438\u043d\u0444\u0435\u043a\u0446\u0438\u0439, \u043f\u0435\u0440\u0435\u0434\u0430\u044e\u0449\u0438\u0445\u0441\u044f \u043b\u044e\u0434\u044f\u043c \u043e\u0442 \u0434\u043e\u043c\u0430\u0448\u043d\u0438\u0445 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 (\u0441\u0438\u0431\u0438\u0440\u0441\u043a\u0430\u044f \u044f\u0437\u0432\u0430, \u0431\u0440\u0443\u0446\u0435\u043b\u043b\u0435\u0437, \u044f\u0449\u0443\u0440, \u0442\u0443\u0431\u0435\u0440\u043a\u0443\u043b\u0435\u0437, \u043b\u0438\u0441\u0442\u0435\u0440\u0438\u043e\u0437, \u0442\u0443\u043b\u044f\u0440\u0435\u043c\u0438\u044f \u0438 \u043c\u043d\u043e\u0433\u0438\u0435 \u0434\u0440\u0443\u0433\u0438\u0435); \n\u0441\u043e\u043a\u0440\u0430\u0449\u0435\u043d\u0438\u0435 \u043f\u043b\u043e\u0449\u0430\u0434\u0438 \u043b\u0435\u0441\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u044b\u0440\u0443\u0431\u0430\u044e\u0442\u0441\u044f \u0434\u043b\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430; \n\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 \u0438 \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432; \n\u0437\u0430\u0445\u043e\u0440\u043e\u043d\u0435\u043d\u0438\u0435 \u043e\u0442\u0445\u043e\u0434\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430. \n\u041f\u043e\u0434\u0440\u043e\u0431\u043d\u043e\u0441\u0442\u0438 \u043e \u043d\u0430\u0438\u0431\u043e\u043b\u0435\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0438\u0437 \u043d\u0438\u0445 \u0431\u0443\u0434\u0443\u0442 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u044b \u043d\u0438\u0436\u0435. \u041d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0432\u0435\u043b\u0438\u043a\u043e \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u043f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442? \n\n\u0412 \u043e\u0442\u0447\u0451\u0442\u0435 \u041f\u0440\u043e\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438 \u0441\u0435\u043b\u044c\u0441\u043a\u043e\u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0438 \u041e\u041e\u041d \u043e\u0442 2006 \u0433\u043e\u0434\u0430 \u0441\u043e\u043e\u0431\u0449\u0430\u043b\u043e\u0441\u044c, \u0447\u0442\u043e \u043d\u0430 \u0434\u043e\u043c\u0430\u0448\u043d\u0438\u0439 \u0441\u043a\u043e\u0442 (\u043a\u043e\u0440\u043e\u0432\u044b \u0438 \u0431\u044b\u043a\u0438, \u0431\u0443\u0439\u0432\u043e\u043b\u044b, \u043e\u0432\u0446\u044b, \u043a\u043e\u0437\u044b, \u0432\u0435\u0440\u0431\u043b\u044e\u0434\u044b, \u0441\u0432\u0438\u043d\u044c\u0438 \u0438 \u0434\u043e\u043c\u0430\u0448\u043d\u044f\u044f \u043f\u0442\u0438\u0446\u0430) \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f 18 % \u043e\u0442 \u0432\u0441\u0435\u0445 \u043c\u0438\u0440\u043e\u0432\u044b\u0445 \u043f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0445 \u0433\u0430\u0437\u043e\u0432. \u0414\u043b\u044f \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u044f, \u0432\u0435\u0441\u044c \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442 (\u0432\u043a\u043b\u044e\u0447\u0430\u044f \u043d\u0430\u0437\u0435\u043c\u043d\u044b\u0439, \u043c\u043e\u0440\u0441\u043a\u043e\u0439 \u0438 \u0432\u043e\u0437\u0434\u0443\u0448\u043d\u044b\u0439) \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 \u0432\u0441\u0435\u0433\u043e 13 %. \n\n\u0412 \u043a\u043e\u043d\u0446\u0435 2009 \u0433\u043e\u0434\u0430 \u0420\u043e\u0431\u0435\u0440\u0442 \u0413\u0443\u0434\u043b\u0430\u043d\u0434 (Robert Goodland) \u0438 \u0414\u0436\u0435\u0444\u0444 \u0410\u043d\u0433\u044d\u043d\u0433 (Jeff Anhang), \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u044b \u043f\u043e \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438 \u0438\u0437 \u0413\u0440\u0443\u043f\u043f\u044b \u0412\u0441\u0435\u043c\u0438\u0440\u043d\u043e\u0433\u043e \u0431\u0430\u043d\u043a\u0430 (World Bank Group) \u0441 \u0431\u043e\u043b\u044c\u0448\u0438\u043c \u0441\u0442\u0430\u0436\u0435\u043c, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b\u0438 \u0432 \u0438\u0437\u0434\u0430\u043d\u0438\u0438 \xabWorld Watch\xbb (\u043f\u0440\u0438 \u043e\u0434\u043d\u043e\u0438\u043c\u0451\u043d\u043d\u043e\u043c \u043d\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u043c \u0438\u043d\u0441\u0442\u0438\u0442\u0443\u0442\u0435) \u0441\u0442\u0430\u0442\u044c\u044e \xab\u0416\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0438 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u043a\u043b\u0438\u043c\u0430\u0442\u0430\xbb (Livestock and Climate Change), \u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043f\u0440\u0438\u0432\u0435\u0434\u0435\u043d\u044b \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u0430\u043d\u0430\u043b\u0438\u0437\u0430 \u0434\u0430\u043d\u043d\u044b\u0445 \u043e\u0442 \u041e\u041e\u041d \u0441 \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u043b\u043d\u044b\u043c\u0438 \u043d\u0430 \u0438\u0445 \u0432\u0437\u0433\u043b\u044f\u0434 \u043a\u043e\u0440\u0440\u0435\u043a\u0442\u0438\u0440\u043e\u0432\u043a\u0430\u043c\u0438. \u0420\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043e\u043a\u0430\u0437\u0430\u043b\u0441\u044f \u0432\u043f\u0435\u0447\u0430\u0442\u043b\u044f\u044e\u0449\u0438\u043c: \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044f \u044d\u0442\u043e\u0439 \u0438\u043d\u0434\u0443\u0441\u0442\u0440\u0438\u0438 \u0432\u044b\u0437\u044b\u0432\u0430\u0435\u0442 \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u044b\u0435 \u0432\u044b\u0431\u0440\u043e\u0441\u044b \u0431\u043e\u043b\u0435\u0435 32 \u043c\u0438\u043b\u043b\u0438\u0430\u0440\u0434\u043e\u0432 \u0442\u043e\u043d\u043d \u043f\u0430\u0440\u043d\u0438\u043a\u043e\u0432\u044b\u0445 \u0433\u0430\u0437\u043e\u0432, \u0447\u0442\u043e \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u044b (\u043e\u043a\u043e\u043b\u043e 51 %) \u043e\u0442 \u0432\u0441\u0435\u0445 \u0432\u044b\u0431\u0440\u043e\u0441\u043e\u0432 \u0432 \u043c\u0430\u0441\u0448\u0442\u0430\u0431\u0430\u0445 \u043f\u043b\u0430\u043d\u0435\u0442\u044b. \n\n2. \u041f\u043e\u0442\u0440\u0435\u0431\u043b\u0435\u043d\u0438\u0435 \u0432\u043e\u0434\u044b \n\u0421\u043e\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0441\u0432\u044f\u0437\u0430\u043d\u043e \u0441 \u043f\u043e\u0442\u0440\u0435\u0431\u043b\u0435\u043d\u0438\u0435\u043c \u043e\u0433\u0440\u043e\u043c\u043d\u043e\u0433\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0432\u043e\u0434\u044b, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0443\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u0432\u044b\u0440\u0430\u0449\u0438\u0432\u0430\u043d\u0438\u0435 \u0437\u0435\u0440\u043d\u043e\u0432\u044b\u0445, \u043f\u0438\u0442\u044c\u0451, \u043f\u043e\u043c\u044b\u0432\u043a\u0443 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u043e\u043f\u0443\u0442\u0441\u0442\u0432\u0443\u044e\u0449\u0438\u0435 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u044b. \u0422\u0430\u043a\u043e\u0435 \u0447\u0435\u043b\u043e\u0432\u0435\u0447\u0435\u0441\u043a\u043e\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u043e\u0434\u043d\u043e\u0433\u043e \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0446\u0435\u043d\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432, \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e, \u043d\u0435 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043e\u043f\u0442\u0438\u043c\u0430\u043b\u044c\u043d\u044b\u043c. \u0420\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u043f\u0440\u0438\u0432\u0435\u043b\u043e \u043a \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0431\u043e\u043b\u044c\u0448\u0430\u044f \u0447\u0430\u0441\u0442\u044c \u0432\u043e\u0434\u044b \u043d\u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f\u0448\u043d\u0438\u0439 \u0434\u0435\u043d\u044c \u0440\u0430\u0441\u0445\u043e\u0434\u0443\u0435\u0442\u0441\u044f \u0432\u043e\u0432\u0441\u0435 \u043d\u0435 \u043b\u044e\u0434\u044c\u043c\u0438 \u0434\u043b\u044f \u043d\u0435\u043f\u043e\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u0438\u0442\u044c\u044f \u0438 \u043b\u0438\u0447\u043d\u044b\u0445 \u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u043d\u0443\u0436\u0434, \u0430 \u0438\u043c\u0435\u043d\u043d\u043e \u043d\u0430 \u044d\u0442\u0443 \u0438\u043d\u0434\u0443\u0441\u0442\u0440\u0438\u044e. \u041e\u0446\u0435\u043d\u043a\u0438 \u043f\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0443 \u0432\u043e\u0434\u044b, \u0442\u0440\u0435\u0431\u0443\u0435\u043c\u043e\u0439 \u0434\u043b\u044f \xab\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0430\xbb \u043c\u044f\u0441\u0430, \u043e\u0447\u0435\u043d\u044c \u0440\u0430\u0437\u043d\u044f\u0442\u0441\u044f, \u043d\u043e \u0432\u0441\u0435 \u0441\u0445\u043e\u0434\u044f\u0442\u0441\u044f \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e \u044d\u0442\u043e \u043a\u043e\u043b\u043e\u0441\u0441\u0430\u043b\u044c\u043d\u044b\u0435 \u0437\u0430\u0442\u0440\u0430\u0442\u044b. \n\n\u0428\u0438\u0440\u043e\u043a\u043e \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043c\u0430\u044f \u043e\u0446\u0435\u043d\u043a\u0430 \u043f\u0440\u0438\u043d\u0430\u0434\u043b\u0435\u0436\u0438\u0442 \u0434\u043e\u043a\u0442\u043e\u0440\u0443 \u0414\u0436\u043e\u0440\u0434\u0436\u0443 \u0411\u043e\u0440\u0433\u0441\u0442\u0440\u043e\u043c\u0443 (George Borgstrom) \u0438\u0437 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0430 \u0448\u0442\u0430\u0442\u0430 \u041c\u0438\u0447\u0438\u0433\u0430\u043d: 2500 \u0433\u0430\u043b\u043b\u043e\u043d\u043e\u0432 \u0432\u043e\u0434\u044b \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044f \u0434\u043b\u044f \u043a\u0430\u0436\u0434\u043e\u0433\u043e 1 \u0444\u0443\u043d\u0442\u0430 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u043e\u0439 \u0433\u043e\u0432\u044f\u0434\u0438\u043d\u044b (\u0442.\u0435.\u043d\u0430 1 \u043a\u0433 \u043c\u044f\u0441\u0430 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043e\u043a\u043e\u043b\u043e 4300 \u043b \u0432\u043e\u0434\u044b). \u0412 \u0442\u043e \u0436\u0435 \u0432\u0440\u0435\u043c\u044f \u0430\u0432\u0442\u043e\u0440\u044b \u0441\u0442\u0430\u0442\u044c\u0438 \xab\u0412\u043e\u0434\u043d\u044b\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044b: \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0438 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0432\u043e\u043f\u0440\u043e\u0441\u044b\xbb (Water Resources: Agricultural and Environmental Issues), \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 \xabBioScience\xbb \u043f\u0440\u0438 \u041e\u043a\u0441\u0444\u043e\u0440\u0434\u0441\u043a\u043e\u043c \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u0432 2004 \u0433\u043e\u0434\u0443, \u0437\u0430\u044f\u0432\u043b\u044f\u044e\u0442, \u0447\u0442\u043e \u0435\u0441\u043b\u0438 \u043d\u0430 1 \u043a\u0438\u043b\u043e\u0433\u0440\u0430\u043c\u043c \u0445\u043b\u0435\u0431\u043d\u044b\u0445 \u0437\u043b\u0430\u043a\u043e\u0432 \u0432 \u0441\u0440\u0435\u0434\u043d\u0435\u043c \u0440\u0430\u0441\u0445\u043e\u0434\u0443\u0435\u0442\u0441\u044f \u043e\u043a\u043e\u043b\u043e 1000 \u043b\u0438\u0442\u0440\u043e\u0432 \u0432\u043e\u0434\u044b, \u0442\u043e \u043d\u0430 1 \u043a\u0438\u043b\u043e\u0433\u0440\u0430\u043c\u043c \u0433\u043e\u0432\u044f\u0434\u0438\u043d\u044b \u2014 43 000 \u043b\u0438\u0442\u0440\u043e\u0432. \n\n\u041e\u0431\u0449\u0438\u0435 \u0437\u0430\u0442\u0440\u0430\u0442\u044b \u0432\u043e\u0434\u043d\u044b\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432 \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443 \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0442 \u043e\u0442 20 \u0434\u043e 70 %. \u0412 \u0447\u0430\u0441\u0442\u043d\u043e\u0441\u0442\u0438, \u0430\u0432\u0442\u043e\u0440\u044b \u043d\u0430\u0443\u0447\u043d\u043e\u0439 \u0441\u0442\u0430\u0442\u044c\u0438, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0432 2013 \u0433\u043e\u0434\u0443 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 PNAS \u043f\u0440\u0438 \u041d\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0439 \u0430\u043a\u0430\u0434\u0435\u043c\u0438\u0438 \u043d\u0430\u0443\u043a \u0421\u0428\u0410, \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043b\u0438 28 \u0440\u0435\u0433\u0438\u043e\u043d\u043e\u0432 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443 \u0438 \u043f\u0440\u0438\u0448\u043b\u0438 \u043a \u0432\u044b\u0432\u043e\u0434\u0443, \u0447\u0442\u043e \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043f\u043e\u0442\u0440\u0435\u0431\u043b\u044f\u0435\u0442 1/3 \u043e\u0442 \u0432\u0441\u0435\u0439 \u0441\u0432\u0435\u0436\u0435\u0439 \u0432\u043e\u0434\u044b.\n\n3. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u0437\u0435\u043c\u043d\u043e\u0439 \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438\n\n\u041f\u0430\u0441\u0442\u0431\u0438\u0449\u0430, \u0444\u0435\u0440\u043c\u044b \u0438 \u043f\u0440\u043e\u0447\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0447\u0435\u0441\u043a\u0438\u0435 \u0443\u0433\u043e\u0434\u044c\u044f \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u044e\u0442 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u0447\u0430\u0441\u0442\u044c \u043f\u043b\u0430\u043d\u0435\u0442\u044b, \u043d\u043e \u0438: \n\n\u043f\u0440\u0438\u0432\u043e\u0434\u044f\u0442 \u043a \u0434\u0435\u0433\u0440\u0430\u0434\u0430\u0446\u0438\u0438 \u0437\u0435\u043c\u043b\u0438, \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435: \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0435\u043d\u0438\u044e \u0445\u0438\u043c\u0438\u043a\u0430\u0442\u0430\u043c\u0438, \u0443\u043f\u043b\u043e\u0442\u043d\u0435\u043d\u0438\u044e \u0438 \u044d\u0440\u043e\u0437\u0438\u0438 \u043f\u043e\u0447\u0432, \u043f\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u044e \xab\u043c\u0451\u0440\u0442\u0432\u044b\u0445 \u0437\u043e\u043d\xbb \u2014 \u0443\u0447\u0430\u0441\u0442\u043a\u043e\u0432 \u0432 \u043f\u0440\u0438\u0431\u0440\u0435\u0436\u043d\u044b\u0445 \u0432\u043e\u0434\u0430\u0445, \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u043a\u0438\u0441\u043b\u043e\u0440\u043e\u0434\u0430 \u0432 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u044b\u043c \u0434\u043b\u044f \u0436\u0438\u0437\u043d\u0438 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445; \n\u0441\u043f\u043e\u0441\u043e\u0431\u0441\u0442\u0432\u0443\u044e\u0442 \u043e\u0431\u0435\u0437\u043b\u0435\u0441\u0435\u043d\u0438\u044e \u043f\u043b\u0430\u043d\u0435\u0442\u044b \u0438\u0437-\u0437\u0430 \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u0438 \xab\u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0430\u0442\u044c\xbb \u0432\u0441\u0451 \u043d\u043e\u0432\u044b\u0435 \u0438 \u043d\u043e\u0432\u044b\u0435 \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0438 \u0434\u043b\u044f \u0432\u0435\u0434\u0435\u043d\u0438\u044f \u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0446\u0435\u043d\u043e\u0439 \u0432\u044b\u0440\u0443\u0431\u043a\u0438 \u043b\u0435\u0441\u043e\u0432; \n\u0443\u0441\u043a\u043e\u0440\u044f\u044e\u0442 \u0432\u044b\u043c\u0438\u0440\u0430\u043d\u0438\u0435 \u0432\u0438\u0434\u043e\u0432, \u043f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u043b\u044e\u0434\u0438 \u0438\u0441\u0442\u0440\u0435\u0431\u043b\u044f\u044e\u0442 \u0445\u0438\u0449\u043d\u0438\u043a\u043e\u0432 \u0438 \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u044b\u0445 \u043a\u043e\u043d\u043a\u0443\u0440\u0435\u043d\u0442\u043e\u0432 \u0434\u043b\u044f \u0432\u044b\u0440\u0430\u0449\u0438\u0432\u0430\u0435\u043c\u044b\u0445 \u0438 \u043f\u043e\u0442\u0440\u0435\u0431\u043b\u044f\u0435\u043c\u044b\u0445 \u0432 \u043f\u0438\u0449\u0443 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445. \n\u041f\u043e \u0440\u0430\u0437\u043d\u044b\u043c \u0434\u0430\u043d\u043d\u044b\u043c, \u0434\u043b\u044f \u043d\u0443\u0436\u0434 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u043e\u0442 1/3 \u0434\u043e \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u044b \u0432\u0441\u0435\u0439 \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u043e\u0439 \u043f\u043b\u043e\u0449\u0430\u0434\u0438 \u0437\u0435\u043c\u043b\u0438. \u0414\u043e\u043b\u044e \u043f\u043e\u0432\u0435\u0440\u0445\u043d\u043e\u0441\u0442\u0438 \u043f\u043b\u0430\u043d\u0435\u0442\u044b, \u043f\u0440\u0438\u0445\u043e\u0434\u044f\u0449\u0443\u044e\u0441\u044f \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e, \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u044e\u0442 \u0432 30 % \u0443\u0447\u0451\u043d\u044b\u0435 \u0443\u0436\u0435 \u0443\u043f\u043e\u043c\u044f\u043d\u0443\u0442\u043e\u0433\u043e \u0434\u043e\u043a\u043b\u0430\u0434\u0430 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 PNAS, \u0430 \u0432 45 % \u2014 \u0424\u0438\u043b\u0438\u043f \u0422\u043e\u0440\u043d\u0442\u043e\u043d (Philip Thornton), \u041c\u0430\u0440\u0438\u043e \u0425\u0435\u0440\u0440\u0435\u0440\u043e (Mario Herrero) \u0438 \u041f\u043e\u043b\u043b\u0438 \u042d\u0440\u0438\u043a\u0441\u0435\u043d (Polly Ericksen) \u0432 \u043f\u0443\u0431\u043b\u0438\u043a\u0430\u0446\u0438\u0438 \xab\u0416\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0438 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u043a\u043b\u0438\u043c\u0430\u0442\u0430\xbb (Livestock and climate change), \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u043d\u043e\u0439 \u0432 2011 \u0433\u043e\u0434\u0443 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 \xabLivestock Xchange\xbb (\u0432\u044b\u043f\u0443\u0441\u043a\u0430\u0435\u0442\u0441\u044f \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u043c \u0438\u043d\u0441\u0442\u0438\u0442\u0443\u0442\u043e\u043c ILRI, International Livestock Research Institute). \n\n\u041f\u0440\u043e\u0444\u0435\u0441\u0441\u043e\u0440 \u042d\u0434\u0433\u0430\u0440 \u0425\u0435\u0440\u0442\u0432\u0438\u043a (Edgar Hertwich), \u0430\u0432\u0442\u043e\u0440 \u043e\u0442\u0447\u0451\u0442\u0430 2010 \u0433\u043e\u0434\u0430 \u0434\u043b\u044f \u041f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u044b \u041e\u041e\u041d \u043f\u043e \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435 (United Nations Environment Programme, UNEP), \u0441\u0440\u0430\u0432\u043d\u0438\u043b \u044d\u0444\u0444\u0435\u043a\u0442 \u043e\u0442 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0441 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u044b\u0445 \u043d\u0430\u043c \u0432\u0440\u0435\u0434\u043d\u044b\u0445 \u0434\u043b\u044f \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u043e\u0432: \xab\u041f\u0440\u043e\u0434\u0443\u043a\u0442\u044b \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u043c\u043e\u0433\u0443\u0442 \u043d\u0430\u043d\u0435\u0441\u0442\u0438 \u0431\u043e\u043b\u044c\u0448\u0438\u0439 \u0443\u0440\u043e\u043d, \u0447\u0435\u043c \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0442\u0430\u043a\u0438\u0445 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u043e\u0432 \u0434\u043b\u044f \u0441\u0442\u0440\u043e\u0438\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430, \u043a\u0430\u043a \u043f\u0435\u0441\u043e\u043a, \u0446\u0435\u043c\u0435\u043d\u0442, \u043f\u043b\u0430\u0441\u0442\u0438\u043a \u0438\u043b\u0438 \u043c\u0435\u0442\u0430\u043b\u043b. \u0411\u0438\u043e\u043c\u0430\u0441\u0441\u0430 \u0438 \u0441\u0435\u043b\u044c\u0441\u043a\u043e\u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u044b \u0434\u043b\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0442\u0430\u043a \u0436\u0435 \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043b\u044c\u043d\u044b, \u043a\u0430\u043a \u0441\u0436\u0438\u0433\u0430\u043d\u0438\u0435 \u0438\u0441\u043a\u043e\u043f\u0430\u0435\u043c\u043e\u0433\u043e \u0442\u043e\u043f\u043b\u0438\u0432\u0430\xbb. \n\n\u0414\u043e\u043a\u0443\u043c\u0435\u043d\u0442 2006 \u0433\u043e\u0434\u0430 \xab\u0414\u043b\u0438\u043d\u043d\u0430\u044f \u0442\u0435\u043d\u044c \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430\xbb (Livestock\u2019s long shadow), \u043f\u043e\u0434\u0433\u043e\u0442\u043e\u0432\u043b\u0435\u043d\u043d\u044b\u0439 \u041f\u0440\u043e\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438 \u0441\u0435\u043b\u044c\u0441\u043a\u043e\u0445\u043e\u0437\u044f\u0439\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0435\u0439 \u041e\u041e\u041d, \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0444\u0430\u043a\u0442\u044b \u043e\u0431 \u0443\u043d\u0438\u0447\u0442\u043e\u0436\u0435\u043d\u0438\u0438 \u043b\u0435\u0441\u043e\u0432: \xab\u0420\u0430\u0441\u0448\u0438\u0440\u0435\u043d\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u2014 \u0433\u043b\u0430\u0432\u043d\u044b\u0439 \u0444\u0430\u043a\u0442\u043e\u0440 \u043e\u0431\u0435\u0437\u043b\u0435\u0441\u0435\u043d\u0438\u044f, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u0432 \u041b\u0430\u0442\u0438\u043d\u0441\u043a\u043e\u0439 \u0410\u043c\u0435\u0440\u0438\u043a\u0435, \u0433\u0434\u0435 \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u044e\u0442\u0441\u044f \u043e\u0433\u0440\u043e\u043c\u043d\u044b\u0435 \u0442\u0435\u043c\u043f\u044b \u0432\u044b\u0440\u0443\u0431\u043a\u0438 \u043b\u0435\u0441\u043e\u0432: 70 \u043f\u0440\u043e\u0446\u0435\u043d\u0442\u043e\u0432 \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0438 \u0431\u044b\u0432\u0448\u0438\u0445 \u043b\u0435\u0441\u043e\u0432 \u0437\u0430\u043d\u044f\u0442\u044b \u043f\u0430\u0441\u0442\u0431\u0438\u0449\u0430\u043c\u0438, \u0430 \u043a\u043e\u0440\u043c\u043e\u0432\u044b\u0435 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u044b \u0437\u0430\u043d\u0438\u043c\u0430\u044e\u0442 \u0431\u043e\u043b\u044c\u0448\u0443\u044e \u0447\u0430\u0441\u0442\u044c \u043e\u0441\u0442\u0430\u0432\u0448\u0435\u0439\u0441\u044f \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0438\xbb. \n\n\u041f\u043e\u043c\u0438\u043c\u043e \u043f\u0440\u0438\u043d\u0435\u0441\u0435\u043d\u0438\u044f \u0432\u0440\u0435\u0434\u0430 \u043b\u0430\u043d\u0434\u0448\u0430\u0444\u0442\u0430\u043c, \u0440\u0430\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0441\u043a\u043e\u0442\u0430 \u0442\u0430\u043a\u0436\u0435 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043f\u0440\u0438\u0447\u0438\u043d\u043e\u0439 \u043d\u0435\u0440\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u0435\u043d\u0438\u044f \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432 \u043d\u0430 \u0437\u0435\u043c\u043b\u0435 \u0438, \u043a\u0430\u043a \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0435, \u0433\u043e\u043b\u043e\u0434\u0430 \u0432\u043e \u043c\u043d\u043e\u0433\u0438\u0445 \u0447\u0430\u0441\u0442\u044f\u0445 \u0417\u0435\u043c\u043d\u043e\u0433\u043e \u0448\u0430\u0440\u0430. \u0421 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435\u043c \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0438 \u0440\u043e\u0441\u0442\u043e\u043c \u043d\u0430\u0441\u0435\u043b\u0435\u043d\u0438\u044f \u041f\u043b\u0430\u043d\u0435\u0442\u044b \u0432\u0441\u0435 \u0441\u043b\u043e\u0436\u043d\u0435\u0435 \u043d\u0430\u043a\u043e\u0440\u043c\u0438\u0442\u044c 7 \u043c\u043b\u0440\u0434 \u043b\u044e\u0434\u0435\u0439. \u041d\u043e \u0432\u043c\u0435\u0441\u0442\u043e \u0442\u043e\u0433\u043e, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0440\u0430\u0449\u0438\u0432\u0430\u0442\u044c \u0441\u044a\u0435\u0434\u043e\u0431\u043d\u044b\u0435 \u043f\u043b\u043e\u0434\u044b \u0434\u043b\u044f \u043f\u0438\u0442\u0430\u043d\u0438\u044f \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u043e\u0442\u0440\u0435\u0431\u043b\u044f\u0435\u0442 \u043d\u0430\u043c\u043d\u043e\u0433\u043e \u043c\u0435\u043d\u044c\u0448\u0435, \u043c\u044b \u0432\u044b\u0440\u0430\u0449\u0438\u0432\u0430\u0435\u043c \u043a\u043e\u0440\u043c\u043e\u0432\u044b\u0435 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u044b \u0434\u043b\u044f \u0441\u043a\u043e\u0442\u0430. \u041e\u0434\u043d\u0430 \u043a\u043e\u0440\u043e\u0432\u0430 \u0432 \u0434\u0435\u043d\u044c \u0441\u044a\u0435\u0434\u0430\u0435\u0442 10-20 \u043a\u0433 \u043a\u043e\u0440\u043c\u0430 (\u0438\u043b\u0438 \u043a\u043e\u0440\u043c\u043e\u0432\u044b\u0445 \u043a\u0443\u043b\u044c\u0442\u0443\u0440, \u0442\u0430\u043a\u0438\u0445 \u043a\u0430\u043a \u043a\u0430\u0440\u0442\u043e\u0444\u0435\u043b\u044c, \u0441\u0432\u0435\u043a\u043b\u0430, \u0442\u043e\u043f\u0438\u043d\u0430\u043c\u0431\u0443\u0440). \u0414\u043b\u044f \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u043d\u0438\u044f \u043e\u0434\u043d\u043e\u0439 \u0441\u0440\u0435\u0434\u043d\u0435\u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0441\u0435\u043c\u044c\u0438 \u0442\u0430\u043a\u043e\u0433\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u0430 \u0435\u0434\u044b \u0445\u0432\u0430\u0442\u0438\u0442 \u043d\u0430 \u043d\u0435\u0434\u0435\u043b\u044e. \u041d\u043e \u043e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u043f\u043e\u0442\u0440\u0435\u0431\u0438\u0442\u0435\u043b\u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u0438 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u043d\u0435 \u0438\u043c\u0435\u044e\u0442 \u043f\u0440\u043e\u0431\u043b\u0435\u043c \u0441 \u043f\u0438\u0442\u0430\u043d\u0438\u0435\u043c, \u0430 \u043f\u043e\u0442\u043e\u043c\u0443 \u0438\u043c \u0441\u043b\u043e\u0436\u043d\u043e \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044c, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0433\u043e\u043b\u043e\u0434\u043d\u044b\u0445 \u0434\u0435\u0442\u0435\u0439 \u0443\u043c\u0438\u0440\u0430\u0435\u0442 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443, \u043a\u043e\u0442\u043e\u0440\u044b\u043c \u0434\u043b\u044f \u0432\u044b\u0436\u0438\u0432\u0430\u043d\u0438\u044f \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c \u043b\u0438\u0448\u044c \u043c\u0435\u0448\u043e\u043a \u0437\u0435\u0440\u043d\u0430.\n\n4. \u041e\u0442\u0445\u043e\u0434\u044b\n\n\xab\u041f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e\xbb \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u2014 \u044d\u0442\u043e \u043e\u0447\u0435\u043d\u044c \u0434\u043e\u0440\u043e\u0433\u043e\u0441\u0442\u043e\u044f\u0449\u0438\u0439 \u043f\u0440\u043e\u0446\u0435\u0441\u0441 \u0438 \u0432 \u043f\u043b\u0430\u043d\u0435 \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u0435\u043c\u044b\u0445 \u043e\u0442\u0445\u043e\u0434\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0435, \u043a\u0430\u043a \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u043e, \u0432\u0441\u0435\u0433\u0434\u0430 \xab\u043d\u0443\u0436\u043d\u043e \u043a\u0443\u0434\u0430-\u0442\u043e \u0434\u0435\u0432\u0430\u0442\u044c\xbb. \u0426\u0435\u043b\u044b\u0435 \u043f\u0440\u0443\u0434\u044b \u0438\u0437 \u044d\u043a\u0441\u043a\u0440\u0435\u043c\u0435\u043d\u0442\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u043d\u0430\u043a\u0430\u043f\u043b\u0438\u0432\u0430\u044e\u0442 \u0432 \u0441\u0435\u0431\u0435 \u0442\u0430\u043a\u0438\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430, \u043a\u0430\u043a \u0430\u043c\u043c\u0438\u0430\u043a, \u043c\u0435\u0442\u0430\u043d, \u0441\u0435\u0440\u043e\u0432\u043e\u0434\u043e\u0440\u043e\u0434, \u0443\u0433\u0430\u0440\u043d\u044b\u0439 \u0433\u0430\u0437, \u0446\u0438\u0430\u043d\u0438\u0434, \u043d\u0438\u0442\u0440\u0430\u0442\u044b, \u0442\u044f\u0436\u0435\u043b\u044b\u0435 \u043c\u0435\u0442\u0430\u043b\u043b\u044b, \u0431\u0430\u043a\u0442\u0435\u0440\u0438\u0438 (\u0441\u0430\u043b\u044c\u043c\u043e\u043d\u0435\u043b\u043b\u0430, \u0441\u0442\u0440\u0435\u043f\u0442\u043e\u043a\u043e\u043a\u043a\u0438 \u0438 \u0442.\u043f.). \n\n\u041f\u043e \u0434\u0430\u043d\u043d\u044b\u043c \u043f\u0443\u0431\u043b\u0438\u043a\u0430\u0446\u0438\u0438 \u0437\u0430 2004 \u0433\u043e\u0434 \u0410\u0433\u0435\u043d\u0442\u0441\u0442\u0432\u0430 \u043f\u043e \u043e\u0445\u0440\u0430\u043d\u0435 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u044b \u0421\u0428\u0410 (EPA), \xab\u0444\u0435\u0440\u043c\u0430 \u0441 2500 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u043c\u0438, \u0434\u0430\u044e\u0449\u0438\u043c\u0438 \u043c\u043e\u043b\u043e\u043a\u043e, \u0441\u043e\u0437\u0434\u0430\u0451\u0442 \u0441\u0442\u043e\u043b\u044c\u043a\u043e \u0436\u0435 \u043c\u0443\u0441\u043e\u0440\u0430, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0433\u043e\u0440\u043e\u0434 \u0441 \u043d\u0430\u0441\u0435\u043b\u0435\u043d\u0438\u0435\u043c \u0432 411 \u0442\u044b\u0441\u044f\u0447 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\xbb. \u0414\u0440\u0443\u0433\u0430\u044f \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u043a\u0430 \u0438\u0437 \u0421\u0428\u0410 \u0437\u0430 1999 \u0433\u043e\u0434 \u2014 \u043e\u0442 \u0421\u0447\u0451\u0442\u043d\u043e\u0439 \u041f\u0430\u043b\u0430\u0442\u044b (General Accounting Office) \u2014 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442, \u0447\u0442\u043e \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0441\u043e\u0437\u0434\u0430\u0451\u0442 \u0432 130 \u0440\u0430\u0437 \u0431\u043e\u043b\u044c\u0448\u0435 \u043c\u0443\u0441\u043e\u0440\u0430, \u0447\u0435\u043c \u0432\u0441\u0435 \u0436\u0438\u0442\u0435\u043b\u0438 \u0441\u0442\u0440\u0430\u043d\u044b (\u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0433\u0440\u0430\u0436\u0434\u0430\u043d\u0438\u043d\u0430 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043f\u043e 5 \u0442\u043e\u043d\u043d \u043c\u0443\u0441\u043e\u0440\u0430 \u043e\u0442 \u044d\u0442\u043e\u0439 \u0438\u043d\u0434\u0443\u0441\u0442\u0440\u0438\u0438 \u0432 \u0433\u043e\u0434). \n\n5. \u0416\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u0438 \u043c\u043e\u0440\u0430\u043b\u044c \n\u041e\u0441\u043e\u0431\u043e\u0433\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0434\u043e\u0441\u0442\u043e\u0439\u043d\u0430 \u044d\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0441\u0442\u043e\u0440\u043e\u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0430. \u041e\u043d\u0430 \u0442\u043e\u0436\u0435 \u0438\u043c\u0435\u0435\u0442 \u043d\u0435\u043f\u043e\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u043a \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u043d\u0435 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f\u043c\u0438 \u043a\u043b\u0438\u043c\u0430\u0442\u0430, \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u044b\u043c\u0438 \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u043c\u0438 \u0438 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435\u043c \u0444\u043b\u043e\u0440\u044b. \u0416\u0438\u0432\u044b\u0435 \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u043c\u044b \u2014 \u043d\u0435\u043e\u0442\u044a\u0435\u043c\u043b\u0435\u043c\u0430\u044f \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0449\u0430\u044f \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u043a \u043d\u0438\u043c \u2014 \u0432\u0430\u0436\u043d\u044b\u0439 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0441\u0442\u0438. \n\n\u041f\u043e \u0434\u0430\u043d\u043d\u044b\u043c \u0424\u0438\u043b\u0438\u043f\u0430 \u041b\u0438\u043c\u0431\u0435\u0440\u0438 (Philip Lymbery), \u0433\u043b\u0430\u0432\u044b \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u0438 \u0421\u043e\u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u0435 \u0432 \u043c\u0438\u0440\u043e\u0432\u043e\u043c \u0444\u0435\u0440\u043c\u0435\u0440\u0441\u0442\u0432\u0435 (Compassion in World Farming), \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u043e \u043c\u044b \u0443\u0431\u0438\u0432\u0430\u0435\u043c \u0431\u043e\u043b\u0435\u0435 70 \u043c\u0438\u043b\u043b\u0438\u0430\u0440\u0434\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 (\u044d\u0442\u043e \u0431\u043e\u043b\u0435\u0435 133 \u0442\u044b\u0441\u044f\u0447 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0432 \u043c\u0438\u043d\u0443\u0442\u0443!).\n\n\u0415\u0441\u043b\u0438 \u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c \u043d\u0430 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u0443 \u0433\u043b\u043e\u0431\u0430\u043b\u044c\u043d\u043e, \u0442\u043e \u0432\u0430\u0436\u043d\u043e \u043d\u0435 \u0441\u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0430\u043c\u043e \u043d\u0430\u043b\u0438\u0447\u0438\u0435 \u043f\u043e\u0434\u043e\u0431\u043d\u043e\u0439 \u0434\u0435\u044f\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u041d\u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f\u0448\u043d\u0438\u0439 \u0434\u0435\u043d\u044c \u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0430 \u043d\u0435\u0442 \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u0438 \u0432 \u0440\u0430\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0438, \u044d\u043a\u0441\u043f\u043b\u0443\u0430\u0442\u0430\u0446\u0438\u0438 \u0438 \u0443\u0431\u0438\u0439\u0441\u0442\u0432\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0434\u043b\u044f \u0443\u0434\u043e\u0432\u043b\u0435\u0442\u0432\u043e\u0440\u0435\u043d\u0438\u044f \u0431\u0430\u0437\u043e\u0432\u044b\u0445 \u043f\u043e\u0442\u0440\u0435\u0431\u043d\u043e\u0441\u0442\u0435\u0439 (\u0432 \u0435\u0434\u0435, \u043e\u0434\u0435\u0436\u0434, \u043a\u043e\u0441\u043c\u0435\u0442\u0438\u043a\u0435 \u0438 \u043a\u0430\u043a\u0438\u0445-\u043b\u0438\u0431\u043e \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430\u0445) \u2014 \u0443 \u0432\u0441\u0435\u0433\u043e \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044e\u0442 \u0430\u043d\u0430\u043b\u043e\u0433\u0438. \u041f\u0440\u0438\u0447\u0451\u043c \u044d\u0442\u043e \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0438\u043b\u0438 \u0447\u0435\u043c-\u0442\u043e \u0445\u0443\u0434\u0448\u0438\u0435 \u0430\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u044b, \u0430 \u0442\u043e, \u0447\u0442\u043e \u0434\u0430\u0432\u043d\u043e \u0441\u0442\u0430\u043b\u043e \u043d\u043e\u0440\u043c\u043e\u0439 \u0434\u043b\u044f \u043c\u043d\u043e\u0433\u0438\u0445 \u043b\u044e\u0434\u0435\u0439 \u0441\u043e \u0432\u0441\u0435\u0433\u043e \u043c\u0438\u0440\u0430, \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0445 \u0438 \u0432\u0435\u0441\u044c\u043c\u0430 \xab\u0443\u0441\u043f\u0435\u0448\u043d\u044b\u0445\xbb \u0432 \u043e\u0431\u0449\u0435\u043f\u0440\u0438\u043d\u044f\u0442\u044b\u0445 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0445 \u043a\u0440\u0438\u0442\u0435\u0440\u0438\u044f\u0445. \u041f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u043e\u0441\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u044f \u0432\u0435\u0433\u0430\u043d\u043e\u0432, \u043a \u0447\u0438\u0441\u043b\u0443 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u043e\u0442\u043d\u043e\u0441\u044f\u0442\u0441\u044f \u0438 \u043c\u043d\u043e\u0433\u0438\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0435 \u043b\u0438\u0447\u043d\u043e\u0441\u0442\u0438, \u0441\u043b\u0443\u0436\u0438\u0442 \u0445\u043e\u0440\u043e\u0448\u0438\u043c \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e\u043c \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0412\u042b\u0411\u041e\u0420 \u041d\u0410 \u0421\u0410\u041c\u041e\u041c \u0414\u0415\u041b\u0415 \u0415\u0421\u0422\u042c. \n\n\u0415\u0441\u043b\u0438 \u0437\u0430\u043a\u0440\u044b\u0442\u044c \u0433\u043b\u0430\u0437\u0430 \u043d\u0430 \u0436\u0435\u0441\u0442\u043e\u043a\u0438\u0439 \u043f\u0440\u043e\u0446\u0435\u0441\u0441 \u0443\u0431\u0438\u0439\u0441\u0442\u0432\u0430 \u0436\u0438\u0432\u043e\u0433\u043e \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 (\u043f\u043e\u0441\u043b\u0435 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u043c\u043d\u043e\u0433\u0438\u0435 \u0432\u0440\u044f\u0434 \u043b\u0438 \u0441\u043e\u0433\u043b\u0430\u0441\u044f\u0442\u0441\u044f \u0435\u0441\u0442\u044c \u0441\u0432\u043e\u044e \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u0443\u044e \u0435\u0434\u0443), \u0442\u043e \u043d\u0435 \u043c\u0435\u043d\u0435\u0435 \u0442\u044f\u0436\u0435\u043b\u044b\u043c \u0444\u0430\u043a\u0442\u043e\u0440\u043e\u043c \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043d\u0430\u0441\u0438\u043b\u044c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043d\u0435\u0432\u043e\u043b\u044c\u043d\u043e\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0433\u043e \u0432 \u0443\u0436\u0430\u0441\u043d\u044b\u0445 \u0443\u0441\u043b\u043e\u0432\u0438\u044f\u0445. \u041a\u043e\u0440\u043e\u0432\u044b \u0432\u0441\u044e \u0436\u0438\u0437\u043d\u044c \u0441\u0442\u043e\u044f\u0442 \u0432 \u0441\u0442\u043e\u0439\u043b\u0430\u0445, \u043f\u0440\u0438\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u043a \u0441\u0432\u043e\u0435\u043c\u0443 \u043c\u0435\u0441\u0442\u0443, \u0430 \u043d\u043e\u0432\u043e\u0440\u043e\u0436\u0434\u0435\u043d\u043d\u044b\u0445 \u0442\u0435\u043b\u044f\u0442 \u0437\u0430\u0431\u0438\u0440\u0430\u044e\u0442 \u0441\u0440\u0430\u0437\u0443 \u0436\u0435 \u043f\u043e\u0441\u043b\u0435 \u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e\u0431\u044b \u043c\u043e\u043b\u043e\u043a\u043e, \u043f\u0440\u0435\u0434\u043d\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043d\u043e\u0435 \u0435\u043c\u0443, \u0431\u044b\u043b\u043e \u0434\u043e\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0443. \u041a\u0443\u0440\u044b \u0436\u0438\u0432\u0443\u0442 \u0432 \u043d\u0430\u0441\u0442\u043e\u043b\u044c\u043a\u043e \u0442\u0435\u0441\u043d\u044b\u0445 \u043a\u043b\u0435\u0442\u043a\u0430\u0445, \u0447\u0442\u043e \u043d\u0430 \u043a\u0430\u0436\u0434\u0443\u044e \u043f\u0442\u0438\u0446\u0443 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u043b\u043e\u0449\u0430\u0434\u044c \u0440\u0430\u0437\u043c\u0435\u0440\u043e\u043c \u043e\u0434\u0438\u043d \u0430\u043b\u044c\u0431\u043e\u043c\u043d\u044b\u0439 \u043b\u0438\u0441\u0442, \u0438 \u0447\u0442\u043e\u0431\u044b \u043e\u043d\u0438 \u043d\u0435 \u0446\u0435\u043f\u043b\u044f\u043b\u0438 \u0434\u0440\u0443\u0433 \u0434\u0440\u0443\u0433\u0430, \u0438\u043c \u043e\u0431\u0440\u0435\u0437\u0430\u044e\u0442 \u0447\u0430\u0441\u0442\u0438 \u043a\u043b\u044e\u0432\u0430. \u041f\u043e\u043c\u0438\u043c\u043e \u044d\u0442\u043e\u0433\u043e, \u043f\u0442\u0438\u0446 (\u043a\u0443\u0440, \u0446\u044b\u043f\u043b\u044f\u0442, \u0443\u0442\u043e\u043a) \u043d\u0430\u0441\u0438\u043b\u044c\u043d\u043e \u043e\u0442\u043a\u0430\u0440\u043c\u043b\u0438\u0432\u0430\u044e\u0442 \u0438 \u043d\u0430\u043a\u0430\u0447\u0438\u0432\u0430\u044e\u0442 \u0430\u043d\u0442\u0438\u0431\u0438\u043e\u0442\u0438\u043a\u0430\u043c\u0438 \u0434\u043b\u044f \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u043d\u0430\u0431\u043e\u0440\u0430 \u043c\u0430\u0441\u0441\u044b, \u0432\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u0447\u0435\u0433\u043e \u043e\u043d\u0438 \u043d\u0435 \u043c\u043e\u0433\u0443\u0442 \u0445\u043e\u0434\u0438\u0442\u044c \u0438\u0437-\u0437\u0430 \u043d\u0435\u0434\u043e\u0440\u0430\u0437\u0432\u0438\u0442\u043e\u0441\u0442\u0438 \u043a\u043e\u0441\u0442\u0435\u0439. \u041c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0445 \u043f\u043e\u0440\u043e\u0441\u044f\u0442 \u043a\u0430\u0441\u0442\u0440\u0438\u0440\u0443\u044e\u0442 \u0431\u0435\u0437 \u043e\u0431\u0435\u0437\u0431\u043e\u043b\u0438\u0432\u0430\u043d\u0438\u044f \u0434\u043b\u044f \u0441\u043a\u043e\u0440\u0435\u0439\u0448\u0435\u0433\u043e \u043d\u0430\u0431\u043e\u0440\u0430 \u0432\u0435\u0441\u0430. \u0415\u0441\u0442\u044c \u043c\u043d\u043e\u0433\u043e \u0434\u0440\u0443\u0433\u0438\u0445 \u0444\u0430\u043a\u0442\u043e\u0432 \u043e \u0436\u0435\u0441\u0442\u043e\u043a\u043e\u043c \u043e\u0431\u0440\u0430\u0449\u0435\u043d\u0438\u0438 \u0441 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0438\u043c\u0435\u044e\u0442 \u043f\u043e\u0447\u0442\u0438 \u0442\u0430\u043a\u0443\u044e \u0436\u0435 \u043d\u0435\u0440\u0432\u043d\u0443\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u0443, \u043a\u0430\u043a \u0438 \u043c\u044b \u0441 \u0432\u0430\u043c\u0438, \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u044e\u0442 \u0431\u043e\u043b\u044c \u0438 \u0441\u0442\u0440\u0430\u0434\u0430\u043d\u0438\u0435. \u041c\u044b \u043d\u0435 \u0441\u0442\u0430\u043b\u0438 \u043f\u0440\u0438\u043a\u0440\u0435\u043f\u043b\u044f\u0442\u044c \u0432 \u0441\u0442\u0430\u0442\u044c\u044e \u0448\u043e\u043a\u0438\u0440\u0443\u044e\u0449\u0438\u0435 \u0444\u043e\u0442\u043e \u0441 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0432\u043e\u0434\u0447\u0435\u0441\u043a\u0438\u0445 \u0444\u0435\u0440\u043c, \u043d\u043e \u043f\u0440\u0438 \u0436\u0435\u043b\u0430\u043d\u0438\u0438 \u0432\u044b \u0441\u0430\u043c\u0438 \u043c\u043e\u0436\u0435\u0442\u0435 \u043f\u043e\u0438\u043d\u0442\u0435\u0440\u0435\u0441\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u044d\u0442\u0438\u043c \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043d\u0438\u043c\u0430\u0442\u044c, \u0437\u0430 \u0447\u0442\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u044b \u043f\u043b\u0430\u0442\u0438\u0442\u0435 \u0434\u0435\u043d\u044c\u0433\u0438 \u0438 \u0447\u0442\u043e \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0443 \u0432\u0430\u0441 \u043d\u0430 \u0441\u0442\u043e\u043b\u0435. \n\n\u041a \u0442\u043e\u043c\u0443 \u0436\u0435, \u0436\u0435\u0441\u0442\u043e\u043a\u043e\u0441\u0442\u044c \u043f\u043e\u0440\u043e\u0436\u0434\u0430\u0435\u0442 \u0436\u0435\u0441\u0442\u043e\u043a\u043e\u0441\u0442\u044c \u0438 \u043d\u0430\u043c \u043d\u0435 \u0443\u0434\u0430\u0441\u0442\u0441\u044f \u0441\u0434\u0435\u043b\u0430\u0442\u044c \u043c\u0438\u0440 \u043b\u0443\u0447\u0448\u0435, \u0434\u043e\u0431\u0440\u0435\u0435 \u0438 \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u0435\u0435, \u043f\u043e\u043a\u0430 \u043c\u044b \u043d\u0435 \u0438\u0437\u0431\u0430\u0432\u0438\u043c\u0441\u044f \u043e\u0442 \u043d\u0430\u0441\u0438\u043b\u0438\u044f \u043f\u043e \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044e \u043a \u0434\u0440\u0443\u0433\u0438\u043c \u0436\u0438\u0432\u044b\u043c \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043c.\n\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: http://ecobeing.ru/articles/livestock-farming-harms-ecology/"},C.aj,t.c)
C.zv=new H.aA(3,{id:11,title:"\u041a\u0430\u043a \u043a\u0430\u0441\u0441\u043e\u0432\u044b\u0435 \u0447\u0435\u043a\u0438 \u0432\u0440\u0435\u0434\u044f\u0442 \u043d\u0430\u0448\u0435\u043c\u0443 \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044e \u0438 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435",text:"\u041a\u0430\u0441\u0441\u043e\u0432\u044b\u0435 \u0447\u0435\u043a\u0438 \u043c\u043e\u0433\u0443\u0442 \u043d\u0430\u043d\u0435\u0441\u0442\u0438 \u0432\u0440\u0435\u0434 \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044e \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 \u0438 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c. \u041f\u0440\u0438 \u044d\u0442\u043e\u043c \u0430\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u044b \u0447\u0435\u043a\u0430\u043c \u0435\u0449\u0435 \u043d\u0435 \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043b\u0438 \u0438 \u043c\u044b \u043a\u0430\u0436\u0434\u044b\u0439 \u0434\u0435\u043d\u044c \u0432\u044b\u043d\u0443\u0436\u0434\u0435\u043d\u044b \u043f\u0440\u0438\u043a\u0430\u0441\u0430\u0442\u044c\u0441\u044f \u043a \u044d\u0442\u043e\u043c\u0443 \u043e\u043f\u0430\u0441\u043d\u043e\u043c\u0443 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044e. \n\n\u0412 \u0420\u043e\u0441\u0441\u0438\u0438 \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u043e\u043a\u043e\u043b\u043e 10 \u0442\u044b\u0441\u044f\u0447 \u0442\u043e\u043d\u043d \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0438. \u0418\u0437 \u043d\u0435\u0435 \u0434\u0435\u043b\u0430\u044e\u0442 \u0447\u0435\u043a\u0438, \u0431\u0443\u043c\u0430\u0433\u0443 \u0434\u043b\u044f \u0444\u0430\u043a\u0441\u043e\u0432, \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u0432 \u043c\u0435\u0434\u0438\u0446\u0438\u043d\u0435. \n\u0412 \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043e\u043f\u0430\u0441\u043d\u043e\u0435 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u043e \u0411\u0438\u0441\u0444\u0435\u043d\u043e\u043b \u0410. \u0414\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u043f\u043e\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0447\u0435\u043a \u0432 \u0440\u0443\u043a\u0430\u0445 \u043f\u044f\u0442\u044c \u0441\u0435\u043a\u0443\u043d\u0434, \u0447\u0442\u043e\u0431\u044b 1 \u043c\u043a\u0433 \u044d\u0442\u043e\u0433\u043e \u0442\u043e\u043a\u0441\u0438\u043d\u0430 \u043f\u0440\u043e\u043d\u0438\u043a\u043b\u043e \u0432 \u043a\u043e\u0436\u0443. \u0414\u043e\u0437\u0430 \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0442\u0441\u044f \u0434\u0435\u0441\u044f\u0442\u0438\u043a\u0440\u0430\u0442\u043d\u043e, \u0435\u0441\u043b\u0438 \u0443 \u0432\u0430\u0441 \u0431\u0443\u0434\u0443\u0442 \u0432\u043b\u0430\u0436\u043d\u044b\u0435 \u0440\u0443\u043a\u0438 \u0438\u043b\u0438 \u043d\u0430\u043c\u043e\u043a\u043d\u0435\u0442 \u0441\u0430\u043c\u0430 \u0431\u0443\u043c\u0430\u0436\u043a\u0430. \n\n\u0415\u0441\u043b\u0438 \u0432 \u0434\u0435\u043d\u044c \u0432\u044b \u043f\u0440\u0438\u043a\u0430\u0441\u0430\u0435\u0442\u0435\u0441\u044c \u0431\u043e\u043b\u0435\u0435 \u0447\u0435\u043c \u043a \u0434\u0435\u0441\u044f\u0442\u0438 \u0447\u0435\u043a\u0430\u043c, \u0434\u043e\u0437\u0430 \u0442\u043e\u043a\u0441\u0438\u043d\u0430, \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043d\u043e\u0433\u043e \u0432\u0430\u043c\u0438, \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 71 \u043c\u043a\u0433/\u0441\u0443\u0442.\n\n\u041f\u043e\u043a\u0430 \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f, \u0447\u0442\u043e \u044d\u0442\u043e \u0432 \u0434\u0435\u0441\u044f\u0442\u043a\u0438 \u0440\u0430\u0437 \u043c\u0435\u043d\u044c\u0448\u0435 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u043c\u043e\u0439 \u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u0434\u043e\u0437\u044b, \u043d\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u044e\u0442\u0441\u044f \u0438 \u0443\u0447\u0435\u043d\u044b\u0435 \u0441\u043a\u043b\u043e\u043d\u044f\u044e\u0442\u0441\u044f \u043a \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0434\u0430\u0436\u0435 \u0441\u0442\u043e\u043b\u044c \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0430\u044f \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044f \u043e\u043f\u0430\u0441\u043d\u0430 \u0434\u043b\u044f \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f. \n\n\u0412\u0435\u0449\u0435\u0441\u0442\u0432\u043e \u0438\u043c\u0435\u0435\u0442 \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u043d\u0443\u044e \u0441\u0445\u043e\u0436\u0435\u0441\u0442\u044c \u0441 \u0436\u0435\u043d\u0441\u043a\u0438\u043c \u043f\u043e\u043b\u043e\u0432\u044b\u043c \u0433\u043e\u0440\u043c\u043e\u043d\u043e\u043c \u044d\u0441\u0442\u0440\u043e\u0433\u0435\u043d\u043e\u043c \u0438 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043d\u0430 \u043c\u043e\u0437\u0433 \u0438 \u0440\u0435\u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0438\u0432\u043d\u0443\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430. \u041c\u043e\u0436\u0435\u0442 \u0441\u043f\u0440\u043e\u0432\u043e\u0446\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043e\u043d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0437\u0430\u0431\u043e\u043b\u0435\u0432\u0430\u043d\u0438\u044f - \u0440\u0430\u043a \u043f\u0440\u043e\u0441\u0442\u0430\u0442\u044b, \u044f\u0438\u0447\u0435\u043a, \u043c\u043e\u043b\u043e\u0447\u043d\u044b\u0445 \u0436\u0435\u043b\u0435\u0437. \n\n\u0415\u0441\u0442\u044c \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f, \u0434\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0449\u0438\u0435, \u0447\u0442\u043e \u0411\u0438\u0441\u0444\u0435\u043d\u043e\u043b \u0410 \u043f\u0440\u0438\u0432\u043e\u0434\u0438\u0442 \u043a \u0437\u0430\u0434\u0435\u0440\u0436\u043a\u0435 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044f \u043c\u043e\u0437\u0433\u0430, \u0430\u0443\u0442\u0438\u0437\u043c\u0443, \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044e \u0441\u0430\u0445\u0430\u0440\u043d\u043e\u0433\u043e \u0434\u0438\u0430\u0431\u0435\u0442\u0430, \u043e\u0436\u0438\u0440\u0435\u043d\u0438\u044f \u0438 \u0441\u0435\u0440\u0434\u0435\u0447\u043d\u043e-\u0441\u043e\u0441\u0443\u0434\u0438\u0441\u0442\u044b\u0445 \u0437\u0430\u0431\u043e\u043b\u0435\u0432\u0430\u043d\u0438\u0439. \n\n\u0412\u043e \u043c\u043d\u043e\u0433\u0438\u0445 \u0441\u0442\u0440\u0430\u043d\u0430\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u043e \u0443\u0436\u0435 \u0432\u043d\u0435\u0441\u043b\u0438 \u0432 \u0441\u043f\u0438\u0441\u043e\u043a \u043e\u043f\u0430\u0441\u043d\u044b\u0445 \u0445\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432. \u041d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0432 \u041a\u0430\u043d\u0430\u0434\u0435 \u0435\u0449\u0435 10 \u043b\u0435\u0442 \u043d\u0430\u0437\u0430\u0434 \u0437\u0430\u043f\u0440\u0435\u0442\u0438\u043b\u0438 \u0431\u0443\u0442\u044b\u043b\u043e\u0447\u043a\u0438 \u0434\u043b\u044f \u043a\u043e\u0440\u043c\u043b\u0435\u043d\u0438\u044f, \u0432 \u0441\u043e\u0441\u0442\u0430\u0432 \u043f\u043b\u0430\u0441\u0442\u043c\u0430\u0441\u0441\u044b \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0432\u0445\u043e\u0434\u0438\u043b \u0411\u0438\u0441\u0444\u0435\u043d\u043e\u043b-\u0410. \n\n\u041f\u0440\u0438 \u044d\u0442\u043e\u043c \u043c\u044b \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e \u0445\u043e\u0442\u044f \u0431\u044b \u0440\u0430\u0437 \u0432 \u0434\u0435\u043d\u044c \u0431\u0435\u0440\u0435\u043c \u0432 \u0440\u0443\u043a\u0438 \u0447\u0435\u043a\u0438, \u0432 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u044d\u0442\u043e \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u043e. \n\n\u0418\u043c\u0435\u043d\u043d\u043e \u0438\u0437-\u0437\u0430 \u0411\u0438\u0441\u0444\u0435\u043d\u043e\u043b\u0430 \u0410 \u043a\u0430\u0441\u0441\u043e\u0432\u044b\u0435 \u0447\u0435\u043a\u0438 \u043d\u0435 \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442 \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443: \u043f\u043e\u043c\u0438\u043c\u043e \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0432 \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0435 \u043c\u0430\u043b\u043e \u0446\u0435\u043b\u043b\u044e\u043b\u043e\u0437\u044b \u0438 \u0432\u044b\u0445\u043e\u0434 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0433\u043e \u0441\u044b\u0440\u044c\u044f \u0438\u0437 \u043d\u0435\u0435 \u043e\u0447\u0435\u043d\u044c \u043d\u0438\u0437\u043a\u0438\u0439, \u043e\u043d\u0430 \u043c\u043e\u0436\u0435\u0442 \u0437\u0430\u0433\u0440\u044f\u0437\u043d\u0438\u0442\u044c \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u0443\u044e \u043c\u0430\u043a\u0443\u043b\u0430\u0442\u0443\u0440\u0443 \u0442\u043e\u043a\u0441\u0438\u043d\u0430\u043c\u0438. \u041f\u043e\u044d\u0442\u043e\u043c\u0443 \u0441\u0434\u0430\u0432\u0430\u0442\u044c \u0447\u0435\u043a\u0438 \u0432 \u043c\u0430\u043a\u0443\u043b\u0430\u0442\u0443\u0440\u0443 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0431\u0435\u0441\u043f\u043e\u043b\u0435\u0437\u043d\u043e, \u043d\u043e \u0438 \u0432\u0440\u0435\u0434\u043d\u043e.\n\n\u0421\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u044b \u0444\u0438\u043d\u0441\u043a\u043e\u0439 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 Jujo Thermal Kautta \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b\u0438 \u043d\u043e\u0432\u044b\u0435 \u0432\u0438\u0434\u044b \u043f\u043e\u043a\u0440\u044b\u0442\u0438\u044f \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0438, \u0437\u0430\u043c\u0435\u043d\u0438\u0432 \u0444\u0435\u043d\u043e\u043b \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u043c\u0438 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0430\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0430\u0431\u0441\u043e\u043b\u044e\u0442\u043d\u043e \u043d\u0435 \u0432\u043b\u0438\u044f\u044e\u0442 \u043d\u0430 \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u0435 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430. \n\n\u041d\u043e \u043f\u043e\u043a\u0430 \u0438\u0445 \u0442\u0435\u0440\u043c\u043e\u043b\u0435\u043d\u0442\u0430 \u043d\u0435 \u043d\u0430\u0448\u043b\u0430 \u043c\u0430\u0441\u0441\u043e\u0432\u043e\u0433\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u044f, \u0442\u0430\u043a \u0447\u0442\u043e \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u043e\u0442\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f \u043e\u0442 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0438 \u0441 \u0411\u0438\u0441\u0444\u0435\u043d\u043e\u043b\u043e\u043c-\u0410 \u043d\u0435 \u043f\u043e\u043b\u0443\u0447\u0438\u0442\u0441\u044f. \n\n\u041e\u0434\u043d\u0430\u043a\u043e \u043a\u0430\u0436\u0434\u044b\u0439 \u0438\u0437 \u043d\u0430\u0441 \u043c\u043e\u0436\u0435\u0442 \u043c\u0438\u043d\u0438\u043c\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0435\u0435 \u043f\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u0435 \u043d\u0430 \u0433\u043e\u0440\u043e\u0434\u0441\u043a\u0438\u0445 \u0441\u0432\u0430\u043b\u043a\u0430\u0445. \u041d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044f \u0431\u0430\u043d\u043a\u043e\u043c\u0430\u0442\u044b, \u043c\u043e\u0436\u043d\u043e \u043e\u0442\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f \u043e\u0442 \u043f\u0435\u0447\u0430\u0442\u0438 \u0447\u0435\u043a\u0430 \u043f\u0440\u0438 \u0432\u044b\u0434\u0430\u0447\u0435 \u043d\u0430\u043b\u0438\u0447\u043d\u044b\u0445 \u0438 \u0437\u0430\u043f\u0440\u043e\u0441\u0430\u0445 \u0431\u0430\u043b\u0430\u043d\u0441\u0430. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \xab\u043c\u043e\u0431\u0438\u043b\u044c\u043d\u044b\u0439 \u0431\u0430\u043d\u043a\xbb \u0438\u043b\u0438 \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u0435 \u0437\u0430\u043f\u0440\u043e\u0441 \u0431\u0430\u043b\u0430\u043d\u0441\u0430 \u043d\u0430 \u044d\u043a\u0440\u0430\u043d \u043c\u043e\u043d\u0438\u0442\u043e\u0440\u0430. \u0421\u0442\u0430\u0440\u0430\u0439\u0442\u0435\u0441\u044c \u0447\u0430\u0449\u0435 \u0441\u043e\u0432\u0435\u0440\u0448\u0430\u0442\u044c \u043e\u043d\u043b\u0430\u0439\u043d-\u043f\u043e\u043a\u0443\u043f\u043a\u0438 \u0432\u043c\u0435\u0441\u0442\u043e \u0442\u043e\u0433\u043e, \u0447\u0442\u043e\u0431\u044b \u0438\u0434\u0442\u0438 \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d, \u0433\u0434\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u0446\u044b \u043f\u043e \u0437\u0430\u043a\u043e\u043d\u0443 \u043e\u0431\u044f\u0437\u0430\u043d\u044b \u0432\u044b\u0431\u0438\u0442\u044c \u0447\u0435\u043a. \n\n\u0414\u0430\u0436\u0435 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u044f\u0441\u044c \u043d\u0430 \u043e\u0431\u0435\u0434, \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u043c\u0438\u043d\u0438\u043c\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u0447\u0435\u043a\u043e\u0432, \u0435\u0441\u043b\u0438 \u0432 \u0437\u0430\u0432\u0435\u0434\u0435\u043d\u0438\u044f\u0445 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u043f\u0438\u0442\u0430\u043d\u0438\u044f \u043e\u0444\u043e\u0440\u043c\u0438\u0442\u0435 \u0437\u0430\u043a\u0430\u0437 \u0447\u0435\u0440\u0435\u0437 \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0442\u0435\u0440\u043c\u0438\u043d\u0430\u043b\u044b. \u0412\u0430\u043c, \u043a\u043e\u043d\u0435\u0447\u043d\u043e, \u043d\u0430\u043f\u0435\u0447\u0430\u0442\u0430\u044e\u0442 \u0442\u0430\u043b\u043e\u043d \u0441 \u043d\u043e\u043c\u0435\u0440\u043e\u043c \u0437\u0430\u043a\u0430\u0437\u0430, \u043d\u043e \u0437\u0430\u0442\u043e \u043e\u0442 \u0447\u0435\u043a\u0430 \u043c\u043e\u0436\u043d\u043e \u0431\u0443\u0434\u0435\u0442 \u043e\u0442\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f. \n\n\u041d\u0443 \u0430 \u0435\u0441\u043b\u0438 \u0431\u0435\u0437 \u0447\u0435\u043a\u0430 \u043d\u0435 \u043e\u0431\u043e\u0439\u0442\u0438\u0441\u044c, \u0441\u0442\u0430\u0440\u0430\u0439\u0442\u0435\u0441\u044c \u0431\u0440\u0430\u0442\u044c \u0435\u0433\u043e \u0440\u0443\u043a\u0430\u043c\u0438 \u0432 \u043f\u0435\u0440\u0447\u0430\u0442\u043a\u0430\u0445. \u041e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u0430\u043a\u0442\u0443\u0430\u043b\u0435\u043d \u0441\u043e\u0432\u0435\u0442 \u0434\u043b\u044f \u0442\u0435\u0445, \u043a\u043e\u043c\u0443 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e \u043f\u0440\u0438\u043a\u0430\u0441\u0430\u0442\u044c\u0441\u044f \u043a \u0442\u0435\u0440\u043c\u043e\u0431\u0443\u043c\u0430\u0433\u0435 - \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u043f\u0440\u043e\u0434\u0430\u0432\u0446\u0430\u043c \u0432 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0430\u0445. \n\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://recyclemag.ru/article/kassovie-vredyat-nashemu-zdorovyu-okruzhayuschei-srede"},C.aj,t.c)
C.zw=new H.aA(3,{id:12,title:"6 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0438\u043d\u0438\u0446\u0438\u0430\u0442\u0438\u0432 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 SPLAT",text:"\u0420\u043e\u0441\u0441\u0438\u0439\u0441\u043a\u0438\u0439 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u044c \u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u043f\u043e \u0443\u0445\u043e\u0434\u0443 \u0437\u0430 \u043f\u043e\u043b\u043e\u0441\u0442\u044c\u044e \u0440\u0442\u0430 \u043e\u0431\u043e\u0441\u043d\u043e\u0432\u0430\u043b\u0441\u044f \u043d\u0430 \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0435, \u0431\u0435\u0440\u0435\u0436\u0435\u0442 \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u044b\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044b, \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u043b\u0435\u0441\u0430, \u0430 \u043f\u043e\u0442\u0440\u0435\u0431\u0438\u0442\u0435\u043b\u044f\u043c \u043f\u0440\u0435\u0434\u043b\u0430\u0433\u0430\u0435\u0442 \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u0443\u044e \u044d\u043a\u043e\u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044e, \u0443\u043f\u0430\u043a\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u0432 100% \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u0439 \u043f\u043b\u0430\u0441\u0442\u0438\u043a.\n\n\u0421\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0430 \n\u042d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0441\u0442\u044c \u2015 \u043e\u0434\u0438\u043d \u0438\u0437 \u0447\u0435\u0442\u044b\u0440\u0435\u0445 \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u043c\u0438 \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f SPLAT. \u0421 2010 \u0433\u043e\u0434\u0430 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0441\u044f \u043d\u0430 \u0431\u0430\u0437\u0435 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0438 Organic Pharmaceuticals. \u0417\u0434\u0430\u043d\u0438\u0435 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438 \u0447\u0438\u0441\u0442\u043e\u043c \u0440\u0430\u0439\u043e\u043d\u0435 \u0412\u0430\u043b\u0434\u0430\u044f (\u041d\u043e\u0432\u0433\u043e\u0440\u043e\u0434\u0441\u043a\u0430\u044f \u043e\u0431\u043b\u0430\u0441\u0442\u044c). \n\n\u041f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0442\u0435\u0445\u043d\u043e\u043b\u043e\u0433\u0438\u0438 \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u044b \u043d\u0430 \u0441\u0431\u0435\u0440\u0435\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u043e\u0432. \u0424\u0430\u0431\u0440\u0438\u043a\u0430, \u043f\u043e\u0441\u0442\u0440\u043e\u0435\u043d\u043d\u0430\u044f \u043f\u043e \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0443 \u043a\u0430\u043f\u0441\u0443\u043b\u044b, \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u044d\u043a\u043e\u043d\u043e\u043c\u0438\u0442\u044c \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u044d\u043d\u0435\u0440\u0433\u0438\u044e \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0442\u044c \u0432\u044b\u0441\u043e\u043a\u0443\u044e \u0442\u0435\u043f\u043b\u043e\u0438\u0437\u043e\u043b\u044f\u0446\u0438\u044e. \n\n\u042d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e \nSPLAT \u0441\u0442\u0440\u0435\u043c\u0438\u0442\u0441\u044f \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e \u043e\u0447\u0438\u0441\u0442\u0438\u0442\u044c \u0441\u044b\u0440\u044c\u0435 \u043d\u0430 \u0432\u0445\u043e\u0434\u0435 \u0438 \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u0432\u044b\u0445\u043e\u0434\u0435. \u041b\u0438\u0432\u043d\u0435\u0432\u044b\u0435, \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0438 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u0441\u0442\u043e\u0447\u043d\u044b\u0435 \u0432\u043e\u0434\u044b \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0442 \u0442\u0440\u0435\u0445\u0441\u0442\u0443\u043f\u0435\u043d\u0447\u0430\u0442\u0443\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u0443 \u043e\u0447\u0438\u0441\u0442\u043a\u0438. \u041c\u043d\u043e\u0433\u043e\u043a\u0440\u0430\u0442\u043d\u043e \u043e\u0447\u0438\u0449\u0430\u044e\u0442\u0441\u044f \u0438 \u0432\u043e\u0437\u0434\u0443\u0448\u043d\u044b\u0435 \u0432\u044b\u0431\u0440\u043e\u0441\u044b. \u042d\u0442\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u043c\u0438\u043d\u0438\u043c\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0432\u043e\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043d\u0430 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0443\u044e \u0441\u0440\u0435\u0434\u0443. \u041f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e SPLAT \u043f\u0440\u0438\u0437\u043d\u0430\u043d\u043e CO2-\u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u043c. \n\n\u041a\u0440\u043e\u043c\u0435 \u0441\u043e\u0431\u043b\u044e\u0434\u0435\u043d\u0438\u044f \u0441\u0430\u043d\u0438\u0442\u0430\u0440\u043d\u043e-\u0433\u0438\u0433\u0438\u0435\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0438 \u044d\u043a\u043e\u043d\u043e\u0440\u043c, \u043d\u0430 \u0444\u0430\u0431\u0440\u0438\u043a\u0435 \u0432\u044b\u0441\u0442\u0440\u043e\u0435\u043d\u0430 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043c\u0435\u043d\u0435\u0434\u0436\u043c\u0435\u043d\u0442\u0430. \u042d\u0442\u043e \u0437\u043d\u0430\u0447\u0438\u0442, \u0447\u0442\u043e \u043f\u0440\u0435\u0434\u043f\u0440\u0438\u044f\u0442\u0438\u0435 \u043c\u043e\u0436\u0435\u0442 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c \u0440\u0438\u0441\u043a\u0430\u043c\u0438 \u0438 \u0438\u0441\u043a\u043b\u044e\u0447\u0438\u0442\u044c \u0432\u043e\u0437\u043d\u0438\u043a\u043d\u043e\u0432\u0435\u043d\u0438\u0435 \u0430\u0432\u0430\u0440\u0438\u0439\u043d\u044b\u0445 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0439 \u2015 \u0440\u043e\u0437\u043b\u0438\u0432\u0430 \u0441\u044b\u0440\u044c\u044f \u0438\u043b\u0438 \u043f\u043e\u0436\u0430\u0440\u0430. \u0421\u043e\u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0438 \u043c\u0435\u0436\u0434\u0443\u043d\u0430\u0440\u043e\u0434\u043d\u044b\u043c \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0430\u043c \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u0430\u043c\u0438 \u0441\u0438\u0441\u0442\u0435\u043c\u044b ISO 14001, ISO 9001 \u0438 GMP cosmetics .\n\n\u041d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0435 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b \n\u0412 \u0441\u043e\u0441\u0442\u0430\u0432 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 SPLAT \u0432\u0445\u043e\u0434\u044f\u0442 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b \u043b\u0443\u0447\u0448\u0438\u0445 \u043c\u0438\u0440\u043e\u0432\u044b\u0445 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u0439, \u043e\u043d\u0438 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b \u0438 \u0440\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u043e\u0432\u0430\u043d\u044b \u0434\u043b\u044f \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0433\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u044f. \u0424\u043e\u0440\u043c\u0443\u043b\u044b \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u044e\u0442\u0441\u044f: \u0443\u0441\u0442\u0430\u0440\u0435\u0432\u0448\u0438\u0435 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u043d\u0430 \u043f\u0435\u0440\u0435\u0434\u043e\u0432\u044b\u0435 \u043d\u0430\u0443\u0447\u043d\u044b\u0435 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0438. \n\n\u0412 \u043a\u043e\u0441\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u0445 \u043d\u0435\u0442 \u0442\u0440\u0438\u043a\u043b\u043e\u0437\u0430\u043d\u0430, \u0445\u043b\u043e\u0440\u0433\u0435\u043a\u0441\u0438\u0434\u0438\u043d\u0430 \u0438 \u0444\u0442\u043e\u0440\u0430. \u041f\u0440\u0438 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u043f\u043e \u0443\u0445\u043e\u0434\u0443 \u0437\u0430 \u0434\u043e\u043c\u043e\u043c \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0430 \u043d\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442 \u0441\u0443\u043b\u044c\u0444\u0430\u0442\u044b, \u0444\u043e\u0441\u0444\u0430\u0442\u044b, \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043d\u044b\u0435 \u041f\u0410\u0412, \u0445\u043b\u043e\u0440, \u043d\u0435\u0444\u0442\u0435\u043f\u0440\u043e\u0434\u0443\u043a\u0442\u044b, \u0438\u0441\u043a\u0443\u0441\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0430\u0440\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0442\u043e\u0440\u044b, \u043a\u0440\u0430\u0441\u0438\u0442\u0435\u043b\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043c\u043e\u0433\u0443\u0442 \u043d\u0430\u043d\u0435\u0441\u0442\u0438 \u0432\u0440\u0435\u0434 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0443 \u0438 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u0435. \u0417\u0430 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0441\u0442\u044c \u044d\u0442\u0430 \u043b\u0438\u043d\u0435\u0439\u043a\u0430 \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u0438 \u043e\u0442\u043c\u0435\u0447\u0435\u043d\u0430 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442\u043e\u043c \xab\u041b\u0438\u0441\u0442\u043e\u043a \u0436\u0438\u0437\u043d\u0438\xbb \u2015 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0440\u043e\u0441\u0441\u0438\u0439\u0441\u043a\u043e\u0439 \u044d\u043a\u043e\u043c\u0430\u0440\u043a\u0438\u0440\u043e\u0432\u043a\u043e\u0439, \u043f\u0440\u0438\u0437\u043d\u0430\u043d\u043d\u043e\u0439 \u043c\u0435\u0436\u0434\u0443\u043d\u0430\u0440\u043e\u0434\u043d\u044b\u043c \u0441\u043e\u043e\u0431\u0449\u0435\u0441\u0442\u0432\u043e\u043c.\n\n\u0411\u0435\u0437 \u0442\u0435\u0441\u0442\u043e\u0432 \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \n\u041a\u043e\u043c\u043f\u0430\u043d\u0438\u044f SPLAT \u043d\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0432\u043e\u044e \u043f\u0440\u043e\u0434\u0443\u043a\u0446\u0438\u044e \u043d\u0430 \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445. \u0412\u0441\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f, \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0438 \u043d\u0430 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u044c \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f, \u043f\u0440\u043e\u0432\u043e\u0434\u044f\u0442\u0441\u044f in-vitro \u0432 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u044f\u0445 \u0438 \u041d\u0430\u0443\u0447\u043d\u043e\u043c \u0446\u0435\u043d\u0442\u0440\u0435 R&D. \n\nAnimal friendly-\u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 \u0438 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u043a\u0430\u0442 \u043f\u043e \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0443 \u0425\u0430\u043b\u044f\u043b\u044c \u0442\u0430\u043a \u0436\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442, \u0447\u0442\u043e \u0432 \u0441\u043e\u0441\u0442\u0430\u0432\u0430\u0445 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 \u043d\u0435\u0442 \u0433\u0435\u043d\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043c\u043e\u0434\u0438\u0444\u0438\u0446\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u0432\u0435\u0449\u0435\u0441\u0442\u0432 \u0438 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u0432 \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f.\n\n\u0411\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u044b\u0435 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044b \n\u0412\u0441\u0435 \u043e\u043f\u043e\u043b\u0430\u0441\u043a\u0438\u0432\u0430\u0442\u0435\u043b\u0438 \u0434\u043b\u044f \u043f\u043e\u043b\u043e\u0441\u0442\u0438 \u0440\u0442\u0430 \u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u0441\u0435\u0440\u0438\u0438 BioMio \u0438\u043c\u0435\u044e\u0442 100% \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0443\u044e \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443. \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u0443\u0442\u0438\u043b\u0438\u0437\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u0432 \u0441\u0440\u0435\u0434\u0435 \u0438 \u0434\u0435\u0442\u0441\u043a\u0438\u0435 \u0432\u043b\u0430\u0436\u043d\u044b\u0435 \u0441\u0430\u043b\u0444\u0435\u0442\u043a\u0438 \u0438\u0437 \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u043e\u0439 \u0432\u0438\u0441\u043a\u043e\u0437\u044b. \u0421\u0435\u0439\u0447\u0430\u0441 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432 \u043f\u043e\u0438\u0441\u043a\u0435 \u043f\u0430\u0440\u0442\u043d\u0435\u0440\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0441\u043c\u043e\u0433 \u0431\u044b \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0438\u0442\u044c \u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0449\u0443\u044e \u0431\u0438\u043e\u0440\u0430\u0437\u043b\u0430\u0433\u0430\u0435\u043c\u0443\u044e \u0443\u043f\u0430\u043a\u043e\u0432\u043a\u0443 \u0434\u043b\u044f \u0432\u0441\u0435\u0445 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 SPLAT, \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u044e\u0449\u0443\u044e \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0442\u044c \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u043d\u0430\u0442\u0443\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u0432.\n\n\u0423\u0447\u0430\u0441\u0442\u0438\u0435 \u0432 \u044d\u043a\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430\u0445 \n\u041a\u043e\u043c\u043f\u0430\u043d\u0438\u044f SPLAT \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u043e \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0446\u0435\u043d\u0442 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u043e\u0439 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u043e\u0442\u0445\u043e\u0434\u043e\u0432. \u0421\u0435\u0433\u043e\u0434\u043d\u044f \u043e\u043d \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 60%. \u0422\u0430\u043a, \u0432 2014 \u0433\u043e\u0434\u0443 \u0441\u043e\u0442\u0440\u0443\u0434\u043d\u0438\u043a\u0438 \u044d\u043a\u043e\u0444\u0430\u0431\u0440\u0438\u043a\u0438 \u0441\u0434\u0430\u043b\u0438 \u0431\u043e\u043b\u0435\u0435 125 \u0442\u043e\u043d\u043d \u043c\u0430\u043a\u0443\u043b\u0430\u0442\u0443\u0440\u044b. \u042d\u0442\u043e \u043e\u043a\u043e\u043b\u043e 2080 \u0441\u043f\u0430\u0441\u0435\u043d\u043d\u044b\u0445 \u0434\u0435\u0440\u0435\u0432\u044c\u0435\u0432. \n\n\u0421 2009 \u0433\u043e\u0434\u0430 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0443 CO2-\u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0430 \u0441\u043e\u0432\u043c\u0435\u0441\u0442\u043d\u043e \u0441 \u043d\u0435\u043c\u0435\u0446\u043a\u043e\u0439 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0435\u0439 Prima Klima \u0438 \u0432\u044b\u0434\u0435\u043b\u044f\u0435\u0442 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043d\u0430 \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435 \u043b\u0435\u0441\u043e\u0432. \u0414\u043b\u044f \u043a\u043e\u043c\u043f\u0435\u043d\u0441\u0430\u0446\u0438\u0438 \u0443\u0433\u043b\u0435\u043a\u0438\u0441\u043b\u043e\u0433\u043e \u0433\u0430\u0437\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442 \u0444\u0430\u0431\u0440\u0438\u043a\u0430, \u0442\u043e\u043b\u044c\u043a\u043e \u0432 2014 \u0433\u043e\u0434\u0443 \u0434\u0435\u0440\u0435\u0432\u044c\u044f\u043c\u0438 \u0437\u0430\u0441\u0430\u0436\u0435\u043d\u043e \u0431\u043e\u043b\u0435\u0435 8,5 \u0433\u0435\u043a\u0442\u0430\u0440\u043e\u0432 \u0437\u0435\u043c\u043b\u0438. \u0410 \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044b\u0435 \u0437\u0430 \u0432\u0441\u0435 \u0432\u0440\u0435\u043c\u044f \u0434\u0435\u0440\u0435\u0432\u044c\u044f \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u043e \u043f\u043e\u0433\u043b\u043e\u0449\u0430\u044e\u0442 \u0434\u043e 248 \u0442\u043e\u043d\u043d \u0443\u0433\u043b\u0435\u043a\u0438\u0441\u043b\u043e\u0433\u043e \u0433\u0430\u0437\u0430.\n\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://recyclemag.ru/article/6-ekologicheskih-initsiativ-kompanii-splat"},C.aj,t.c)
C.zn=new H.aA(3,{id:13,title:"\u0417\u0430\u043d\u0438\u043c\u0430\u0439\u0442\u0435\u0441\u044c \u043f\u043b\u043e\u0433\u0433\u0438\u043d\u0433\u043e\u043c!",text:"\u041f\u043b\u043e\u0433\u0433\u0438\u043d\u0433 \u2013 \u044d\u0442\u043e \u043f\u0440\u043e\u0431\u0435\u0436\u043a\u0438 \u0441 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u043c \u0441\u0431\u043e\u0440\u043e\u043c \u043c\u0443\u0441\u043e\u0440\u0430. \u041e\u043d \u0437\u0430\u0440\u043e\u0434\u0438\u043b\u0441\u044f \u0432 \u0428\u0432\u0435\u0446\u0438\u0438 \u0432\u0441\u0435\u0433\u043e \u0434\u0432\u0430 \u0433\u043e\u0434\u0430 \u043d\u0430\u0437\u0430\u0434, \u043d\u043e \u0443\u0436\u0435 \u0441\u0442\u0430\u043b \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u044b\u043c \u0432\u043e \u043c\u043d\u043e\u0433\u0438\u0445 \u0441\u0442\u0440\u0430\u043d\u0430\u0445. \u0427\u0442\u043e\u0431\u044b \u0437\u0430\u043d\u044f\u0442\u044c\u0441\u044f \u043f\u043b\u043e\u0433\u0433\u0438\u043d\u0433\u043e\u043c \u043d\u0443\u0436\u043d\u043e \u0441\u043e\u0432\u0441\u0435\u043c \u043d\u0435\u043c\u043d\u043e\u0433\u043e: \u0437\u0430\u0445\u0432\u0430\u0442\u0438\u0442\u044c \u043d\u0430 \u043f\u0440\u043e\u0431\u0435\u0436\u043a\u0443 \u043f\u0430\u043a\u0435\u0442 \u0438 \u0441\u043e\u0431\u0438\u0440\u0430\u0442\u044c \u0432 \u043d\u0435\u0433\u043e \u043c\u0443\u0441\u043e\u0440, \u043f\u043e\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u0439\u0441\u044f \u043f\u043e \u043f\u0443\u0442\u0438. \u0410 \u0437\u0430\u0442\u0435\u043c \u0441\u0434\u0430\u0442\u044c \u0435\u0433\u043e \u043d\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0443.\n\u2800\n\u041f\u043b\u043e\u0433\u0433\u0438\u043d\u0433 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u0443\u0431\u0438\u0442\u044c \u0441\u0440\u0430\u0437\u0443 \u0434\u0432\u0443\u0445 \u0437\u0430\u0439\u0446\u0435\u0432. \u041e\u0431\u044b\u0447\u043d\u044b\u0439 \u0431\u0435\u0433 \u0442\u0440\u0443\u0441\u0446\u043e\u0439 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0438\u0432\u043e\u0434\u0438\u0442 \u0432\u0430\u0441 \u0432 \u0444\u043e\u0440\u043c\u0443, \u043d\u043e \u0438 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u0441\u0434\u0435\u043b\u0430\u0442\u044c \u043c\u0438\u0440 \u0447\u0438\u0449\u0435. \u041f\u043b\u044e\u0441 \u043a \u044d\u0442\u043e\u043c\u0443 \u0443 \u0431\u0435\u0433\u0443\u043d\u0430 \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0440\u0430\u0441\u0445\u043e\u0434 \u043a\u0430\u043b\u043e\u0440\u0438\u0439: \u0434\u043b\u044f \u0442\u043e\u0433\u043e \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0434\u043e\u0431\u0440\u0430\u0442\u044c \u043c\u0443\u0441\u043e\u0440, \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u043a\u043b\u043e\u043d\u0438\u0442\u044c\u0441\u044f \u0438\u043b\u0438 \u043f\u0440\u0438\u0441\u0435\u0441\u0442\u044c.\n\u2800\n\u261d\u0410 \u0435\u0449\u0451 \u043c\u043e\u0436\u043d\u043e \u0432\u044b\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0442\u044c \u0441\u0435\u043b\u0444\u0438 \u0441 \u0442\u0430\u043a\u0438\u0445 \u043f\u0440\u043e\u0431\u0435\u0436\u0435\u043a \u0441 \u0445\u0435\u0448\u0442\u0435\u0433\u043e\u043c #plogging, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u0438\u0432\u043b\u0435\u0447\u044c \u043a \u044d\u0442\u043e\u0439 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u0438 \u043d\u043e\u0432\u044b\u0445 \u0443\u0447\u0430\u0441\u0442\u043d\u0438\u043a\u043e\u0432.\n\n\u0418\u0441\u0442\u043e\u0447\u043d\u0438\u043a: https://www.instagram.com/p/BxMckkCnX6D/\n"},C.aj,t.c)
